# ==================== THREAD-SAFE QUEST LOCKING ====================
# Prevent multiple asyncio.to_thread() calls from locking the database
# when updating the same user's quests
import threading
import asyncio
dragonpass_locks = {}  # {(guild_id, user_id): threading.Lock()}
spawn_locks = {}  # {guild_id: asyncio.Lock()} - prevents concurrent dragon catches (MUST BE ASYNC!)

def get_quest_lock(guild_id: int, user_id: int):
    """Get or create a lock for this user's quest tracking"""
    key = (guild_id, user_id)
    if key not in dragonpass_locks:
        dragonpass_locks[key] = threading.Lock()
    return dragonpass_locks[key]

def get_spawn_lock(guild_id: int):
    """Get or create an ASYNC lock for this guild's dragon spawns to prevent race conditions"""
    if guild_id not in spawn_locks:
        spawn_locks[guild_id] = asyncio.Lock()
    return spawn_locks[guild_id]

