# ==================== INVENTORY ITEMS VIEW (Dragonscale & Lucky Charm Buttons) ====================
class InventoryItemsView(discord.ui.View):
    def __init__(self, guild_id: int, user_id: int, dragonscale_minutes: int, luckycharm_count: int, usable_items: dict):
        super().__init__(timeout=180)
        self.guild_id = guild_id
        self.user_id = user_id
        self.dragonscale_minutes = dragonscale_minutes
        self.luckycharm_count = luckycharm_count
        self.usable_items = usable_items  # {'dragon_eye': 2, 'dragon_magnet': 1, etc}
        
        # Add buttons for existing items
        if dragonscale_minutes > 0:
            self.add_item(self.create_dragonscale_button())
        if luckycharm_count > 0:
            self.add_item(self.create_luckycharm_button())
        
        # Add buttons for new usable items
        for item_key, count in usable_items.items():
            if count > 0:
                if item_key == 'night_vision':
                    self.add_item(self.create_night_vision_button(count))
                elif item_key == 'lucky_dice':
                    self.add_item(self.create_lucky_dice_button(count))
    
    def create_dragonscale_button(self):
        button = discord.ui.Button(
            label=f"Activate Dragonscale ({self.dragonscale_minutes}m)",
            style=discord.ButtonStyle.primary,
            emoji="⚡",
            custom_id=f"dragonscale_{self.guild_id}_{self.user_id}"
        )
        button.callback = self.activate_dragonscale
        return button
    
    def create_luckycharm_button(self):
        button = discord.ui.Button(
            label=f"Activate Lucky Charm ({self.luckycharm_count}x)",
            style=discord.ButtonStyle.success,
            emoji="🍀",
            custom_id=f"luckycharm_{self.guild_id}_{self.user_id}"
        )
        button.callback = self.activate_luckycharm
        return button
    
    async def activate_dragonscale(self, interaction: discord.Interaction):
        # Check if user is the owner
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ This is not your inventory!", ephemeral=False)
            return
        
        # Check if raid boss is active
        if is_raid_boss_active(self.guild_id):
            await interaction.response.send_message("❌ Cannot activate dragonscale during an active raid boss! ⚔️", ephemeral=False)
            return
        
        # Show modal to ask how many minutes
        modal = DragonscaleMinutesModal(self.guild_id, self.user_id, self.dragonscale_minutes, self, interaction.message)
        await interaction.response.send_modal(modal)
    
    async def activate_luckycharm(self, interaction: discord.Interaction):
        # Check if user is the owner
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ This is not your inventory!", ephemeral=False)
            return
        
        conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
        c = conn.cursor()
        
        # Check if user still has Lucky Charms
        c.execute('SELECT count FROM user_luckycharms WHERE guild_id = ? AND user_id = ?',
                  (self.guild_id, self.user_id))
        result = c.fetchone()
        
        if not result or result[0] <= 0:
            await interaction.response.send_message("❌ You don't have any Lucky Charms anymore!", ephemeral=False)
            conn.close()
            return
        
        available_charms = result[0]
        
        # Check if already active
        if self.guild_id in active_luckycharms and self.user_id in active_luckycharms[self.guild_id]:
            existing_end = active_luckycharms[self.guild_id][self.user_id]
            if existing_end > int(time.time()):
                # Add to existing boost
                new_end_time = existing_end + 1800  # Add 30 minutes
                active_luckycharms[self.guild_id][self.user_id] = new_end_time
                
                # Deduct Lucky Charm
                c.execute('UPDATE user_luckycharms SET count = count - 1 WHERE guild_id = ? AND user_id = ?',
                          (self.guild_id, self.user_id))
                conn.commit()
                conn.close()
                
                new_total = (new_end_time - int(time.time())) // 60
                
                embed = discord.Embed(
                    title="🍀 Lucky Charm Extended!",
                    description=f"Added **30 minutes** to your active Lucky Charm!\n\n"
                                f"**Total Duration:** {new_total} minutes\n"
                                f"**Effect:** 2x Catch Rate!\n"
                                f"**Remaining Lucky Charms:** {available_charms - 1}",
                    color=discord.Color.green()
                )
                await interaction.response.send_message(embed=embed, ephemeral=False)
                return
        
        # Activate new Lucky Charm
        end_time = int(time.time()) + 1800  # 30 minutes
        if self.guild_id not in active_luckycharms:
            active_luckycharms[self.guild_id] = {}
        active_luckycharms[self.guild_id][self.user_id] = end_time
        
        # Deduct Lucky Charm
        c.execute('UPDATE user_luckycharms SET count = count - 1 WHERE guild_id = ? AND user_id = ?',
                  (self.guild_id, self.user_id))
        conn.commit()
        conn.close()
        
        embed = discord.Embed(
            title="🍀 Lucky Charm Activated!",
            description=f"**Duration:** 30 minutes\n"
                        f"**Effect:** 2x Catch Rate! Catch twice as many dragons!\n"
                        f"**Remaining Lucky Charms:** {available_charms - 1}",
            color=discord.Color.green()
        )
        
        await interaction.response.send_message(embed=embed, ephemeral=False)
    
    def create_night_vision_button(self, count: int):
        button = discord.ui.Button(
            label=f"Night Vision ({count}x)",
            style=discord.ButtonStyle.primary,
            emoji="🌙",
            custom_id=f"nightvision_{self.guild_id}_{self.user_id}"
        )
        button.callback = self.activate_night_vision
        return button
    
    async def activate_night_vision(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ This is not your inventory!", ephemeral=False)
            return
        
        # Check if Dragonscale or Dragonfest is active
        if self.guild_id in active_dragonscales:
            existing_end = active_dragonscales[self.guild_id]
            if existing_end > int(time.time()):
                await interaction.response.send_message(
                    "❌ Cannot activate Night Vision while Dragonscale is active! ⚡",
                    ephemeral=False
                )
                return
        
        if self.guild_id in active_dragonfest:
            dragonfest_data = active_dragonfest[self.guild_id]
            if dragonfest_data['end'] > int(time.time()):
                await interaction.response.send_message(
                    "❌ Cannot activate Night Vision while Dragonfest is active! 🎉",
                    ephemeral=False
                )
                return
        
        # Check if current time is nighttime (20:00 - 08:00)
        current_hour = datetime.now().hour
        is_nighttime = current_hour >= 20 or current_hour < 8
        
        if not is_nighttime:
            await interaction.response.send_message(
                f"❌ Night Vision can only be activated between 20:00 (8pm) and 08:00 (8am)!\n"
                f"Current time: {datetime.now().strftime('%H:%M')}\n\n"
                f"Come back during nighttime to activate it!",
                ephemeral=False
            )
            return
        
        # Check if already active for THIS user
        if get_active_item(self.guild_id, self.user_id, 'night_vision'):
            await interaction.response.send_message("⏳ You already have Night Vision active! (60 min)", ephemeral=False)
            return
        
        # Check if user already activated Night Vision tonight
        today_key = (self.guild_id, self.user_id)
        tonight_date = datetime.now().strftime("%Y-%m-%d")
        
        if today_key in night_vision_activations:
            activation_date = night_vision_activations[today_key]
            if activation_date == tonight_date:
                await interaction.response.send_message(
                    f"❌ You already activated Night Vision tonight!\n\n"
                    f"You can activate it again tomorrow night after 20:00.",
                    ephemeral=False
                )
                return
        
        # Activate
        activate_item(self.guild_id, self.user_id, 'night_vision', 60 * 60)  # 60 minutes
        night_vision_activations[today_key] = tonight_date  # Track tonight's activation
        
        # Deduct item
        conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
        c = conn.cursor()
        c.execute('UPDATE user_items SET count = count - 1 WHERE guild_id = ? AND user_id = ? AND item_type = ?',
                  (self.guild_id, self.user_id, 'night_vision'))
        conn.commit()
        conn.close()
        
        # Update usable_items count locally
        self.usable_items['night_vision'] = self.usable_items.get('night_vision', 1) - 1
        
        embed = discord.Embed(
            title="🌙 Night Vision Activated!",
            description="**Duration:** 60 minutes\n"
                        "**Effect:** +50% higher rarity dragons!\n"
                        "Increased chance for rare dragons during nighttime!\n\n"
                        "⚠️ You can only activate once per night. Come back tomorrow after 20:00!",
            color=discord.Color.dark_blue()
        )
        
        # Update the original message to remove/hide the button
        await interaction.response.defer()
        if interaction.message:
            # Recreate the view with updated items
            new_view = InventoryItemsView(self.guild_id, self.user_id, self.dragonscale_minutes, self.luckycharm_count, self.usable_items)
            try:
                await interaction.message.edit(view=new_view)
            except:
                pass  # Message might be deleted
        
        # Send the success message separately
        await interaction.followup.send(embed=embed, ephemeral=False)
    
    def create_lucky_dice_button(self, count: int):
        button = discord.ui.Button(
            label=f"Lucky Dice ({count}x)",
            style=discord.ButtonStyle.primary,
            emoji="🎰",
            custom_id=f"luckydice_{self.guild_id}_{self.user_id}"
        )
        button.callback = self.activate_lucky_dice
        return button
    
    async def activate_lucky_dice(self, interaction: discord.Interaction):
        if interaction.user.id != self.user_id:
            await interaction.response.send_message("❌ This is not your inventory!", ephemeral=False)
            return
        
        # Check if already active
        if get_active_item(self.guild_id, self.user_id, 'lucky_dice'):
            await interaction.response.send_message("⏳ You already have Lucky Dice active! (30 min)", ephemeral=False)
            return
        
        # Activate
        activate_item(self.guild_id, self.user_id, 'lucky_dice', 30 * 60)  # 30 minutes
        
        # Deduct item
        conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
        c = conn.cursor()
        c.execute('UPDATE user_items SET count = count - 1 WHERE guild_id = ? AND user_id = ? AND item_type = ?',
                  (self.guild_id, self.user_id, 'lucky_dice'))
        conn.commit()
        conn.close()
        
        # Update usable_items count locally
        self.usable_items['lucky_dice'] = self.usable_items.get('lucky_dice', 1) - 1
        
        embed = discord.Embed(
            title="🎰 Lucky Dice Activated!",
            description="**Duration:** 30 minutes\n"
                        "**Effect:** +10% casino/gambling win chance!\n"
                        "Lady luck is on your side during this time!",
            color=discord.Color.red()
        )
        
        # Update the original message to remove/hide the button
        await interaction.response.defer()
        if interaction.message:
            # Recreate the view with updated items
            new_view = InventoryItemsView(self.guild_id, self.user_id, self.dragonscale_minutes, self.luckycharm_count, self.usable_items)
            try:
                await interaction.message.edit(view=new_view)
            except:
                pass  # Message might be deleted
        
        # Send the success message separately
        await interaction.followup.send(embed=embed, ephemeral=False)

class DragonscaleMinutesModal(discord.ui.Modal, title="Activate Dragonscale"):
    def __init__(self, guild_id: int, user_id: int, available_minutes: int, inventory_view=None, inventory_message=None):
        super().__init__()
        self.guild_id = guild_id
        self.user_id = user_id
        self.available_minutes = available_minutes
        self.inventory_view = inventory_view
        self.inventory_message = inventory_message
        
        self.minutes_input = discord.ui.TextInput(
            label=f"Wieviele Minuten aktivieren? (max {available_minutes})",
            placeholder=f"z.B. 5 oder 10",
            required=True,
            max_length=5
        )
        self.add_item(self.minutes_input)
    
    async def on_submit(self, interaction: discord.Interaction):
        try:
            minutes = int(self.minutes_input.value)
        except ValueError:
            await interaction.response.send_message("❌ Bitte gib eine Zahl ein!", ephemeral=False)
            return
        
        if minutes <= 0:
            await interaction.response.send_message("❌ Du musst mindestens 1 Minute aktivieren!", ephemeral=False)
            return
        
        if minutes > self.available_minutes:
            await interaction.response.send_message(
                f"❌ Du hast nur **{self.available_minutes} Minuten** verfügbar!\n"
                f"Du versuchtest {minutes} Minuten zu aktivieren.",
                ephemeral=False
            )
            return
        
        # Check if Night Vision is active for ANY user in this guild
        if self.guild_id in active_usable_items:
            current_time = int(time.time())
            for uid, items_dict in active_usable_items[self.guild_id].items():
                if 'night_vision' in items_dict and items_dict['night_vision'] > current_time:
                    await interaction.response.send_message(
                        "❌ Cannot activate Dragonscale while Night Vision is active! 🌙",
                        ephemeral=False
                    )
                    return
        
        conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
        c = conn.cursor()
        
        # Check if already active in server
        if self.guild_id in active_dragonscales:
            existing_end = active_dragonscales[self.guild_id]
            if existing_end > int(time.time()):
                # Add to existing event
                new_end_time = existing_end + (minutes * 60)
                active_dragonscales[self.guild_id] = new_end_time
                
                # Deduct minutes
                c.execute('UPDATE dragonscales SET minutes = minutes - ? WHERE guild_id = ? AND user_id = ?',
                          (minutes, self.guild_id, self.user_id))
                conn.commit()
                conn.close()
                
                new_total = (new_end_time - int(time.time())) // 60
                
                embed = discord.Embed(
                    title="⚡ Dragonscale Extended!",
                    description=f"{interaction.user.mention} added **{minutes} minutes** to the server-wide event!\n\n"
                                f"**New Total Duration:** {new_total} minutes\n"
                                f"**Your Remaining Dragonscales:** {self.available_minutes - minutes} minutes",
                    color=discord.Color.gold()
                )
                await interaction.response.send_message(embed=embed, ephemeral=False)
                
                # Update inventory if available
                if self.inventory_message:
                    new_minutes = self.available_minutes - minutes
                    new_view = InventoryItemsView(self.guild_id, self.user_id, new_minutes, 0, {})
                    try:
                        await self.inventory_message.edit(view=new_view)
                    except:
                        pass
                return
        
        # Activate new server-wide event
        current_time = int(time.time())
        end_time = current_time + (minutes * 60)
        active_dragonscales[self.guild_id] = end_time
        dragonscale_event_starts[self.guild_id] = current_time  # Store event start time
        
        # Initialize stats table if needed
        c.execute('''CREATE TABLE IF NOT EXISTS dragonscale_stats
                     (guild_id INTEGER, user_id INTEGER, dragons_caught INTEGER DEFAULT 0,
                      PRIMARY KEY (guild_id, user_id))''')
        
        # Clear previous stats for new event
        c.execute('DELETE FROM dragonscale_stats WHERE guild_id = ?', (self.guild_id,))
        
        # Deduct minutes
        c.execute('UPDATE dragonscales SET minutes = minutes - ? WHERE guild_id = ? AND user_id = ?',
                  (minutes, self.guild_id, self.user_id))
        conn.commit()
        conn.close()
        
        embed = discord.Embed(
            title="⚡ Dragonscale Event Started!",
            description=f"{interaction.user.mention} activated a **SERVER-WIDE** Dragonscale event!\n\n"
                        f"**Duration:** {minutes} minutes\n"
                        f"**Effect:** All players get spawn boosts!\n"
                        f"**Your Remaining Dragonscales:** {self.available_minutes - minutes} minutes\n\n"
                        f"🐉 Everyone can now catch dragons with enhanced spawn rates!",
            color=discord.Color.gold()
        )
        
        await interaction.response.send_message(embed=embed, ephemeral=False)
        
        # Update inventory if available
        if self.inventory_message:
            new_minutes = self.available_minutes - minutes
            new_view = InventoryItemsView(self.guild_id, self.user_id, new_minutes, 0, {})
            try:
                await self.inventory_message.edit(view=new_view)
            except:
                pass
        
        # Instant spawn first dragon
        channel = interaction.guild.get_channel(spawn_channels.get(self.guild_id)) if self.guild_id in spawn_channels else interaction.channel
        await asyncio.sleep(1)
        await spawn_dragon(self.guild_id, channel)

@bot.tree.command(name="skill", description="View your active passive item skills")
async def skill(interaction: discord.Interaction):
    """Show passive items and their effects"""
    await interaction.response.defer(ephemeral=False)
    
    # Check if player is softlocked
    is_softlocked, upgrade_level = is_player_softlocked(interaction.guild_id, interaction.user.id)
    if is_softlocked:
        next_upgrade_level = upgrade_level + 1
        upgrade_cost = DRAGONNEST_UPGRADES.get(next_upgrade_level, {}).get('cost', 0)
        softlock_embed = discord.Embed(
            title="🔒 Dragon Nest Upgrade Required!",
            description=f"You have enough coins to upgrade your Dragon Nest!\n\n"
                        f"**Current Level:** {upgrade_level}\n"
                        f"**Upgrade Cost:** {upgrade_cost:,} 🪙\n\n"
                        f"You're **softlocked** from using skills until you upgrade.\n"
                        f"Use `/dragonnest` to upgrade!",
            color=discord.Color.red()
        )
        await interaction.followup.send(embed=softlock_embed, delete_after=5)
        return
    
    guild_id = interaction.guild_id
    user_id = interaction.user.id
    
    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
    c = conn.cursor()
    
    # Get user balance for purchase checks
    c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?', (guild_id, user_id))
    user_result = c.fetchone()
    user_balance = user_result[0] if user_result else 0
    
    # Get passive items (knowledge_book, precision_stone)
    c.execute('SELECT item_type, count FROM user_items WHERE guild_id = ? AND user_id = ? AND item_type IN (?, ?)',
              (guild_id, user_id, 'knowledge_book', 'precision_stone'))
    passive_items = c.fetchall()
    conn.close()
    
    if not passive_items:
        embed = discord.Embed(
            title="📚 Your Skills",
            description="You don't have any passive skill items yet!\n\n"
                        "Passive items are always active when you own them:\n"
                        "📚 Knowledge Book      -   5,000 🪙 base (+10% per owned)\n"
                "   └─ +2% Catch (stacking)\n"
                "🎯 Precision Stone     -   12,500 🪙 base (+10% per owned)\n"
                "   └─ +5% Raid Damage (max 30% = 6 stones)",
            color=discord.Color.blue()
        )


      
        
        # Create upgrade view with buttons
        class SkillUpgradeNoItems(discord.ui.View):
            def __init__(self, guild_id, user_id, balance):
                super().__init__(timeout=300)
                self.guild_id = guild_id
                self.user_id = user_id
                self.balance = balance
            
            @discord.ui.button(label="Buy Knowledge Book (5,000 🪙)", style=discord.ButtonStyle.primary, emoji="📚")
            async def buy_knowledge(self, interaction: discord.Interaction, button: discord.ui.Button):
                if interaction.user.id != self.user_id:
                    await interaction.response.send_message("❌ This is not your skill menu!", ephemeral=True)
                    return
                
                cost = 5000
                if self.balance < cost:
                    await interaction.response.send_message(f"❌ Need {cost:,} 🪙, you have {int(self.balance):,} 🪙", ephemeral=True)
                    return
                
                conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                c = conn.cursor()
                c.execute('''INSERT INTO user_items (guild_id, user_id, item_type, count)
                             VALUES (?, ?, 'knowledge_book', 1)
                             ON CONFLICT(guild_id, user_id, item_type)
                             DO UPDATE SET count = count + 1''',
                          (self.guild_id, self.user_id))
                conn.commit()
                conn.close()
                
                await asyncio.to_thread(update_balance, self.guild_id, self.user_id, -cost)
                
                await interaction.response.send_message(
                    f"✅ Purchased Knowledge Book!\n📚 +2% Catch Bonus\n💰 Cost: 5,000 🪙",
                    ephemeral=False
                )
            
            @discord.ui.button(label="Buy Precision Stone (12,500 🪙)", style=discord.ButtonStyle.primary, emoji="🎯")
            async def buy_precision(self, interaction: discord.Interaction, button: discord.ui.Button):
                if interaction.user.id != self.user_id:
                    await interaction.response.send_message("❌ This is not your skill menu!", ephemeral=True)
                    return
                
                cost = 12500
                if self.balance < cost:
                    await interaction.response.send_message(f"❌ Need {cost:,} 🪙, you have {int(self.balance):,} 🪙", ephemeral=True)
                    return
                
                conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                c = conn.cursor()
                c.execute('''INSERT INTO user_items (guild_id, user_id, item_type, count)
                             VALUES (?, ?, 'precision_stone', 1)
                             ON CONFLICT(guild_id, user_id, item_type)
                             DO UPDATE SET count = count + 1''',
                          (self.guild_id, self.user_id))
                conn.commit()
                conn.close()
                
                await asyncio.to_thread(update_balance, self.guild_id, self.user_id, -cost)
                
                await interaction.response.send_message(
                    f"✅ Purchased Precision Stone!\n🎯 +5% Raid Damage Bonus\n💰 Cost: 12,500 🪙",
                    ephemeral=False
                )
        
        view = SkillUpgradeNoItems(guild_id, user_id, user_balance)
        await interaction.followup.send(embed=embed, view=view, ephemeral=False)
        return
    
    embed = discord.Embed(
        title="📚 Your Passive Items",
        description="These items are always active and provide continuous bonuses:",
        color=discord.Color.blue()
    )
    
    total_catch_bonus = 0
    total_raid_bonus = 0
    items_dict = {}
    
    for item_type, count in passive_items:
        items_dict[item_type] = count
        if item_type == 'knowledge_book':
            bonus = count * 2  # 2% per book
            total_catch_bonus += bonus
            next_cost = calculate_item_cost(count, 5000)
            embed.add_field(
                name=f"📚 Knowledge Book x{count}",
                value=f"+{bonus}% Catch Success Rate\n(+2% per book, stacking)\n💰 Next: {next_cost:,} 🪙",
                inline=False
            )
        elif item_type == 'precision_stone':
            bonus = min(count * 5, 30)  # 5% per stone, max 30%
            total_raid_bonus += bonus
            next_cost = calculate_item_cost(count, 12500)
            cap_note = " (MAX)" if count * 5 >= 30 else ""
            embed.add_field(
                name=f"🎯 Precision Stone x{count}{cap_note}",
                value=f"+{bonus}% Raid Boss Damage\n(+5% per stone, max 30%)\n💰 Next: {next_cost:,} 🪙",
                inline=False
            )
    
    # Summary
    summary = ""
    if total_catch_bonus > 0:
        summary += f"✅ **Catch Bonus:** +{total_catch_bonus}%\n"
    if total_raid_bonus > 0:
        summary += f"✅ **Raid Damage Bonus:** +{total_raid_bonus}%\n"
    
    embed.add_field(
        name="📊 Current Bonuses",
        value=summary if summary else "No bonuses active",
        inline=False
    )
    
    embed.set_footer(text="Passive items are always active as long as you own them!")
    
    # Create upgrade buttons view
    class SkillUpgradeView(discord.ui.View):
        def __init__(self, guild_id, user_id, balance, items_dict):
            super().__init__(timeout=300)
            self.guild_id = guild_id
            self.user_id = user_id
            self.balance = balance
            self.items_dict = items_dict
        
        @discord.ui.button(label="Upgrade Knowledge Book", style=discord.ButtonStyle.success, emoji="📚")
        async def upgrade_knowledge(self, interaction: discord.Interaction, button: discord.ui.Button):
            if interaction.user.id != self.user_id:
                await interaction.response.send_message("❌ This is not your skill menu!", ephemeral=True)
                return
            
            current_count = self.items_dict.get('knowledge_book', 0)
            cost = calculate_item_cost(current_count, 5000)
            
            if self.balance < cost:
                await interaction.response.send_message(
                    f"❌ Need {cost:,} 🪙, you have {int(self.balance):,} 🪙",
                    ephemeral=True
                )
                return
            
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            c.execute('''INSERT INTO user_items (guild_id, user_id, item_type, count)
                         VALUES (?, ?, 'knowledge_book', 1)
                         ON CONFLICT(guild_id, user_id, item_type)
                         DO UPDATE SET count = count + 1''',
                      (self.guild_id, self.user_id))
            conn.commit()
            conn.close()
            
            await asyncio.to_thread(update_balance, self.guild_id, self.user_id, -cost)
            
            new_count = current_count + 1
            new_bonus = new_count * 2
            
            await interaction.response.send_message(
                f"✅ Upgraded Knowledge Book!\n📚 Now: +{new_bonus}% Catch\n💰 Cost: {cost:,} 🪙",
                ephemeral=False
            )
        
        @discord.ui.button(label="Upgrade Precision Stone", style=discord.ButtonStyle.success, emoji="🎯")
        async def upgrade_precision(self, interaction: discord.Interaction, button: discord.ui.Button):
            if interaction.user.id != self.user_id:
                await interaction.response.send_message("❌ This is not your skill menu!", ephemeral=True)
                return
            
            current_count = self.items_dict.get('precision_stone', 0)
            cost = calculate_item_cost(current_count, 12500)
            
            if self.balance < cost:
                await interaction.response.send_message(
                    f"❌ Need {cost:,} 🪙, you have {int(self.balance):,} 🪙",
                    ephemeral=True
                )
                return
            
            if current_count >= 6:  # Already at max 30%
                await interaction.response.send_message(
                    f"⚠️ Already at maximum (30% bonus)!",
                    ephemeral=True
                )
                return
            
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            c.execute('''INSERT INTO user_items (guild_id, user_id, item_type, count)
                         VALUES (?, ?, 'precision_stone', 1)
                         ON CONFLICT(guild_id, user_id, item_type)
                         DO UPDATE SET count = count + 1''',
                      (self.guild_id, self.user_id))
            conn.commit()
            conn.close()
            
            await asyncio.to_thread(update_balance, self.guild_id, self.user_id, -cost)
            
            new_count = current_count + 1
            new_bonus = min(new_count * 5, 30)
            
            await interaction.response.send_message(
                f"✅ Upgraded Precision Stone!\n🎯 Now: +{new_bonus}% Raid Damage\n💰 Cost: {cost:,} 🪙",
                ephemeral=False
            )
    
    view = SkillUpgradeView(guild_id, user_id, user_balance, items_dict)
    await interaction.followup.send(embed=embed, view=view, ephemeral=False)

@bot.tree.command(name="inventory", description="View your dragon inventory")
async def inventory(interaction: discord.Interaction, user: discord.User = None):
    target_user = user or interaction.user
    
    # Check if player is softlocked (only check own inventory, not others)
    if target_user.id == interaction.user.id:
        is_softlocked, upgrade_level = is_player_softlocked(interaction.guild_id, interaction.user.id)
        if is_softlocked:
            next_upgrade_level = upgrade_level + 1
            upgrade_cost = DRAGONNEST_UPGRADES.get(next_upgrade_level, {}).get('cost', 0)
            softlock_embed = discord.Embed(
                title="🔒 Dragon Nest Upgrade Required!",
                description=f"You have enough coins to upgrade your Dragon Nest!\n\n"
                            f"**Current Level:** {upgrade_level}\n"
                            f"**Upgrade Cost:** {upgrade_cost:,} 🪙\n\n"
                            f"You're **softlocked** from using items until you upgrade.\n"
                            f"Use `/dragonnest` to upgrade!",
                color=discord.Color.red()
            )
            await interaction.response.send_message(embed=softlock_embed, delete_after=5)
            return
    
    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
    c = conn.cursor()
    c.execute('SELECT dragon_type, count FROM user_dragons WHERE guild_id = ? AND user_id = ? AND count > 0 ORDER BY count DESC',
              (interaction.guild_id, target_user.id))
    dragons = c.fetchall()
    
    # Get dragonscales
    c.execute('SELECT minutes FROM dragonscales WHERE guild_id = ? AND user_id = ?',
              (interaction.guild_id, target_user.id))
    dragonscale_result = c.fetchone()
    dragonscale_minutes = dragonscale_result[0] if dragonscale_result else 0
    
    # Get Lucky Charms
    c.execute('SELECT count FROM user_luckycharms WHERE guild_id = ? AND user_id = ?',
              (interaction.guild_id, target_user.id))
    luckycharm_result = c.fetchone()
    luckycharm_count = luckycharm_result[0] if luckycharm_result else 0
    
    # Get new usable items counts
    c.execute('SELECT item_type, count FROM user_items WHERE guild_id = ? AND user_id = ? AND item_type IN (?, ?, ?, ?)',
              (interaction.guild_id, target_user.id, 'dragon_magnet', 'night_vision', 'lucky_dice', 'dna'))
    usable_items_db = {item_type: count for item_type, count in c.fetchall()}
    
    # Get Packs
    c.execute('SELECT pack_type, count FROM user_packs WHERE guild_id = ? AND user_id = ? AND count > 0',
              (interaction.guild_id, target_user.id))
    packs = c.fetchall()
    
    # Get Raid Boss Damage (keep connection open for this)
    c.execute('SELECT damage_dealt FROM raid_damage WHERE guild_id = ? AND user_id = ?',
              (interaction.guild_id, target_user.id))
    raid_damage_result = c.fetchone()
    raid_damage = raid_damage_result[0] if raid_damage_result else 0
    
    # Get precision stones for raid damage buff
    c.execute('SELECT count FROM user_items WHERE guild_id = ? AND user_id = ? AND item_type = ?',
              (interaction.guild_id, target_user.id, 'precision_stone'))
    precision_stone_result = c.fetchone()
    precision_stone_count = precision_stone_result[0] if precision_stone_result else 0
    
    conn.close()
    
    if not dragons:
        # Check if user has items or packs before saying "no dragons"
        has_items = dragonscale_minutes > 0 or luckycharm_count > 0 or any(usable_items_db.values()) or packs
        if not has_items:
            await interaction.response.send_message(f"📦 {target_user.display_name} has no dragons yet!", ephemeral=False)
            return
        # If they have items, continue to show them
    
    # Calculate stats with market values
    total_dragons = 0
    total_value = 0
    unique_types = 0
    
    if dragons:
        # Filter out invalid dragon types
        valid_dragons = [(dtype, count) for dtype, count in dragons if dtype in DRAGON_TYPES]
        total_dragons = sum(count for _, count in valid_dragons)
        unique_types = len(valid_dragons)
        
        # Calculate total market value (using marketplace prices if available, else base value)
        conn_market = get_db_connection(timeout=60.0)
        c_market = conn_market.cursor()
        
        for dragon_type, count in valid_dragons:
            if dragon_type not in DRAGON_TYPES:
                continue
            
            # Get average market listing price for this dragon type in this server (active listings only)
            c_market.execute('''SELECT AVG(price) FROM market_listings 
                               WHERE guild_id = ? AND dragon_type = ?''',
                            (interaction.guild_id, dragon_type))
            market_result = c_market.fetchone()
            
            # Use market price if available, else base value
            if market_result and market_result[0]:
                dragon_price = market_result[0]
            else:
                dragon_price = DRAGON_TYPES[dragon_type]['value']
            
            total_value += dragon_price * count
        
        conn_market.close()
    
    embed = discord.Embed(
        title=f"🐉 {target_user.display_name}'s Dragon Collection",
        color=0x5865F2
    )
    
    # Stats section
    stats_text = f"🐉 **Total Dragons:** `{total_dragons:,}`\n"
    stats_text += f"🎯 **Unique Types:** `{unique_types}/22`\n"
    stats_text += f"💰 **Market Value:** `{int(total_value):,}` 🪙"
    embed.add_field(name="📊 Collection Stats", value=stats_text, inline=False)
    
    # Items section
    dragonscale_time_str = format_time_remaining(dragonscale_minutes * 60) if dragonscale_minutes > 0 else "0m"
    items_text = f"⚡ Dragonscale: {dragonscale_time_str}\n"
    items_text += f"🍀 Lucky Charms: {luckycharm_count}\n"
    items_text += f"🧬 DNA Samples: {usable_items_db.get('dna', 0)}\n"
    
    # Add new usable items
    for item_key, data in USABLE_ITEMS.items():
        count = usable_items_db.get(item_key, 0)
        if count > 0:
            items_text += f"{data['emoji']} {data['name']}: {count}\n"
    
    if packs:
        pack_text = "\n".join([f"{PACK_TYPES.get(pt, {'emoji': '📦'})['emoji']} `x{c:2}`" for pt, c in packs[:5]])
        items_text += f"\n**Packs:**\n{pack_text}"
    embed.add_field(name="🎁 Items", value=items_text, inline=True)
    
    # Raid Boss Max Damage section (only if user has dragons)
    valid_dragons_list = []
    if dragons:
        # Filter out invalid dragon types
        valid_dragons_list = [(dtype, count) for dtype, count in dragons if dtype in DRAGON_TYPES]
    
    if valid_dragons_list:
        # Calculate max damage potential
        max_damage = 0
        for dragon_type, count in valid_dragons_list:
            # Find rarity of this dragon
            dragon_rarity = 'common'
            for rarity, dragon_list in DRAGON_RARITY_TIERS.items():
                if dragon_type in dragon_list:
                    dragon_rarity = rarity
                    break
            
            damage_per_dragon = RARITY_DAMAGE[dragon_rarity]
            max_damage += count * damage_per_dragon
        
        # Apply precision stone buff (+5% per stone, max 30%)
        precision_bonus = min(precision_stone_count * 0.05, 0.30)
        max_damage_with_buff = int(max_damage * (1 + precision_bonus))
        
        if precision_stone_count > 0:
            raid_text = f"💥 **Max Damage:** `{max_damage_with_buff:,}` 🎯\n"
            raid_text += f"(Base: `{max_damage:,}` + {int(precision_bonus*100)}% Buff)"
        else:
            raid_text = f"💥 **Max Damage:** `{max_damage:,}`"
        
        embed.add_field(name="🐲 Raid Potential", value=raid_text, inline=True)
    
    embed.add_field(name="​", value="​", inline=True)  # Spacer
    embed.add_field(name="​", value="​", inline=True)  # Spacer
    
    # Group by rarity using DRAGON_RARITY_TIERS (only if user has dragons)
    if valid_dragons_list:
        common_dragons = []
        uncommon_dragons = []
        rare_dragons = []
        epic_dragons = []
        legendary_dragons = []
        mythic_dragons = []
        ultra_dragons = []
        
        for dragon_type, count in valid_dragons_list:
            if dragon_type not in DRAGON_TYPES:
                continue
            
            dragon_data = DRAGON_TYPES[dragon_type]
            dragon_text = f"{dragon_data['emoji']} **{dragon_data['name']}** x{count}"
            
            # Determine rarity from DRAGON_RARITY_TIERS
            rarity = None
            for r, dragon_list in DRAGON_RARITY_TIERS.items():
                if dragon_type in dragon_list:
                    rarity = r
                    break
            
            if rarity == 'common':
                common_dragons.append(dragon_text)
            elif rarity == 'uncommon':
                uncommon_dragons.append(dragon_text)
            elif rarity == 'rare':
                rare_dragons.append(dragon_text)
            elif rarity == 'epic':
                epic_dragons.append(dragon_text)
            elif rarity == 'legendary':
                legendary_dragons.append(dragon_text)
            elif rarity == 'mythic':
                mythic_dragons.append(dragon_text)
            elif rarity == 'ultra':
                ultra_dragons.append(dragon_text)
        
        # Add fields by rarity
        if common_dragons:
            embed.add_field(name="⚪ Common", value="\n".join(common_dragons[:10]), inline=False)
        if uncommon_dragons:
            embed.add_field(name="🟢 Uncommon", value="\n".join(uncommon_dragons[:10]), inline=False)
        if rare_dragons:
            embed.add_field(name="🔵 Rare", value="\n".join(rare_dragons[:10]), inline=False)
        if epic_dragons:
            embed.add_field(name="🟣 Epic", value="\n".join(epic_dragons[:10]), inline=False)
        if legendary_dragons:
            embed.add_field(name="🟡 Legendary", value="\n".join(legendary_dragons[:10]), inline=False)
        if mythic_dragons:
            embed.add_field(name="🌟 Mythic", value="\n".join(mythic_dragons[:10]), inline=False)
        if ultra_dragons:
            embed.add_field(name="💎 Ultra", value="\n".join(ultra_dragons[:10]), inline=False)
    
    embed.set_footer(text=f"Use /bal to see your coins")
    
    # Create buttons view if user has items to activate
    if target_user.id == interaction.user.id and (dragonscale_minutes > 0 or luckycharm_count > 0 or any(usable_items_db.values()) or packs):
        view = InventoryItemsView(interaction.guild_id, interaction.user.id, dragonscale_minutes, luckycharm_count, usable_items_db)
        await interaction.response.send_message(embed=embed, view=view, ephemeral=False)
    else:
        await interaction.response.send_message(embed=embed, ephemeral=False)

@bot.tree.command(name="openpacks", description="Open your packs to get dragons")
async def openpacks(interaction: discord.Interaction):
    """Open packs with 30% chance to upgrade to next tier"""
    
    # Check if player is softlocked
    is_softlocked, upgrade_level = is_player_softlocked(interaction.guild_id, interaction.user.id)
    if is_softlocked:
        next_upgrade_level = upgrade_level + 1
        upgrade_cost = DRAGONNEST_UPGRADES.get(next_upgrade_level, {}).get('cost', 0)
        softlock_embed = discord.Embed(
            title="🔒 Dragon Nest Upgrade Required!",
            description=f"You have enough coins to upgrade your Dragon Nest!\n\n"
                        f"**Current Level:** {upgrade_level}\n"
                        f"**Upgrade Cost:** {upgrade_cost:,} 🪙\n\n"
                        f"You're **softlocked** from opening packs until you upgrade.\n"
                        f"Use `/dragonnest` to upgrade!",
            color=discord.Color.red()
        )
        await interaction.response.send_message(embed=softlock_embed, delete_after=5)
        return
    
    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
    c = conn.cursor()
    c.execute('SELECT pack_type, count FROM user_packs WHERE guild_id = ? AND user_id = ? AND count > 0',
              (interaction.guild_id, interaction.user.id))
    packs = c.fetchall()
    conn.close()
    
    if not packs:
        await interaction.response.send_message("📦 You don't have any packs to open!", ephemeral=False)
        return
    
    # Filter to only include packs with count > 0
    packs = [(pack_type, count) for pack_type, count in packs if count > 0]
    
    # Create pack opening buttons
    class OpenPackView(discord.ui.View):
        def __init__(self, guild_id, user_id, available_packs=None):
            super().__init__(timeout=180)
            self.guild_id = guild_id
            self.user_id = user_id
            
            # Use provided packs list or fetch from database
            if available_packs is None:
                conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                c = conn.cursor()
                c.execute('SELECT pack_type, count FROM user_packs WHERE guild_id = ? AND user_id = ? AND count > 0',
                          (guild_id, user_id))
                available_packs = c.fetchall()
                conn.close()
            
            # Add button for each pack type user has
            for pack_type, count in available_packs:
                pack_data = PACK_TYPES.get(pack_type)
                if pack_data and count > 0:
                    button = discord.ui.Button(
                        label=f"{pack_data['name']} (x{count})",
                        emoji=pack_data['emoji'],
                        style=discord.ButtonStyle.primary,
                        custom_id=f"open_{pack_type}"
                    )
                    button.callback = self.create_callback(pack_type)
                    self.add_item(button)
            
            # Add bulk open button if user has multiple packs
            total_packs = sum(count for _, count in available_packs)
            if total_packs >= 5:
                bulk_button = discord.ui.Button(
                    label="Bulk Open",
                    emoji="📦",
                    style=discord.ButtonStyle.green,
                    custom_id="bulk_open"
                )
                bulk_button.callback = self.bulk_open_callback
                self.add_item(bulk_button)
        
        async def bulk_open_callback(self, interaction: discord.Interaction):
            """Handle bulk opening packs"""
            if interaction.user.id != self.user_id:
                await interaction.response.send_message("❌ This is not your pack menu!", ephemeral=False)
                return
            
            # Get available packs
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            c.execute('SELECT pack_type, count FROM user_packs WHERE guild_id = ? AND user_id = ? AND count > 0',
                      (self.guild_id, self.user_id))
            available_packs = c.fetchall()
            conn.close()
            
            if not available_packs:
                await interaction.response.send_message("❌ You don't have any packs!", ephemeral=False)
                return
            
            # Create select menu for pack type and amount
            class BulkOpenView(discord.ui.View):
                def __init__(self, guild_id, user_id, packs):
                    super().__init__(timeout=60)
                    self.guild_id = guild_id
                    self.user_id = user_id
                    self.packs = packs
                    
                    # Pack type select
                    options = []
                    for pack_type, count in packs:
                        pack_data = PACK_TYPES.get(pack_type)
                        if pack_data:
                            options.append(
                                discord.SelectOption(
                                    label=f"{pack_data['name']} (x{count})",
                                    emoji=pack_data['emoji'],
                                    value=pack_type,
                                    description=f"Open multiple {pack_data['name']}s"
                                )
                            )
                    
                    class PackSelect(discord.ui.Select):
                        def __init__(inner_self):
                            super().__init__(
                                placeholder="Select pack type to bulk open...",
                                options=options
                            )
                        
                        async def callback(inner_self, interaction: discord.Interaction):
                            await interaction.response.defer()
                            pack_type = inner_self.values[0] if inner_self.values else None
                            if not pack_type:
                                await interaction.followup.send("❌ Please select a pack!", ephemeral=True)
                                return
                            
                            # Get count for this pack
                            pack_count = next((count for pt, count in self.packs if pt == pack_type), 0)
                            pack_data = PACK_TYPES[pack_type]
                            
                            # Create amount select (5, 10, 25, 50, or max)
                            amount_options = []
                            for amount in [5, 10, 25, 50]:
                                if amount <= pack_count:
                                    amount_options.append(
                                        discord.SelectOption(
                                            label=f"Open {amount}x",
                                            value=str(amount)
                                        )
                                    )
                            if pack_count not in [5, 10, 25, 50]:
                                amount_options.append(
                                    discord.SelectOption(
                                        label=f"Open All ({pack_count}x)",
                                        value=str(pack_count)
                                    )
                                )
                            
                            class AmountSelect(discord.ui.Select):
                                def __init__(inner_self2):
                                    super().__init__(
                                        placeholder=f"How many {pack_data['name']}s?",
                                        options=amount_options
                                    )
                                
                                async def callback(inner_self2, interaction2: discord.Interaction):
                                    await interaction2.response.defer()
                                    try:
                                        amount = int(inner_self2.values[0] if inner_self2.values else 0)
                                    except (ValueError, IndexError):
                                        await interaction2.followup.send("❌ Please select a valid amount!", ephemeral=True)
                                        return
                                    
                                    # Process bulk opening
                                    await interaction2.followup.send(
                                        f"📦 Opening {amount}x {pack_data['emoji']} {pack_data['name']}...",
                                        ephemeral=False
                                    )
                                    
                                    # Open all packs at once (no animation)
                                    total_dragons = {}
                                    total_coins = 0
                                    total_luckycharms = 0
                                    total_dragonscales = 0
                                    total_upgrades = 0
                                    
                                    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                                    c = conn.cursor()
                                    
                                    # Get pack tier for rarity-based drop chances
                                    pack_tier_idx = PACK_UPGRADE_ORDER.index(pack_type)
                                    # Determine drop chances based on pack rarity
                                    if pack_tier_idx <= 1:  # Wooden, Stone
                                        lucky_charm_chance = 0.01  # 1%
                                        dragonscale_chance = 0.0001  # 0.01%
                                    elif pack_tier_idx <= 3:  # Bronze, Silver
                                        lucky_charm_chance = 0.02  # 2%
                                        dragonscale_chance = 0.0002  # 0.02%
                                    elif pack_tier_idx <= 5:  # Gold, Platinum
                                        lucky_charm_chance = 0.03  # 3%
                                        dragonscale_chance = 0.0005  # 0.05%
                                    else:  # Diamond, Celestial
                                        lucky_charm_chance = 0.05  # 5%
                                        dragonscale_chance = 0.001  # 0.1%
                                    
                                    for i in range(amount):
                                        # Deduct pack
                                        c.execute('UPDATE user_packs SET count = count - 1 WHERE guild_id = ? AND user_id = ? AND pack_type = ?',
                                                  (self.guild_id, self.user_id, pack_type))
                                        
                                        # Check for upgrade
                                        current_pack = pack_type
                                        while current_pack != 'celestial':
                                            if random.random() < 0.30:
                                                current_index = PACK_UPGRADE_ORDER.index(current_pack)
                                                current_pack = PACK_UPGRADE_ORDER[current_index + 1]
                                                total_upgrades += 1
                                            else:
                                                break
                                        
                                        # Get dragons from pack
                                        # Use weighted selection based on pack tier
                                        pack_tier_index = PACK_UPGRADE_ORDER.index(current_pack)
                                        
                                        # Build weights for dragons
                                        dragon_weights = []
                                        for dragon_key_option in DRAGON_TYPES.keys():
                                            dragon_spawn_chance = DRAGON_TYPES[dragon_key_option]['spawn_chance']
                                            inverse_chance = 1.0 / (dragon_spawn_chance + 0.001)
                                            
                                            # Get dragon rarity
                                            dragon_rarity = None
                                            for rarity, dragons in DRAGON_RARITY_TIERS.items():
                                                if dragon_key_option in dragons:
                                                    dragon_rarity = rarity
                                                    break
                                            
                                            # Weight based on pack tier
                                            if pack_tier_index <= 1:
                                                weight = dragon_spawn_chance ** 0.3 if dragon_rarity == 'common' else 0.0
                                            elif pack_tier_index == 2:
                                                weight = dragon_spawn_chance ** 0.4 if dragon_rarity in ['common', 'uncommon'] else 0.0
                                            elif pack_tier_index <= 4:
                                                if dragon_rarity == 'common':
                                                    weight = 0.0
                                                elif dragon_rarity in ['uncommon', 'rare']:
                                                    weight = inverse_chance ** 0.2
                                                elif dragon_rarity == 'epic':
                                                    weight = inverse_chance ** 0.1
                                                else:
                                                    weight = 0.0
                                            elif pack_tier_index <= 6:
                                                if dragon_rarity in ['common', 'uncommon']:
                                                    weight = 0.0
                                                elif dragon_rarity == 'rare':
                                                    weight = inverse_chance ** 0.2
                                                elif dragon_rarity in ['epic', 'legendary']:
                                                    weight = inverse_chance ** 0.5
                                                else:
                                                    weight = inverse_chance ** 0.3
                                            else:
                                                weight = 0.0 if dragon_rarity in ['common', 'uncommon', 'rare', 'epic'] else inverse_chance ** 0.6
                                            dragon_weights.append(weight)
                                        
                                        dragon_key = random.choices(list(DRAGON_TYPES.keys()), weights=dragon_weights)[0]
                                        
                                        # Check for lucky charm/dragonscale bonus
                                        if random.random() < lucky_charm_chance:
                                            total_luckycharms += 1
                                        if random.random() < dragonscale_chance:
                                            total_dragonscales += 1
                                        
                                        # Check for coin bonus
                                        if random.random() < 0.02:  # 2% chance
                                            bonus_coins = random.randint(100, 1000)
                                            total_coins += bonus_coins
                                        
                                        # Add dragon directly to database
                                        c.execute('''INSERT INTO user_dragons (guild_id, user_id, dragon_type, count, last_caught_at)
                                                     VALUES (?, ?, ?, 1, ?)
                                                     ON CONFLICT(guild_id, user_id, dragon_type)
                                                     DO UPDATE SET count = count + 1, last_caught_at = ?''',
                                                  (self.guild_id, self.user_id, dragon_key, int(time.time()), int(time.time())))
                                        if dragon_key not in total_dragons:
                                            total_dragons[dragon_key] = 0
                                        total_dragons[dragon_key] += 1
                                    
                                    # Apply bonuses
                                    if total_coins > 0:
                                        c.execute('UPDATE users SET balance = balance + ? WHERE guild_id = ? AND user_id = ?',
                                                  (total_coins, self.guild_id, self.user_id))
                                    if total_luckycharms > 0:
                                        c.execute('''INSERT INTO user_luckycharms (guild_id, user_id, count) 
                                                     VALUES (?, ?, ?) 
                                                     ON CONFLICT(guild_id, user_id) 
                                                     DO UPDATE SET count = count + ?''',
                                                  (self.guild_id, self.user_id, total_luckycharms, total_luckycharms))
                                    
                                    conn.commit()
                                    conn.close()
                                    
                                    # Build result message
                                    result_text = f"🎉 **Opened {amount}x {pack_data['emoji']} {pack_data['name']}!**\n\n"
                                    result_text += f"**Dragons obtained:**\n"
                                    for dragon_key, count in sorted(total_dragons.items()):
                                        dragon_info = DRAGON_TYPES[dragon_key]
                                        result_text += f"{dragon_info['emoji']} {dragon_info['name']}: **x{count}**\n"
                                    
                                    if total_upgrades > 0:
                                        result_text += f"\n⭐ **{total_upgrades}** pack upgrades!\n"
                                    if total_coins > 0:
                                        result_text += f"💰 **+{total_coins:,}** bonus coins!\n"
                                    if total_luckycharms > 0:
                                        result_text += f"🍀 **+{total_luckycharms}** lucky charms!\n"
                                    if total_dragonscales > 0:
                                        result_text += f"<:dragonscale:1446278170998341693> **+{total_dragonscales}** dragonscales!\n"
                                    
                                    result_embed = discord.Embed(
                                        title="📦 Bulk Open Results",
                                        description=result_text,
                                        color=discord.Color.gold()
                                    )
                                    await interaction2.followup.send(embed=result_embed, ephemeral=False)
                            
                            # Show amount select
                            amount_view = discord.ui.View(timeout=60)
                            amount_view.add_item(AmountSelect())
                            await interaction.followup.send("How many packs would you like to open?", view=amount_view, ephemeral=False)
                    
                    self.add_item(PackSelect())

            
            view = BulkOpenView(self.guild_id, self.user_id, available_packs)
            await interaction.response.send_message("Select pack type for bulk opening:", view=view, ephemeral=False)
        
        def create_callback(self, pack_type_param):
            async def callback(interaction: discord.Interaction):
                pack_type = pack_type_param  # Capture the parameter
                if interaction.user.id != self.user_id:
                    await interaction.response.send_message("❌ This is not your pack menu!", ephemeral=False)
                    return
                
                # Check if user still has pack
                conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                c = conn.cursor()
                c.execute('SELECT count FROM user_packs WHERE guild_id = ? AND user_id = ? AND pack_type = ?',
                          (self.guild_id, self.user_id, pack_type))
                result = c.fetchone()
                
                if not result or result[0] <= 0:
                    await interaction.response.send_message("❌ You don't have this pack anymore!", ephemeral=False)
                    conn.close()
                    return
                
                # Deduct pack
                c.execute('UPDATE user_packs SET count = count - 1 WHERE guild_id = ? AND user_id = ? AND pack_type = ?',
                          (self.guild_id, self.user_id, pack_type))
                conn.commit()
                
                pack_data = PACK_TYPES[pack_type]
                
                # Animation stages
                stages = [
                    ("📦 Opening pack...", f"{pack_data['emoji']} **{pack_data['name']}**\n\n🔒 Locked"),
                    ("📦 Opening pack...", f"{pack_data['emoji']} **{pack_data['name']}**\n\n🔓 Unlocking..."),
                    ("📦 Opening pack...", f"{pack_data['emoji']} **{pack_data['name']}**\n\n🎉 Opening...")
                ]
                
                # Start animation
                embed = discord.Embed(
                    title=stages[0][0],
                    description=stages[0][1],
                    color=discord.Color.blue()
                )
                await interaction.response.send_message(embed=embed)
                
                # Animate through stages
                for i in range(1, len(stages)):
                    await asyncio.sleep(0.8)
                    embed.title = stages[i][0]
                    embed.description = stages[i][1]
                    await interaction.edit_original_response(embed=embed)
                
                await asyncio.sleep(0.5)
                
                # 0.5% chance to get dragonscales (1-3 minutes)
                dragonscale_dropped = False
                dragonscale_minutes = 0
                if random.random() < 0.005:  # 0.5% chance
                    dragonscale_minutes = random.randint(1, 3)
                    dragonscale_dropped = True
                    c.execute('''INSERT INTO dragonscales (guild_id, user_id, minutes)
                                 VALUES (?, ?, ?)
                                 ON CONFLICT(guild_id, user_id)
                                 DO UPDATE SET minutes = minutes + ?''',
                              (self.guild_id, self.user_id, dragonscale_minutes, dragonscale_minutes))
                    conn.commit()
                
                # 30% upgrade chance loop
                current_pack = pack_type
                upgrades = []
                while current_pack != 'celestial':
                    if random.random() < 0.30:  # 30% chance
                        current_index = PACK_UPGRADE_ORDER.index(current_pack)
                        current_pack = PACK_UPGRADE_ORDER[current_index + 1]
                        upgrades.append(current_pack)
                    else:
                        break
                
                # Show upgrade animation if upgraded
                if upgrades:
                    upgrade_text = f"{pack_data['emoji']} **{pack_data['name']}**\n\n"
                    for upgrade in upgrades:
                        upgrade_data = PACK_TYPES[upgrade]
                        upgrade_text += f"⬆️ Upgraded to {upgrade_data['emoji']} **{upgrade_data['name']}**!\n"
                    
                    embed.title = "✨ Pack Upgraded!"
                    embed.description = upgrade_text
                    embed.color = discord.Color.gold()
                    await interaction.edit_original_response(embed=embed)
                    await asyncio.sleep(1.5)
                
                # 0.025% chance to get dragonscales (1-3 minutes)
                dragonscale_dropped = False
                dragonscale_minutes = 0
                if random.random() < 0.00025:  # 0.025% chance
                    dragonscale_minutes = random.randint(1, 3)
                    dragonscale_dropped = True
                    c.execute('''INSERT INTO dragonscales (guild_id, user_id, minutes)
                                 VALUES (?, ?, ?)
                                 ON CONFLICT(guild_id, user_id)
                                 DO UPDATE SET minutes = minutes + ?''',
                              (self.guild_id, self.user_id, dragonscale_minutes, dragonscale_minutes))
                    conn.commit()
                
                # Get final pack value
                final_pack_data = PACK_TYPES[current_pack]
                pack_config = PACK_BASE_VALUES[current_pack]
                base_value = pack_config['base_value']
                coin_base = pack_config['coin_base']
                coin_variance = pack_config['coin_variance']
                
                # Variable coin reward: base ± variance
                variance_amount = coin_base * coin_variance
                coin_value = coin_base + random.uniform(-variance_amount, variance_amount)
                coin_value = int(coin_value)
                
                # Get 2-3 dragons with HIGH RARITY PRIORITY (not filling with cheap dragons)
                pack_tier_index = PACK_UPGRADE_ORDER.index(current_pack)
                dragons_received = {}
                value_filled = 0
                dragons_count = 0
                max_dragons_types = 3  # Max 3 different dragon types per pack
                
                # Pre-calculate dragon weights once
                dragon_weights = []
                for dragon_key_option in DRAGON_TYPES.keys():
                    dragon_spawn_chance = DRAGON_TYPES[dragon_key_option]['spawn_chance']
                    inverse_chance = 1.0 / (dragon_spawn_chance + 0.001)
                    
                    # Get dragon rarity tier
                    dragon_rarity = None
                    for rarity, dragons in DRAGON_RARITY_TIERS.items():
                        if dragon_key_option in dragons:
                            dragon_rarity = rarity
                            break
                    
                    # Assign weight based on pack tier and dragon rarity
                    if pack_tier_index <= 1:  # Wooden, Stone - ONLY COMMON
                        if dragon_rarity in ['common']:
                            weight = dragon_spawn_chance ** 0.3  # Heavily favor common
                        else:
                            weight = 0.0  # Block everything else
                    elif pack_tier_index == 2:  # Bronze - COMMON + UNCOMMON
                        if dragon_rarity in ['common', 'uncommon']:
                            weight = dragon_spawn_chance ** 0.4
                        else:
                            weight = 0.0  # Block rare+
                    elif pack_tier_index <= 4:  # Silver, Gold - NO COMMON, focus UNCOMMON/RARE/EPIC
                        if dragon_rarity in ['common']:
                            weight = 0.0  # BLOCK all baby dragons
                        elif dragon_rarity in ['uncommon', 'rare']:
                            weight = inverse_chance ** 0.2
                        elif dragon_rarity == 'epic':
                            weight = inverse_chance ** 0.1
                        else:
                            weight = 0.0
                    elif pack_tier_index <= 6:  # Platinum, Diamond - NO COMMON/UNCOMMON, focus RARE/EPIC/LEGENDARY
                        if dragon_rarity in ['common', 'uncommon']:
                            weight = 0.0  # BLOCK baby dragons and uncommon
                        elif dragon_rarity in ['rare']:
                            weight = inverse_chance ** 0.2
                        elif dragon_rarity in ['epic', 'legendary']:
                            weight = inverse_chance ** 0.5
                        else:
                            weight = inverse_chance ** 0.3
                    else:  # Celestial - ONLY LEGENDARY/MYTHIC/ULTRA
                        if dragon_rarity in ['common', 'uncommon', 'rare', 'epic']:
                            weight = 0.0  # BLOCK all common dragons
                        else:  # legendary, mythic, ultra
                            weight = inverse_chance ** 0.6
                    
                    dragon_weights.append(weight)
                
                dragon_keys_list = list(DRAGON_TYPES.keys())
                
                # Get dragons: prioritize high rarity, limit to 3 types, stop at base_value
                while value_filled < base_value and len(dragons_received) < max_dragons_types:
                    dragon_key = random.choices(dragon_keys_list, weights=dragon_weights)[0]
                    dragon_data = DRAGON_TYPES[dragon_key]
                    
                    if dragon_key not in dragons_received:
                        dragons_received[dragon_key] = 0
                    dragons_received[dragon_key] += 1
                    value_filled += dragon_data['value']
                
                # For display, show the rarest dragon received
                rarest_dragon_key = None
                rarest_rarity_idx = -1
                rarity_order = ['common', 'uncommon', 'rare', 'epic', 'legendary', 'mythic', 'ultra']
                
                for dragon_key in dragons_received.keys():
                    for rarity, dragons in DRAGON_RARITY_TIERS.items():
                        if dragon_key in dragons:
                            rarity_idx = rarity_order.index(rarity) if rarity in rarity_order else -1
                            if rarity_idx > rarest_rarity_idx:
                                rarest_rarity_idx = rarity_idx
                                rarest_dragon_key = dragon_key
                            break
                
                dragon_key = rarest_dragon_key if rarest_dragon_key else list(dragons_received.keys())[0]
                dragon_data = DRAGON_TYPES[dragon_key]
                final_amount = dragons_received[dragon_key]  # Only show count of THIS dragon, not total
                total_dragons_count = sum(dragons_received.values())
                guaranteed = 1
                
                # Special cutscene for rare dragon from common pack (<1 guaranteed)
                if guaranteed < 1:
                    embed.title = "✨ Something special..."
                    embed.description = f"{final_pack_data['emoji']} **{final_pack_data['name']}**\n\n✨ ✨ ✨\n*A rare energy emanates from the pack...*"
                    embed.color = discord.Color.purple()
                    await interaction.edit_original_response(embed=embed)
                    await asyncio.sleep(2.0)
                
                # Add dragons to user
                for drag_key, drag_amount in dragons_received.items():
                    await add_dragons(self.guild_id, self.user_id, drag_key, drag_amount)
                
                # Update Dragon Nest bounties if active
                nest_conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                nest_c = nest_conn.cursor()
                nest_active_check = nest_c.execute('SELECT active_until FROM dragon_nest_active WHERE guild_id = ? AND user_id = ?',
                                                    (self.guild_id, self.user_id)).fetchone()
                if nest_active_check and nest_active_check[0] > int(time.time()):
                    bounties_result = nest_c.execute('SELECT bounties_active FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                                                       (self.guild_id, self.user_id)).fetchone()
                    if bounties_result and bounties_result[0]:
                        import ast
                        pack_bounties = ast.literal_eval(bounties_result[0])
                        # Get dragon rarity level
                        dragon_rarity_level_pack = 0
                        for idx, dragon_key_check in enumerate(DRAGON_TYPES.keys()):
                            if dragon_key_check == dragon_key:
                                if idx >= 5: dragon_rarity_level_pack = 1  # Uncommon+
                                if idx >= 9: dragon_rarity_level_pack = 2  # Rare+
                                if idx >= 14: dragon_rarity_level_pack = 3  # Epic+
                                if idx >= 18: dragon_rarity_level_pack = 4  # Legendary+
                                if idx >= 20: dragon_rarity_level_pack = 5  # Mythic+
                                break
                        
                        # Update bounties
                        for bounty in pack_bounties:
                            if bounty['type'] == 'catch_any':
                                bounty['progress'] = min(bounty['progress'] + final_amount, bounty['target'])
                            elif bounty['type'] == 'catch_rarity_or_higher' and bounty.get('rarity_level'):
                                if dragon_rarity_level_pack >= bounty['rarity_level']:
                                    bounty['progress'] = min(bounty['progress'] + final_amount, bounty['target'])
                        
                        # Save updated bounties
                        nest_c.execute('UPDATE dragon_nest SET bounties_active = ? WHERE guild_id = ? AND user_id = ?',
                                      (str(pack_bounties), self.guild_id, self.user_id))
                        nest_conn.commit()
                nest_conn.close()
                
                # Determine drop chances based on pack rarity (tier index)
                pack_tier_idx = PACK_UPGRADE_ORDER.index(current_pack)  # Current pack after potential upgrades
                if pack_tier_idx <= 1:  # Wooden, Stone
                    lucky_charm_chance = 0.01  # 1%
                    dragonscale_chance = 0.0001  # 0.01%
                elif pack_tier_idx <= 3:  # Bronze, Silver
                    lucky_charm_chance = 0.02  # 2%
                    dragonscale_chance = 0.0002  # 0.02%
                elif pack_tier_idx <= 5:  # Gold, Platinum
                    lucky_charm_chance = 0.03  # 3%
                    dragonscale_chance = 0.0005  # 0.05%
                else:  # Diamond, Celestial
                    lucky_charm_chance = 0.05  # 5%
                    dragonscale_chance = 0.001  # 0.1%
                
                # Lucky Charm drop (rarity-based)
                luckycharm_dropped = False
                if random.random() < lucky_charm_chance:
                    luckycharm_dropped = True
                    conn_charm = sqlite3.connect('dragon_bot.db', timeout=120.0)
                    c_charm = conn_charm.cursor()
                    c_charm.execute('''INSERT INTO user_luckycharms (guild_id, user_id, count)
                                       VALUES (?, ?, 1)
                                       ON CONFLICT(guild_id, user_id)
                                       DO UPDATE SET count = count + 1''',
                                    (self.guild_id, self.user_id))
                    conn_charm.commit()
                    conn_charm.close()
                
                # Dragonscale drop (rarity-based)
                dragonscale_dropped = False
                dragonscale_minutes = 0
                if random.random() < dragonscale_chance:
                    dragonscale_minutes = random.randint(1, 3)
                    dragonscale_dropped = True
                    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                    c = conn.cursor()
                    c.execute('''INSERT INTO dragonscales (guild_id, user_id, minutes)
                                 VALUES (?, ?, ?)
                                 ON CONFLICT(guild_id, user_id)
                                 DO UPDATE SET minutes = minutes + ?''',
                              (self.guild_id, self.user_id, dragonscale_minutes, dragonscale_minutes))
                    conn.commit()
                    conn.close()
                
                # Calculate coin value (variable reward)
                await asyncio.to_thread(update_balance, self.guild_id, self.user_id, coin_value)
                
                # Build bonus text with drop rates shown
                # Map pack index to correct pack tier name
                pack_names_by_tier = {
                    0: 'Wooden', 1: 'Stone', 2: 'Bronze', 3: 'Silver',
                    4: 'Gold', 5: 'Platinum', 6: 'Diamond', 7: 'Celestial'
                }
                pack_tier_name = pack_names_by_tier.get(pack_tier_idx, 'Unknown')
                bonus_text = ""
                
                if luckycharm_dropped:
                    bonus_text = "\n🍀 **+1 Lucky Charm!**"
                if dragonscale_dropped:
                    bonus_text = f"\n⚡ **+{dragonscale_minutes} Dragonscale Minutes!**" + bonus_text
                
                # Build reward text showing all dragons
                reward_text = "**Reward:**\n"
                for drag_key, drag_count in sorted(dragons_received.items(), key=lambda x: -DRAGON_TYPES[x[0]]['value']):
                    drag_data = DRAGON_TYPES[drag_key]
                    reward_text += f"{drag_data['emoji']} **{drag_count}x {drag_data['name']}**\n"
                reward_text += f"💰 **{int(coin_value)} 🪙**"
                
                # Final result
                final_embed = discord.Embed(
                    title="🎁 Pack Opened!",
                    description=f"{final_pack_data['emoji']} **{final_pack_data['name']}**\n\n"
                                f"{reward_text}{bonus_text}\n\n"
                                f"*Added to your collection!*",
                    color=discord.Color.gold()
                )
                
                if upgrades:
                    final_embed.set_footer(text=f"Upgraded {len(upgrades)} time(s)! 🎉")
                
                await interaction.edit_original_response(embed=final_embed)
                
                # Track for dragonpass quest
                _qr = await asyncio.to_thread(check_dragonpass_quests, self.guild_id, self.user_id, 'open_pack', 1)
                if _qr and _qr[3]:
                    await send_quest_notification(bot, self.guild_id, self.user_id, _qr[3])

                # Update the original pack list message
                await asyncio.sleep(2)
                
                # Fetch updated pack counts
                conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                c = conn.cursor()
                c.execute('SELECT pack_type, count FROM user_packs WHERE guild_id = ? AND user_id = ? AND count > 0',
                          (self.guild_id, self.user_id))
                updated_packs = c.fetchall()
                conn.close()
                
                # Create updated embed
                if not updated_packs:
                    updated_embed = discord.Embed(
                        title="📦 Your Packs",
                        description="✅ All packs opened! You don't have any packs left.",
                        color=discord.Color.green()
                    )
                    # Remove all buttons
                    await interaction.message.edit(embed=updated_embed, view=None)
                else:
                    updated_embed = discord.Embed(
                        title="📦 Your Packs",
                        description="Click a button to open a pack!",
                        color=discord.Color.blue()
                    )
                    
                    for pack_type, count in updated_packs:
                        pack_data = PACK_TYPES.get(pack_type)
                        if pack_data:
                            updated_embed.add_field(
                                name=f"{pack_data['emoji']} {pack_data['name']}",
                                value=f"Count: {count}",
                                inline=True
                            )
                    
                    # Create new view with updated buttons
                    new_view = OpenPackView(self.guild_id, self.user_id, updated_packs)
                    await interaction.message.edit(embed=updated_embed, view=new_view)
            
            return callback
    
    # Create embed showing available packs
    embed = discord.Embed(
        title="📦 Your Packs",
        description="Click a button to open a pack!",
        color=discord.Color.blue()
    )
    
    for pack_type, count in packs:
        pack_data = PACK_TYPES.get(pack_type)
        if pack_data:
            embed.add_field(
                name=f"{pack_data['emoji']} {pack_data['name']}",
                value=f"Count: {count}",
                inline=True
            )
    
    view = OpenPackView(interaction.guild_id, interaction.user.id, packs)
    await interaction.response.send_message(embed=embed, view=view)

@bot.tree.command(name="dragonnest", description="Access the Dragon Nest leveling system")
async def dragonnest(interaction: discord.Interaction):
    """Dragon Nest leveling system (like Cat Mafia)"""
    await interaction.response.defer(ephemeral=False)
    
    try:
        conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
        c = conn.cursor()
        
        # Get or create nest data
        c.execute('INSERT OR IGNORE INTO dragon_nest (guild_id, user_id) VALUES (?, ?)',
                  (interaction.guild_id, interaction.user.id))
        c.execute('SELECT level, xp, bounties_completed, bounties_active FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                  (interaction.guild_id, interaction.user.id))
        result = c.fetchone()
        
        # Check if there's a pending level up (sacrifice waiting)
        c.execute('SELECT level, perks_json FROM pending_perks WHERE guild_id = ? AND user_id = ?',
                  (interaction.guild_id, interaction.user.id))
        pending_result = c.fetchone()
        
        conn.commit()
        conn.close()
        
    except sqlite3.OperationalError as e:
        # Database schema issue - ignore and show default nest view
        await interaction.followup.send("⚠️ Database integrity issue detected. Please try again in a moment.")
        return
    
    # If there's a pending data, handle appropriately
    if pending_result:
        pending_level, perks_json = pending_result
        pending_data = json.loads(perks_json)
        
        # Check what type of pending action this is
        if 'sacrifice_list' in pending_data:
            # This is a sacrifice/level up screen
            sacrifice_list = pending_data['sacrifice_list']
            new_level = pending_data['new_level']
            
            # Handle both old format (list of tuples) and new format (dict)
            if isinstance(sacrifice_list, list):
                sacrifice_list = {dragon_type: count for dragon_type, count in sacrifice_list}
            
            # Build sacrifice display
            sacrifice_display = ""
            for dragon_type, count in sacrifice_list.items():
                dragon_data = DRAGON_TYPES[dragon_type]
                sacrifice_display += f"{dragon_data['emoji']} {count}x {dragon_data['name']}\n"
            
            embed = discord.Embed(
                title="🎉 Dragon Nest Level Complete!",
                description=f"You completed all bounties and reached **Level {new_level}: {LEVEL_NAMES.get(new_level, 'Unknown')}**!\n\n"
                            f"🐉 **Dragons to Sacrifice:**\n{sacrifice_display}\n"
                            f"Click **Submit Dragons** to confirm and unlock your perk reward!",
                color=discord.Color.green()
            )
            
            # Create sacrifice view for this user
            class DragonSacrificeViewInstance(discord.ui.View):
                def __init__(self, guild_id, user_id, sac_list, level):
                    super().__init__(timeout=300)
                    self.guild_id = guild_id
                    self.user_id = user_id
                    self.sacrifice_list = sac_list
                    self.level = level
                    
                    submit_button = discord.ui.Button(
                        label="💾 Submit Dragons",
                        style=discord.ButtonStyle.success,
                        custom_id=f"submit_dragons_{guild_id}_{user_id}_{level}"
                    )
                    submit_button.callback = self.submit_dragons
                    self.add_item(submit_button)
                
                async def submit_dragons(self, btn_interaction: discord.Interaction):
                    if btn_interaction.user.id != self.user_id:
                        await btn_interaction.response.send_message("This is not your action!", ephemeral=True)
                        return
                    
                    await btn_interaction.response.defer()
                    
                    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                    c = conn.cursor()
                    
                    # Remove dragons and level up
                    for dragon_type, count in self.sacrifice_list.items():
                        c.execute('UPDATE user_dragons SET count = count - ? WHERE guild_id = ? AND user_id = ? AND dragon_type = ?',
                                  (count, self.guild_id, self.user_id, dragon_type))
                    
                    # Update level
                    c.execute('UPDATE dragon_nest SET level = ? WHERE guild_id = ? AND user_id = ?',
                              (self.level, self.guild_id, self.user_id))
                    
                    # Delete pending perks entry
                    c.execute('DELETE FROM pending_perks WHERE guild_id = ? AND user_id = ?',
                              (self.guild_id, self.user_id))
                    
                    # Check if player reached max level (10)
                    c.execute('SELECT level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                              (self.guild_id, self.user_id))
                    current_level = c.fetchone()[0]
                    
                    conn.commit()
                    conn.close()
                    
                    if current_level < 10:
                        # Generate perks for next level
                        # Get upgrade level for proper perk rarity filtering
                        c_upg = conn.cursor()
                        c_upg.execute('SELECT upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                        upg_result = c_upg.fetchone()
                        upgrade_level_val = upg_result[0] if upg_result else 0
                        new_selected_perks = generate_unique_perks(current_level + 1, 3, upgrade_level_val)
                        conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                        c = conn.cursor()
                        c.execute('''INSERT OR REPLACE INTO pending_perks (guild_id, user_id, level, perks_json)
                                     VALUES (?, ?, ?, ?)''',
                                  (self.guild_id, self.user_id, current_level + 1, json.dumps({'selected_perks': new_selected_perks})))
                        conn.commit()
                        conn.close()
                        
                        await btn_interaction.followup.send(
                            f"✨ **Level {self.level} Unlocked!**\n"
                            f"🎁 A new perk is waiting for you! Use `/dragonnest` to claim it.",
                            ephemeral=False
                        )
                    else:
                        await btn_interaction.followup.send(
                            f"🏆 **Max Level Reached!**\n"
                            f"You've reached the maximum Dragon Nest level!",
                            ephemeral=False
                        )
            
            view = DragonSacrificeViewInstance(interaction.guild_id, interaction.user.id, sacrifice_list, new_level)
            await interaction.followup.send(embed=embed, view=view, ephemeral=False)
            return
        
        elif 'selected_perks' in pending_data:
            # This is a perk selection screen
            selected_perks = pending_data['selected_perks']
            pending_level = pending_level
            
            # Build perk selection view
            perks_list = []
            for rarity, perk in selected_perks:
                # perk is already a dict from json.loads
                perks_list.append((rarity, perk))
            
            rarity_emoji = {"common": "⚪", "uncommon": "🟢", "rare": "🔵", "epic": "🟣", "legendary": "🟡"}
            perk_text = ""
            for i, (r, p) in enumerate(perks_list, 1):
                perk_text += f"{i}. {rarity_emoji.get(r, '⚪')} **{p.get('name', 'Unknown')}** ({r.capitalize()})\n   *{p.get('effect', '')}*\n\n"
            
            embed = discord.Embed(
                title=f"🎁 Claim Missing Perk - Level {pending_level}",
                description=perk_text + "Select a perk to claim!",
                color=discord.Color.gold()
            )
            
            # Get remaining missing perks count
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            c.execute('SELECT COUNT(*) FROM user_perks WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            perk_count = c.fetchone()[0]
            
            c.execute('SELECT level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            current_level = c.fetchone()[0]
            conn.close()
            
            total_missing = current_level - perk_count
            embed.set_footer(text=f"Missing perks: {total_missing}")
            
            class MissingPerkSelectionView(discord.ui.View):
                def __init__(self, guild_id, user_id, perks, level, total_missing):
                    super().__init__(timeout=180)
                    self.guild_id = guild_id
                    self.user_id = user_id
                    self.perks = perks
                    self.level = level
                    self.total_missing = total_missing
                    
                    rarity_emoji = {"common": "⚪", "uncommon": "🟢", "rare": "🔵", "epic": "🟣", "legendary": "🟡"}
                    for i, (rarity, perk) in enumerate(perks, 1):
                        button = discord.ui.Button(
                            label=f"{i}",
                            style=discord.ButtonStyle.primary if rarity in ['common', 'uncommon'] else discord.ButtonStyle.success if rarity == 'rare' else discord.ButtonStyle.danger if rarity == 'epic' else discord.ButtonStyle.blurple,
                            custom_id=f"claim_perk_{guild_id}_{user_id}_{level}_{i}"
                        )
                        button.callback = self.create_callback(i-1, rarity, perk)
                        self.add_item(button)
                
                def create_callback(self, index, rarity, perk):
                    async def callback(btn_interaction: discord.Interaction):
                        if btn_interaction.user.id != self.user_id:
                            await btn_interaction.response.send_message("This is not your selection!", ephemeral=False)
                            return
                        
                        try:
                            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                            c = conn.cursor()
                            
                            # Add perk to collection (not activated yet)
                            c.execute('''INSERT OR IGNORE INTO user_perks (guild_id, user_id, perk_id, perk_name, perk_effect, perk_value, rarity)
                                         VALUES (?, ?, ?, ?, ?, ?, ?)''',
                                      (self.guild_id, self.user_id, perk['id'], perk['name'],
                                       perk['effect'], perk.get('value', 0), rarity))
                            
                            # Delete the pending perk for this level
                            c.execute('DELETE FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level = ?',
                                      (self.guild_id, self.user_id, self.level))
                            
                            # Check if there are more missing perks
                            c.execute('SELECT COUNT(*) FROM user_perks WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                            new_count = c.fetchone()[0]
                            
                            c.execute('SELECT level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                            current_level = c.fetchone()[0]
                            
                            conn.commit()
                            conn.close()
                            
                            remaining = current_level - new_count
                            
                            rarity_emoji = {"common": "⚪", "uncommon": "🟢", "rare": "🔵", "epic": "🟣", "legendary": "🟡"}
                            
                            if remaining > 0:
                                # More perks to claim - check for stored perks or generate new
                                next_level = new_count + 1
                                
                                # Check if we have stored perks for next level
                                conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                                c = conn.cursor()
                                c.execute('SELECT perks_json FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level = ?',
                                          (self.guild_id, self.user_id, next_level))
                                stored_next = c.fetchone()
                                
                                # Get upgrade level for proper perk generation
                                c.execute('SELECT upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                                          (self.guild_id, self.user_id))
                                upg_res_sel = c.fetchone()
                                upg_level_sel = upg_res_sel[0] if upg_res_sel else 0
                                conn.close()
                                
                                if stored_next:
                                    import json
                                    stored_data = json.loads(stored_next[0])
                                    if isinstance(stored_data, dict) and 'selected_perks' in stored_data:
                                        next_perks = stored_data['selected_perks']
                                    else:
                                        next_perks = stored_data if isinstance(stored_data, list) else []
                                else:
                                    # Generate new perks if none stored
                                    next_perks = generate_unique_perks(next_level, 3, upg_level_sel)
                                    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                                    c = conn.cursor()
                                    import json
                                    c.execute('''INSERT OR REPLACE INTO pending_perks (guild_id, user_id, level, perks_json)
                                                 VALUES (?, ?, ?, ?)''',
                                              (self.guild_id, self.user_id, next_level, json.dumps({'selected_perks': next_perks})))
                                    conn.commit()
                                    conn.close()
                                
                                # Show next perk selection
                                perk_text = ""
                                for i, (r, p) in enumerate(next_perks, 1):
                                    perk_text += f"{i}. {rarity_emoji.get(r, '⚪')} **{p['name']}** ({r.capitalize()})\n   *{p['effect']}*\n\n"
                                
                                next_embed = discord.Embed(
                                    title=f"🎁 Claim Missing Perk - Level {next_level}",
                                    description=perk_text + "Select a perk to claim!",
                                    color=discord.Color.gold()
                                )
                                next_embed.set_footer(text=f"Missing perks: {remaining - 1}")
                                
                                await btn_interaction.response.send_message(embed=next_embed, view=MissingPerkSelectionView(self.guild_id, self.user_id, next_perks, next_level, remaining - 1), ephemeral=False)
                            else:
                                # All perks claimed!
                                await btn_interaction.response.send_message("🎉 You've claimed all missing perks!", ephemeral=False)
                        except Exception as e:
                            import traceback
                            await btn_interaction.response.send_message(f"❌ Error claiming perk: {str(e)}", ephemeral=True)
                            traceback.print_exc()
                    
                    return callback
            
            view = MissingPerkSelectionView(interaction.guild_id, interaction.user.id, perks_list, pending_level, total_missing)
            await interaction.followup.send(embed=embed, view=view)
            return
        
        else:
            # Unknown pending data format - just clear it and show normal nest view
            c = sqlite3.connect('dragon_bot.db', timeout=120.0)
            cursor = c.cursor()
            c.execute('DELETE FROM pending_perks WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            c.commit()
            c.close()
            
            # Fall through to normal display
            perks_list = []  # Initialize as empty so it doesn't cause UnboundLocalError
            new_level = 0

        class PerkSelectionView(discord.ui.View):
            def __init__(self, guild_id, user_id, perks, level):
                super().__init__(timeout=300)
                self.guild_id = guild_id
                self.user_id = user_id
                self.perks = perks
                self.level = level
            
                for i, (rarity, perk) in enumerate(perks, 1):
                    button = discord.ui.Button(
                        label=f"{i}. {perk['name']}",
                        style=discord.ButtonStyle.primary if rarity in ['common', 'uncommon'] else discord.ButtonStyle.success if rarity == 'rare' else discord.ButtonStyle.danger if rarity == 'epic' else discord.ButtonStyle.blurple,
                        custom_id=f"perk_lvlup_{guild_id}_{user_id}_{perk['id']}"
                    )
                    button.callback = self.create_callback(i-1, rarity, perk)
                    self.add_item(button)
            
            def create_callback(self, index, rarity, perk):
                async def callback(interaction: discord.Interaction):
                    # User selected a perk
                    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                    c = conn.cursor()
                    
                    # Mark perk as selected
                    c.execute('UPDATE user_perks SET selected = 1 WHERE guild_id = ? AND user_id = ? AND perk_id = ?',
                              (self.guild_id, self.user_id, perk['id']))
                    
                    # Confirm level up and reset perk activation for new level
                    c.execute('UPDATE dragon_nest SET level = ?, perks_activated_at_current_level = 0 WHERE guild_id = ? AND user_id = ?',
                              (self.level, self.guild_id, self.user_id))
                    
                    # Remove pending sacrifice
                    c.execute('DELETE FROM pending_perks WHERE guild_id = ? AND user_id = ?',
                              (self.guild_id, self.user_id))
                    
                    conn.commit()
                    conn.close()
                    
                    await interaction.response.send_message(
                        f"🎉 **Level {self.level} Unlocked!**\n"
                        f"✨ You selected: **{perk['name']}**\n"
                        f"Your perk is now available to activate!",
                        ephemeral=False
                    )
                
                return callback
        
        # ONLY create and display PerkSelectionView if we have perks
        if perks_list:
            view = PerkSelectionView(interaction.guild_id, interaction.user.id, perks_list, new_level)
            await interaction.followup.send(embed=embed, view=view, ephemeral=False)
            return
        # Otherwise, fall through to normal nest display below
    
    # Normal Dragon Nest display
    c = sqlite3.connect('dragon_bot.db', timeout=120.0)
    cursor = c.cursor()
    
    # Check if Dragon Nest is active
    cursor.execute('SELECT active_until FROM dragon_nest_active WHERE guild_id = ? AND user_id = ?',
                   (interaction.guild_id, interaction.user.id))
    active_result = cursor.fetchone()
    
    # Check if raid boss is active
    cursor.execute('SELECT expires_at FROM raid_bosses WHERE guild_id = ? AND expires_at > ?',
                   (interaction.guild_id, int(time.time())))
    raid_active = cursor.fetchone()
    
    # Get upgrade level
    cursor.execute('SELECT upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                   (interaction.guild_id, interaction.user.id))
    upgrade_result = cursor.fetchone()
    
    c.close()
    
    level = result[0] if result else 0
    xp = result[1] if result else 0
    bounties_completed = result[2] if result else 0
    bounties_active = result[3] if result else None
    upgrade_level = upgrade_result[0] if upgrade_result else 0
    
    level_name = LEVEL_NAMES.get(level, "Unknown")
    character = LEVEL_CHARACTERS.get(level, "None")
    lore_text = LEVEL_LORE.get(level, "Your journey continues...")
    
    # Check if active
    is_active = active_result and active_result[0] > int(time.time())
    time_left = (active_result[0] - int(time.time())) if is_active else 0
    
    # If raid boss is active and dragon nest is active, it's paused
    is_paused = is_active and raid_active
    
    embed = discord.Embed(
        title=f"🏰 {interaction.user.display_name}'s Dragon Nest",
        description=f"**Level {level}: {level_name}** | Upgrade Tier: {upgrade_level}/5\n*{character}*\n\n✨ {lore_text}",
        color=discord.Color.red() if is_paused else discord.Color.green() if is_active else discord.Color.purple()
    )
    
    # Set thumbnail if available
    thumbnail_url = LEVEL_THUMBNAILS.get(level)
    if thumbnail_url:
        embed.set_thumbnail(url=thumbnail_url)
    
    embed.add_field(name="Total Bounties Completed", value=str(bounties_completed), inline=True)
    embed.add_field(name="Current Level", value=f"{level}/10", inline=True)
    
    # Show pause message if raid is active
    if is_paused:
        embed.add_field(
            name="⏸️ PAUSED - Raid Boss Active!",
            value="Dragon Nest is paused while a raid boss is active.\nNo normal dragons are spawning.",
            inline=False
        )
    
    # Show active bounties if nest is active (and not paused)
    if is_active and bounties_active and not is_paused:
        import ast
        bounties = ast.literal_eval(bounties_active)
        bounty_text = ""
        for i, bounty in enumerate(bounties, 1):
            progress = bounty['progress']
            target = bounty['target']
            if bounty['type'] == 'catch_any':
                bounty_text += f"📋 **Bounty {i}:** Catch {target} dragons ({progress}/{target})\n"
            elif bounty['type'] == 'catch_type':
                dragon_name = DRAGON_TYPES[bounty['dragon_type']]['name']
                dragon_emoji = DRAGON_TYPES[bounty['dragon_type']]['emoji']
                bounty_text += f"📋 **Bounty {i}:** Catch {target}x {dragon_emoji} {dragon_name} ({progress}/{target})\n"
            elif bounty['type'] == 'catch_rarity_or_higher':
                rarity_names = {1: 'Uncommon', 2: 'Rare', 3: 'Epic', 4: 'Legendary', 5: 'Mythic'}
                rarity_name = rarity_names.get(bounty.get('rarity_level'), 'Rare')
                bounty_text += f"📋 **Bounty {i}:** Catch {target} {rarity_name}+ dragons ({progress}/{target})\n"
        
        embed.add_field(name="🎯 Active Bounties", value=bounty_text, inline=False)
        embed.add_field(name="⏰ Time Remaining", value=format_time_remaining(time_left), inline=False)
    
    embed.set_footer(text="Activate Dragon Nest to start bounties!")
    
    # Create button view
    class DragonNestView(discord.ui.View):
        def __init__(self, is_active=False, guild_id=None, user_id=None, current_level=0):
            super().__init__(timeout=180)
            self.is_active = is_active
            self.guild_id = guild_id
            self.user_id = user_id
            self.current_level = current_level
            
            # Button 1: Activate Dragon Nest (only if NOT active)
            if not is_active:
                activate_button = discord.ui.Button(
                    label="Activate Dragon Nest",
                    style=discord.ButtonStyle.green,
                    emoji="🔥",
                    custom_id="activate_nest"
                )
                activate_button.callback = self.activate_nest
                self.add_item(activate_button)
            
            # Button 2: View Perks (always visible)
            view_perks_button = discord.ui.Button(
                label="View Perks",
                style=discord.ButtonStyle.blurple,
                emoji="✨",
                custom_id="view_perks"
            )
            view_perks_button.callback = self.view_perks
            self.add_item(view_perks_button)
            
            # Button 3: Upgrade Dragon Nest (always visible)
            upgrade_button = discord.ui.Button(
                label="Upgrade Dragon Nest",
                style=discord.ButtonStyle.primary,
                emoji="⬆️",
                custom_id="upgrade_nest"
            )
            upgrade_button.callback = self.upgrade_nest
            self.add_item(upgrade_button)
            
            # Button 4: Help (always visible)
            help_button = discord.ui.Button(
                label="Help",
                style=discord.ButtonStyle.gray,
                emoji="❓",
                custom_id="help"
            )

            help_button.callback = self.help_button
            self.add_item(help_button)
            
            # Button 5: Claim Missing Perks - ONLY for users with upgrades but no active perks
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            c.execute('SELECT upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                      (guild_id, user_id))
            result = c.fetchone()
            upgrade_level = result[0] if result else 0
            
            # Count ALL ACTIVE perks (regardless of expiration - if they're in the table, they've been claimed)
            c.execute('SELECT COUNT(*) FROM active_perks WHERE guild_id = ? AND user_id = ?',
                      (guild_id, user_id))
            active_perks_count = c.fetchone()[0]
            
            conn.close()
            
            # Button should ONLY show if user has upgraded Dragon Nest but lost their perks
            if upgrade_level > 0 and active_perks_count == 0:
                select_perk_button = discord.ui.Button(
                    label="Claim Missing Perks",
                    style=discord.ButtonStyle.blurple,
                    emoji="🎁",
                    custom_id="select_perk"
                )
                select_perk_button.callback = self.claim_missing_perks
                self.add_item(select_perk_button)
        
        async def claim_missing_perks(self, interaction: discord.Interaction):
            """Allow users to claim their missing perks (both level-ups and upgrades)"""
            await interaction.response.defer()
            
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            
            # Get current level and collected perks count
            c.execute('SELECT level, upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            result = c.fetchone()
            current_level = result[0] if result else 0
            upgrade_level = result[1] if result and len(result) > 1 else 0
            
            # Count active perks (permanent perks already claimed)
            c.execute('SELECT COUNT(*) FROM active_perks WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            active_perks_count = c.fetchone()[0]
            
            conn.close()
            
            # PRIORITY 1: EMERGENCY - User has upgrade_level but NO active perks
            # This means they lost their startup perks - regenerate and offer them PER TIER!
            if upgrade_level > 0 and active_perks_count == 0:
                # Start with Tier 1
                await self.show_tier_perk_selection(interaction, interaction.guild_id, interaction.user.id, tier=1, upgrade_level=upgrade_level)
                return
            
            # Continue with normal logic for other cases
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            
            # Get current level and collected perks count
            c.execute('SELECT level, upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            result = c.fetchone()
            current_level = result[0] if result else 0
            upgrade_level = result[1] if result and len(result) > 1 else 0
            
            # Count how many perks user has collected
            c.execute('SELECT COUNT(*) FROM user_perks WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            perks_count = c.fetchone()[0]
            
            # Check for missing level-up perks
            expected_perks = min(current_level, 10)  # Cap at level 10
            missing_level_perks = expected_perks - perks_count
            
            # Check for missing upgrade perks (NEW FORMAT: stored with level=0)
            c.execute('SELECT perks_json FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level = 0',
                      (interaction.guild_id, interaction.user.id))
            upgrade_perks_result = c.fetchone()
            
            # Check for OLD FORMAT upgrade perks (level < 0) for backwards compatibility
            c.execute('SELECT level, perks_json FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level < 0 ORDER BY level DESC',
                      (interaction.guild_id, interaction.user.id))
            old_upgrade_results = c.fetchall()
            
            conn.close()
            
            has_upgrade_perks = False
            upgrade_tiers_available = {}
            use_old_format = False
            
            # Check NEW FORMAT first
            if upgrade_perks_result:
                try:
                    import json
                    upgrade_data = json.loads(upgrade_perks_result[0])
                    upgrade_tiers_available = upgrade_data.get('upgrade_tiers', {})
                    has_upgrade_perks = len(upgrade_tiers_available) > 0
                except:
                    has_upgrade_perks = False
            
            # If no new format perks, check OLD FORMAT
            if not has_upgrade_perks and len(old_upgrade_results) > 0:
                has_upgrade_perks = True
                use_old_format = True
                # Convert old format to new format for consistent handling
                for level_val, perks_json in old_upgrade_results:
                    actual_tier = abs(level_val)  # level is negative, e.g., -1, -2
                    try:
                        import json
                        stored_data = json.loads(perks_json)
                        if isinstance(stored_data, dict) and 'selected_perks' in stored_data:
                            upgrade_tiers_available[str(actual_tier)] = {
                                'perks': stored_data['selected_perks'],
                                'level_marker': level_val
                            }
                        else:
                            upgrade_tiers_available[str(actual_tier)] = {
                                'perks': stored_data if isinstance(stored_data, list) else [],
                                'level_marker': level_val
                            }
                    except:
                        pass
            
            # Determine which perks to offer first: upgrade perks (if available) or level perks
            if has_upgrade_perks:
                # Show the EARLIEST upgrade tier that hasn't been claimed yet
                # Start from tier 1
                earliest_unclaimed_tier = None
                for tier_str in ['1', '2', '3', '4', '5']:
                    if tier_str in upgrade_tiers_available:
                        earliest_unclaimed_tier = tier_str
                        break
                
                if earliest_unclaimed_tier:
                    tier_data = upgrade_tiers_available[earliest_unclaimed_tier]
                    selected_perks = tier_data.get('perks', [])
                    
                    if not selected_perks:
                        await interaction.followup.send("❌ Error loading upgrade perks. Please try again later.", ephemeral=True)
                        return
                    
                    # Build embed for upgrade perks
                    rarity_emoji = {"common": "⚪", "uncommon": "🟢", "rare": "🔵", "epic": "🟣", "legendary": "🟡"}
                    perk_text = ""
                    for i, (rarity, perk) in enumerate(selected_perks, 1):
                        perk_text += f"{i}. {rarity_emoji.get(rarity, '⚪')} **{perk['name']}** ({rarity.capitalize()})\n   *{perk['effect']}*\n\n"
                    
                    # Count how many tiers are left
                    remaining_tiers = sum(1 for t in ['1', '2', '3', '4', '5'] if t in upgrade_tiers_available)
                    
                    embed = discord.Embed(
                        title=f"🎁 Claim Upgrade Tier {earliest_unclaimed_tier} Perks",
                        description=perk_text + "Select a perk to claim!",
                        color=discord.Color.gold()
                    )
                    embed.set_footer(text=f"Upgrade perks remaining: {remaining_tiers}")
                    
                    # Create view for upgrade perk selection
                    class UpgradePerkSelectionView(discord.ui.View):
                        def __init__(self, guild_id, user_id, perks, upgrade_tier_str, missing_level_perks_val):
                            super().__init__(timeout=180)
                            self.guild_id = guild_id
                            self.user_id = user_id
                            self.perks = perks
                            self.upgrade_tier_str = upgrade_tier_str
                            self.missing_level_perks = missing_level_perks_val
                            
                            rarity_emoji_local = {"common": "⚪", "uncommon": "🟢", "rare": "🔵", "epic": "🟣", "legendary": "🟡"}
                            for i, (rarity, perk) in enumerate(perks, 1):
                                button = discord.ui.Button(
                                    label=f"{i}",
                                    style=discord.ButtonStyle.primary if rarity in ['common', 'uncommon'] else discord.ButtonStyle.success if rarity == 'rare' else discord.ButtonStyle.danger if rarity == 'epic' else discord.ButtonStyle.blurple,
                                    custom_id=f"claim_upgrade_perk_{guild_id}_{user_id}_{upgrade_tier_str}_{i}"
                                )
                                button.callback = self.create_callback(i-1, rarity, perk)
                                self.add_item(button)
                        
                        def create_callback(self, index, rarity, perk):
                            async def callback(btn_interaction: discord.Interaction):
                                if btn_interaction.user.id != self.user_id:
                                    await btn_interaction.response.send_message("This is not your selection!", ephemeral=False)
                                    return
                                
                                try:
                                    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                                    c = conn.cursor()
                                    
                                    # Add perk to active_perks as permanent
                                    expires_at = int(datetime(2099, 12, 31).timestamp())
                                    c.execute(
                                        '''INSERT OR REPLACE INTO active_perks 
                                           (guild_id, user_id, perk_id, perk_name, perk_effect, perk_value, perk_type, expires_at) 
                                           VALUES (?, ?, ?, ?, ?, ?, ?, ?)''',
                                        (self.guild_id, self.user_id, perk['id'], perk['name'], perk['effect'], perk.get('value', 0), perk.get('type', 'upgrade'), expires_at)
                                    )
                                    
                                    # Remove this tier from pending_perks
                                    # Check for BOTH new format (level=0) and old format (level<0)
                                    c.execute('SELECT perks_json FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level = 0',
                                              (self.guild_id, self.user_id))
                                    existing_result = c.fetchone()
                                    
                                    # Get the level marker if this is old format
                                    level_marker = None
                                    c.execute('SELECT level FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level < 0',
                                              (self.guild_id, self.user_id))
                                    level_results = c.fetchall()
                                    if level_results and len(level_results) > 0:
                                        # Find the matching tier's level marker
                                        for level_val, in level_results:
                                            if abs(level_val) == int(self.upgrade_tier_str):
                                                level_marker = level_val
                                                break
                                    
                                    if existing_result:
                                        # NEW FORMAT
                                        import json
                                        existing_data = json.loads(existing_result[0])
                                        upgrade_tiers = existing_data.get('upgrade_tiers', {})
                                        
                                        # Remove the claimed tier
                                        if self.upgrade_tier_str in upgrade_tiers:
                                            del upgrade_tiers[self.upgrade_tier_str]
                                        
                                        # Update or delete the pending_perks entry
                                        if upgrade_tiers:
                                            c.execute('''INSERT OR REPLACE INTO pending_perks (guild_id, user_id, level, perks_json)
                                                         VALUES (?, ?, ?, ?)''',
                                                      (self.guild_id, self.user_id, 0, json.dumps({'upgrade_tiers': upgrade_tiers})))
                                        else:
                                            c.execute('DELETE FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level = 0',
                                                      (self.guild_id, self.user_id))
                                    elif level_marker:
                                        # OLD FORMAT - delete by level marker
                                        c.execute('DELETE FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level = ?',
                                                  (self.guild_id, self.user_id, level_marker))
                                    
                                    conn.commit()
                                    conn.close()
                                    
                                    success_msg = f"✅ You claimed **{perk['name']}** from Upgrade Tier {self.upgrade_tier_str}!\n\n"
                                    
                                    # Check if there are more upgrade tiers to claim
                                    remaining_tiers = 0
                                    if existing_result:
                                        import json
                                        try:
                                            existing_data = json.loads(existing_result[0])
                                            remaining_tiers = len(existing_data.get('upgrade_tiers', {})) - 1
                                        except:
                                            pass
                                    
                                    if remaining_tiers > 0:
                                        success_msg += f"You have **{remaining_tiers}** more upgrade tier(s) to claim!"
                                    elif self.missing_level_perks > 0:
                                        success_msg += f"You still have **{self.missing_level_perks}** level-up perks to claim!"
                                    else:
                                        success_msg += "🎉 All your perks are now claimed!"
                                    
                                    await btn_interaction.response.send_message(success_msg, ephemeral=False)
                                except Exception as e:
                                    import traceback
                                    await btn_interaction.response.send_message(f"❌ Error: {str(e)}", ephemeral=True)
                                    traceback.print_exc()
                            
                            return callback
                    
                    view = UpgradePerkSelectionView(interaction.guild_id, interaction.user.id, selected_perks, earliest_unclaimed_tier, missing_level_perks)
                    await interaction.followup.send(embed=embed, view=view, ephemeral=False)
                    return
            
            elif missing_level_perks > 0:
                # Show level-up perks
                first_missing_level = perks_count + 1  # If user has 0 perks, start at level 1
                
                # Check if we have stored perks for this level - if not, ALWAYS generate them
                conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                c = conn.cursor()
                c.execute('SELECT perks_json FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level = ?',
                          (interaction.guild_id, interaction.user.id, first_missing_level))
                stored = c.fetchone()
                conn.close()
                
                import json
                if stored:
                    # Load stored perks
                    stored_data = json.loads(stored[0])
                    if isinstance(stored_data, dict) and 'selected_perks' in stored_data:
                        selected_perks = stored_data['selected_perks']
                    else:
                        selected_perks = stored_data if isinstance(stored_data, list) else []
                else:
                    # Generate and store new perks if none exist
                    selected_perks = generate_unique_perks(first_missing_level, 3, upgrade_level)
                    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                    c = conn.cursor()
                    c.execute('''INSERT OR REPLACE INTO pending_perks (guild_id, user_id, level, perks_json)
                                 VALUES (?, ?, ?, ?)''',
                              (interaction.guild_id, interaction.user.id, first_missing_level, json.dumps({'selected_perks': selected_perks})))
                    conn.commit()
                    conn.close()
                
                # Build embed for level perks
                rarity_emoji = {"common": "⚪", "uncommon": "🟢", "rare": "🔵", "epic": "🟣", "legendary": "🟡"}
                perk_text = ""
                for i, (rarity, perk) in enumerate(selected_perks, 1):
                    perk_text += f"{i}. {rarity_emoji.get(rarity, '⚪')} **{perk['name']}** ({rarity.capitalize()})\n   *{perk['effect']}*\n\n"
                
                embed = discord.Embed(
                    title=f"🎁 Claim Missing Perk - Level {first_missing_level}",
                    description=perk_text + "Select a perk to claim!",
                    color=discord.Color.gold()
                )
                embed.set_footer(text=f"Missing perks: {missing_level_perks}")
                
                view = MissingPerkSelectionView(interaction.guild_id, interaction.user.id, selected_perks, first_missing_level, missing_level_perks)
                await interaction.followup.send(embed=embed, view=view, ephemeral=False)
                return
            
            else:
                await interaction.followup.send(
                    "✅ You don't have any missing perks!\n\n"
                    f"You've collected **{perks_count}** perks for your **Level {current_level}** account.",
                    ephemeral=False
                )
                return
        
        async def show_tier_perk_selection(self, interaction: discord.Interaction, guild_id: int, user_id: int, tier: int, upgrade_level: int):
            """Show tier-specific perk selection for upgrade recovery"""
            try:
                # Get perks allowed for this tier
                allowed_rarities = DRAGONNEST_UPGRADES.get(tier, {}).get('allowed_rarities', [])
                available_perks = []
                for rarity in allowed_rarities:
                    available_perks.extend(PERKS_POOL.get(rarity, []))
                
                # Shuffle and pick 10
                random.shuffle(available_perks)
                selected_perks = available_perks[:10]
                
                # Build embed for this tier
                perk_list = ""
                for i, perk in enumerate(selected_perks, 1):
                    perk_list += f"{i}. **{perk['name']}** - {perk['effect']}\n"
                
                embed = discord.Embed(
                    title=f"🎁 Upgrade Tier {tier}: Select 2 Starting Perks",
                    description=f"Choose 2 perks that will be permanently active for Tier {tier}:\n\n{perk_list}",
                    color=discord.Color.gold()
                )
                
                # Create dropdown view for tier-specific perk selection
                class TierPerkSelectionView(discord.ui.View):
                    def __init__(self, guild_id, user_id, perks, tier, total_tiers, outer_self):
                        super().__init__(timeout=300)
                        self.guild_id = guild_id
                        self.user_id = user_id
                        self.perks = perks
                        self.tier = tier
                        self.total_tiers = total_tiers
                        self.selected_perks = []
                        self.outer_self = outer_self  # Store reference to outer class
                        
                        # Create dropdown with perks
                        perk_options = [
                            discord.SelectOption(
                                label=perk['name'][:100],
                                value=str(i),
                                description=perk['effect'][:100]
                            )
                            for i, perk in enumerate(perks)
                        ]
                        
                        # Set the select options and constraints (always 2 perks per tier)
                        self.perk_select.options = perk_options
                        self.perk_select.min_values = 2
                        self.perk_select.max_values = 2
                        self.perk_select.placeholder = f"Select 2 perks for Tier {tier}..."
                    
                    @discord.ui.select(placeholder="Select 2 perks...")
                    async def perk_select(self, interaction_select: discord.Interaction, select: discord.ui.Select):
                        self.selected_perks = [int(idx) for idx in select.values]
                        selected_names = ", ".join([self.perks[idx]['name'] for idx in self.selected_perks])
                        await interaction_select.response.send_message(f"✅ You selected: **{selected_names}**\n\nNow click **Confirm** to proceed!", ephemeral=True)
                    
                    @discord.ui.button(label="Confirm", style=discord.ButtonStyle.success, emoji="✅")
                    async def confirm_tier_perks(self, btn_interaction: discord.Interaction, button: discord.ui.Button):
                        try:
                            if btn_interaction.user.id != self.user_id:
                                await btn_interaction.response.send_message("This is not your selection!", ephemeral=True)
                                return
                            
                            if len(self.selected_perks) != 2:
                                await btn_interaction.response.send_message("You must select exactly 2 perks!", ephemeral=True)
                                return
                            
                            await btn_interaction.response.defer()
                            
                            # Save these tier's perks
                            conn_perk = sqlite3.connect('dragon_bot.db', timeout=120.0)
                            c_perk = conn_perk.cursor()
                            
                            expires_at = int(datetime(2099, 12, 31).timestamp())
                            
                            for perk_idx in self.selected_perks:
                                perk = self.perks[perk_idx]
                                c_perk.execute(
                                    '''INSERT OR IGNORE INTO active_perks 
                                       (guild_id, user_id, perk_id, perk_name, perk_effect, perk_value, perk_type, expires_at) 
                                       VALUES (?, ?, ?, ?, ?, ?, ?, ?)''',
                                    (self.guild_id, self.user_id, perk['id'], perk['name'], perk['effect'], perk['value'], perk['type'], expires_at)
                                )
                            
                            conn_perk.commit()
                            conn_perk.close()
                            
                            selected_names = ", ".join([self.perks[idx]['name'] for idx in self.selected_perks])
                            
                            # Check if there are more tiers to go
                            if self.tier < self.total_tiers:
                                # Show confirmation and continue to next tier
                                confirm_embed = discord.Embed(
                                    title=f"✅ Tier {self.tier} Complete!",
                                    description=f"**Perks for Tier {self.tier}:**\n{selected_names}\n\n"
                                                f"Get ready for **Tier {self.tier + 1}**...",
                                    color=discord.Color.green()
                                )
                                await btn_interaction.followup.send(embed=confirm_embed, ephemeral=False)
                                
                                # Continue with next tier (wait a moment to avoid timing issues)
                                try:
                                    if self.outer_self is None:
                                        await btn_interaction.followup.send("❌ Internal error: outer_self is None", ephemeral=True)
                                        return
                                    
                                    await asyncio.sleep(0.5)  # Small delay to ensure message is sent first
                                    await self.outer_self.show_tier_perk_selection(interaction, self.guild_id, self.user_id, self.tier + 1, self.total_tiers)
                                except AttributeError as ae:
                                    await btn_interaction.followup.send(f"❌ Method error: {str(ae)}", ephemeral=True)
                                except Exception as e:
                                    await btn_interaction.followup.send(f"❌ Error continuing to next tier: {str(e)}", ephemeral=True)
                            else:
                                # All tiers complete!
                                final_embed = discord.Embed(
                                    title="🎉 Dragon Nest Setup Complete!",
                                    description=f"You've successfully recovered all your perks from Tiers 1-{self.total_tiers}!\n\n"
                                                f"You're ready to continue your Dragon Nest journey!",
                                    color=discord.Color.gold()
                                )
                                await btn_interaction.followup.send(embed=final_embed, ephemeral=False)
                        except Exception as e:
                            import traceback
                            await btn_interaction.followup.send(f"❌ Error: {str(e)}", ephemeral=True)
                            traceback.print_exc()
                
                view = TierPerkSelectionView(guild_id, user_id, selected_perks, tier, upgrade_level, self)
                await interaction.followup.send(embed=embed, view=view, ephemeral=False)
                
            except Exception as e:
                import traceback
                await interaction.followup.send(f"❌ Error loading tier perks: {str(e)}", ephemeral=True)
                traceback.print_exc()
        
        async def select_perk_to_activate(self, interaction: discord.Interaction):
            """Show collected perks to activate OR claim missing perks first"""
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            
            # Get current level, perks count, and last activation time
            c.execute('SELECT level, perks_activated_at_current_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            result = c.fetchone()
            current_level = result[0] if result else 0
            last_activation_level = result[1] if result and result[1] else 0
            
            c.execute('SELECT COUNT(*) FROM user_perks WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            perks_count = c.fetchone()[0]
            
            # Check if user has missing perks
            expected_perks = current_level
            missing_perks = expected_perks - perks_count
            
            # If missing perks, redirect to claim interface
            if missing_perks > 0:
                conn.close()
                await self.claim_missing_perks(interaction)
                return
            
            # Check if perks were already activated at this level
            if current_level == last_activation_level and current_level > 0:
                conn.close()
                await interaction.response.send_message(
                    f"❌ You've already activated your perks at this level!\n\nLevel up or down and reach another level to activate them again.",
                    ephemeral=False
                )
                return
            
            # Get collected perks
            c.execute('''SELECT perk_id, perk_name, perk_effect, perk_value, rarity FROM user_perks 
                         WHERE guild_id = ? AND user_id = ?
                         ORDER BY rarity DESC, perk_name''',
                      (interaction.guild_id, interaction.user.id))
            collected_perks = c.fetchall()
            
            conn.close()
            
            if not collected_perks:
                await interaction.response.send_message(
                    "❌ You haven't collected any perks yet!\n\n"
                    "Complete Dragon Nest bounties to earn perks!",
                    ephemeral=False
                )
                return
            
            # Show perks with "Activate Now" button
            rarity_emoji = {"common": "⚪", "uncommon": "🟢", "rare": "🔵", "epic": "🟣", "legendary": "🟡"}
            perk_list = ""
            for perk_id, perk_name, perk_effect, perk_value, rarity in collected_perks[:10]:  # Show first 10
                perk_list += f"{rarity_emoji.get(rarity, '⚪')} **{perk_name}**\n   *{perk_effect}*\n\n"
            
            if len(collected_perks) > 10:
                perk_list += f"*...and {len(collected_perks) - 10} more perks*"
            
            preview_embed = discord.Embed(
                title="✨ Your Collected Perks",
                description=f"You have **{len(collected_perks)}** perk(s) ready to activate:\n\n{perk_list}",
                color=discord.Color.purple()
            )
            preview_embed.set_footer(text="Click 'Activate Now' to activate all perks for 3 hours!")
            
            # Create view with "Activate Now" button
            class ActivatePerksView(discord.ui.View):
                def __init__(self, guild_id, user_id, perks, current_level):
                    super().__init__(timeout=180)
                    self.guild_id = guild_id
                    self.user_id = user_id
                    self.perks = perks
                    self.current_level = current_level
                
                @discord.ui.button(label="Activate Now", style=discord.ButtonStyle.green, emoji="🔥")
                async def activate_now(self, btn_interaction: discord.Interaction, button: discord.ui.Button):
                    if btn_interaction.user.id != self.user_id:
                        await btn_interaction.response.send_message("This is not your perk selection!", ephemeral=False)
                        return
                    
                    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                    c = conn.cursor()
                    
                    # Activate ALL perks for 3 hours
                    expires_at = int(time.time()) + 10800  # 3 hours
                    activated_count = 0
                    
                    for perk_id, perk_name, perk_effect, perk_value, rarity in self.perks:
                        c.execute('''INSERT INTO active_perks (guild_id, user_id, perk_id, perk_name, perk_effect, perk_value, perk_type, expires_at)
                                     VALUES (?, ?, ?, ?, ?, ?, ?, ?)
                                     ON CONFLICT(guild_id, user_id, perk_id)
                                     DO UPDATE SET expires_at = ?''',
                                  (self.guild_id, self.user_id, perk_id, perk_name, 
                                   perk_effect, perk_value, 'lucky', expires_at, expires_at))
                        activated_count += 1
                    
                    # Update last activation level for THIS level only
                    c.execute('UPDATE dragon_nest SET perks_activated_at_current_level = ? WHERE guild_id = ? AND user_id = ?',
                              (self.current_level, self.guild_id, self.user_id))
                    
                    conn.commit()
                    conn.close()
                    
                    # Show success by editing the current message
                    rarity_emoji = {"common": "⚪", "uncommon": "🟢", "rare": "🔵", "epic": "🟣", "legendary": "🟡"}
                    perk_list = ""
                    for perk_id, perk_name, perk_effect, perk_value, rarity in self.perks[:10]:
                        perk_list += f"{rarity_emoji.get(rarity, '⚪')} **{perk_name}**\n   *{perk_effect}*\n\n"
                    
                    if len(self.perks) > 10:
                        perk_list += f"*...and {len(self.perks) - 10} more perks*"
                    
                    success_embed = discord.Embed(
                        title="✨ All Perks Activated!",
                        description=f"You activated **{activated_count}** perk(s) for the next **3 hours**!\n\n{perk_list}",
                        color=discord.Color.gold()
                    )
                    success_embed.set_footer(text="⏰ All perks will expire in 3 hours")
                    
                    # Create Back button view
                    class BackButtonView(discord.ui.View):
                        def __init__(self, guild_id, user_id):
                            super().__init__(timeout=180)
                            self.guild_id = guild_id
                            self.user_id = user_id
                        
                        @discord.ui.button(label="Back to Dragon Nest", style=discord.ButtonStyle.gray, emoji="🔙")
                        async def back_button(self, btn_interaction: discord.Interaction, button: discord.ui.Button):
                            if btn_interaction.user.id != self.user_id:
                                await btn_interaction.response.send_message("This is not your interaction!", ephemeral=True)
                                return
                            
                            # Get the updated dragonnest embed
                            cog = btn_interaction.client.get_cog('Game')
                            updated_embed = await cog.get_updated_embed(btn_interaction)
                            
                            # Create dragonnest view buttons
                            dragon_view = cog.DragonNestView(btn_interaction.guild_id, btn_interaction.user.id)
                            
                            await btn_interaction.response.edit_message(embed=updated_embed, view=dragon_view)
                    
                    back_view = BackButtonView(self.guild_id, self.user_id)
                    await btn_interaction.response.edit_message(embed=success_embed, view=back_view)
            
            view = ActivatePerksView(interaction.guild_id, interaction.user.id, collected_perks, current_level)
            await interaction.response.edit_message(embed=preview_embed, view=view)
        
        async def get_updated_embed(self, interaction: discord.Interaction):
            """Get updated Dragon Nest embed"""
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            
            c.execute('SELECT level, xp, bounties_completed, bounties_active FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            result = c.fetchone()
            
            c.execute('SELECT active_until FROM dragon_nest_active WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            active_result = c.fetchone()
            
            conn.close()
            
            level = result[0] if result else 0
            xp = result[1] if result else 0
            bounties_completed = result[2] if result else 0
            bounties_active = result[3] if result else None
            
            level_name = LEVEL_NAMES.get(level, "Unknown")
            character = LEVEL_CHARACTERS.get(level, "None")
            
            is_active = active_result and active_result[0] > int(time.time())
            time_left = (active_result[0] - int(time.time())) if is_active else 0
            
            embed = discord.Embed(
                title=f"🏰 {interaction.user.display_name}'s Dragon Nest",
                description=f"**Level {level}: {level_name}**\n*{character}*",
                color=discord.Color.green() if is_active else discord.Color.purple()
            )
            
            embed.add_field(name="Total Bounties Completed", value=str(bounties_completed), inline=True)
            embed.add_field(name="Current Level", value=f"{level}/10", inline=True)
            
            if is_active and bounties_active:
                import ast
                bounties = ast.literal_eval(bounties_active)
                bounty_text = ""
                for i, bounty in enumerate(bounties, 1):
                    progress = bounty['progress']
                    target = bounty['target']
                    if bounty['type'] == 'catch_any':
                        bounty_text += f"📋 **Bounty {i}:** Catch {target} dragons ({progress}/{target})\n"
                    elif bounty['type'] == 'catch_rarity_or_higher':
                        rarity_names = {1: 'Uncommon', 2: 'Rare', 3: 'Epic', 4: 'Legendary', 5: 'Mythic'}
                        rarity_name = rarity_names.get(bounty.get('rarity_level'), 'Rare')
                        bounty_text += f"📋 **Bounty {i}:** Catch {target} {rarity_name}+ dragons ({progress}/{target})\n"
                
                embed.add_field(name="🎯 Active Bounties", value=bounty_text, inline=False)
                embed.add_field(name="⏰ Time Remaining", value=format_time_remaining(time_left), inline=False)
            
            embed.set_footer(text="Activate Dragon Nest to start bounties!")
            return embed
        
        async def activate_nest(self, interaction: discord.Interaction):
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            
            # Check if raid boss is active (block Dragon Nest during raid)
            c.execute('SELECT expires_at FROM raid_bosses WHERE guild_id = ? AND expires_at > ?',
                      (interaction.guild_id, int(time.time())))
            raid_active = c.fetchone()
            
            if raid_active:
                await interaction.response.send_message(
                    f"❌ Dragon Nest is paused during Raid Boss battles!\n\n"
                    f"⚔️ A raid boss is currently active. Normal dragons aren't spawning.\n"
                    f"Focus on defeating the boss and try Dragon Nest afterwards!",
                    ephemeral=False
                )
                conn.close()
                return
            
            # Get current level and bounties
            c.execute('SELECT level, bounties_active, upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            result = c.fetchone()
            current_level = result[0] if result else 0
            bounties_active = result[1] if result else None
            upgrade_level = result[2] if result else 0
            
            # Check if already active
            c.execute('SELECT active_until FROM dragon_nest_active WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            active_result = c.fetchone()
            
            if active_result and active_result[0] > int(time.time()):
                time_left = active_result[0] - int(time.time())
                await interaction.response.send_message(
                    f"✅ Dragon Nest is already active!\n"
                    f"⏰ Time remaining: {format_time_remaining(time_left)}",
                    ephemeral=False
                )
                conn.close()
                return
            
            # Check if user has at least 100 total dragons
            c.execute('SELECT SUM(count) FROM user_dragons WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            total_result = c.fetchone()
            total_dragons = total_result[0] if total_result and total_result[0] else 0
            
            if total_dragons < 100:
                await interaction.response.send_message(
                    f"❌ You need at least **100 total dragons** to activate Dragon Nest!\n"
                    f"You currently have: **{total_dragons}** dragons\n\n"
                    f"Catch more dragons and try again!",
                    ephemeral=False
                )
                conn.close()
                return
            
            # Generate exactly 3 unique bounties
            bounties = []
            difficulty = LEVEL_BOUNTY_DIFFICULTY.get(current_level, 3)
            
            used_rarity_levels = set()  # Track used rarity levels to avoid duplicates
            used_targets = set()  # Track used targets for catch_any to avoid exact duplicates
            
            # Always generate 3 bounties with guaranteed variety:
            # 1. One catch_any bounty
            # 2. Two catch_rarity_or_higher bounties with different rarity levels
            
            # Bounty 1: Catch any dragons (general bounty)
            target_1 = max(2, int(difficulty * random.uniform(0.9, 1.1)))
            bounties.append({
                'type': 'catch_any',
                'target': target_1,
                'progress': 0,
                'rarity_level': None
            })
            used_targets.add(target_1)
            
            # Bounty 2: Catch rarity or higher (first rarity level)
            target_2 = max(1, int((difficulty / 2.5) * random.uniform(0.9, 1.1)))
            rarity_level_1 = random.randint(1, 4)  # 1=Uncommon, 2=Rare, 3=Epic, 4=Legendary
            used_rarity_levels.add(rarity_level_1)
            bounties.append({
                'type': 'catch_rarity_or_higher',
                'target': target_2,
                'progress': 0,
                'rarity_level': rarity_level_1
            })
            
            # Bounty 3: Catch rarity or higher (different rarity level)
            target_3 = max(1, int((difficulty / 2.5) * random.uniform(0.9, 1.1)))
            # Ensure different rarity level from bounty 2
            available_rarities = [r for r in range(1, 5) if r not in used_rarity_levels]
            if available_rarities:
                rarity_level_2 = random.choice(available_rarities)
            else:
                # Fallback: just use a different number
                rarity_level_2 = (rarity_level_1 % 4) + 1
            
            bounties.append({
                'type': 'catch_rarity_or_higher',
                'target': target_3,
                'progress': 0,
                'rarity_level': rarity_level_2
            })
            
            c.execute('UPDATE dragon_nest SET bounties_active = ? WHERE guild_id = ? AND user_id = ?',
                      (str(bounties), interaction.guild_id, interaction.user.id))
            
            # Activate for 2 hours (fixed duration for consistency)
            duration_hours = 2
            duration = duration_hours * 3600  # Convert to seconds
            end_time = int(time.time()) + duration
            
            c.execute('''INSERT INTO dragon_nest_active (guild_id, user_id, active_until)
                         VALUES (?, ?, ?)
                         ON CONFLICT(guild_id, user_id)
                         DO UPDATE SET active_until = ?''',
                      (interaction.guild_id, interaction.user.id, end_time, end_time))
            
            conn.commit()
            conn.close()
            
            # Build bounty list
            rarity_names = {1: 'Uncommon', 2: 'Rare', 3: 'Epic', 4: 'Legendary', 5: 'Mythic'}
            bounty_list = ""
            for i, bounty in enumerate(bounties, 1):
                target = bounty['target']
                if bounty['type'] == 'catch_any':
                    bounty_list += f"📋 **Bounty {i}:** Catch {target} dragons\n"
                elif bounty['type'] == 'catch_rarity_or_higher':
                    rarity_name = rarity_names.get(bounty['rarity_level'], 'Rare')
                    bounty_list += f"📋 **Bounty {i}:** Catch {target} {rarity_name} or higher dragons\n"
            
            # Get additional nest info
            c = sqlite3.connect('dragon_bot.db', timeout=120.0)
            cursor = c.cursor()
            cursor.execute('SELECT xp, bounties_completed FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                           (interaction.guild_id, interaction.user.id))
            nest_info = cursor.fetchone()
            bounties_completed = nest_info[1] if nest_info else 0
            c.close()
            
            level_name = LEVEL_NAMES.get(current_level, "Unknown")
            character = LEVEL_CHARACTERS.get(current_level, "None")
            lore_text = LEVEL_LORE.get(current_level, "Your journey continues...")
            
            # Create updated main embed
            updated_embed = discord.Embed(
                title=f"🏰 {interaction.user.display_name}'s Dragon Nest",
                description=f"**Level {current_level}: {level_name}** | Upgrade Tier: {upgrade_level}/5\n*{character}*\n\n✨ {lore_text}",
                color=discord.Color.green()
            )
            
            # Set thumbnail if available
            thumbnail_url = LEVEL_THUMBNAILS.get(current_level)
            if thumbnail_url:
                updated_embed.set_thumbnail(url=thumbnail_url)
            
            updated_embed.add_field(name="Total Bounties Completed", value=str(bounties_completed), inline=True)
            updated_embed.add_field(name="Current Level", value=f"{current_level}/10", inline=True)
            
            # Add active bounties
            updated_embed.add_field(
                name="🎯 Active Bounties",
                value=f"✨ Complete all bounties to level up and choose a perk!\n"
                      f"⚠️ If you fail, you will be demoted!\n\n{bounty_list}",
                inline=False
            )
            
            # Add time remaining
            updated_embed.add_field(
                name="⏰ Time Remaining",
                value=format_time_remaining(duration),
                inline=False
            )
            
            updated_embed.set_footer(text="Activate Dragon Nest to start bounties!")
            
            # Create an active view (without the Activate button, since nest is now active)
            active_view = DragonNestView(is_active=True, guild_id=interaction.guild_id, user_id=interaction.user.id, current_level=current_level)
            
            # Edit the original message with the new embed and updated view
            await interaction.response.edit_message(embed=updated_embed, view=active_view)
        
        async def upgrade_nest(self, interaction: discord.Interaction):
            """Upgrade Dragon Nest - requires 500M coins and unlocks better perk rarities"""
            await interaction.response.defer(ephemeral=False)
            
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            
            # Get user's balance
            c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            balance_result = c.fetchone()
            balance = balance_result[0] if balance_result else 0
            
            # Get current upgrade level
            c.execute('SELECT upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            upgrade_result = c.fetchone()
            current_upgrade_level = upgrade_result[0] if upgrade_result else 0
            
            conn.close()
            
            # Check if already at max upgrade level
            if current_upgrade_level >= 5:
                embed = discord.Embed(
                    title="🏰 Dragon Nest Fully Upgraded",
                    description="Your Dragon Nest is already at **Maximum Level (V)**!\n\n"
                                "✨ You have unlocked all perk rarities!\n"
                                "Only **Legendary perks** will appear now.",
                    color=discord.Color.gold()
                )
                
                # Check if user has missing perks to claim
                conn_check = sqlite3.connect('dragon_bot.db', timeout=120.0)
                c_check = conn_check.cursor()
                
                c_check.execute('SELECT upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                                (interaction.guild_id, interaction.user.id))
                result = c_check.fetchone()
                check_upgrade_level = result[0] if result else 0
                
                c_check.execute('SELECT COUNT(*) FROM active_perks WHERE guild_id = ? AND user_id = ?',
                                (interaction.guild_id, interaction.user.id))
                check_active_perks = c_check.fetchone()[0]
                
                conn_check.close()
                
                # Only show button if user has upgrade_level but NO active perks
                has_missing_perks = check_upgrade_level > 0 and check_active_perks == 0
                
                if has_missing_perks:
                    # Create button to claim perks
                    class MaxLevelView(discord.ui.View):
                        def __init__(self):
                            super().__init__(timeout=300)
                        
                        @discord.ui.button(label="Claim Missing Perks", style=discord.ButtonStyle.blurple, emoji="🎁")
                        async def claim_button(self, btn_interaction: discord.Interaction, button: discord.ui.Button):
                            # Defer first
                            await btn_interaction.response.defer()
                            
                            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                            c = conn.cursor()
                            
                            # Get current level and collected perks count
                            c.execute('SELECT level, upgrade_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                                      (btn_interaction.guild_id, btn_interaction.user.id))
                            result = c.fetchone()
                            current_level = result[0] if result else 0
                            upgrade_level = result[1] if result and len(result) > 1 else 0
                            
                            # Count active perks
                            c.execute('SELECT COUNT(*) FROM active_perks WHERE guild_id = ? AND user_id = ?',
                                      (btn_interaction.guild_id, btn_interaction.user.id))
                            active_perks_count = c.fetchone()[0]
                            
                            conn.close()
                            
                            # EMERGENCY: User has upgrade_level but NO active perks at all
                            if upgrade_level > 0 and active_perks_count == 0:
                                # Generate 10 perks for them to choose from
                                allowed_rarities = DRAGONNEST_UPGRADES.get(upgrade_level, {}).get('allowed_rarities', [])
                                available_perks = []
                                for rarity in allowed_rarities:
                                    available_perks.extend(PERKS_POOL.get(rarity, []))
                                
                                # Shuffle and pick 10
                                random.shuffle(available_perks)
                                selected_perks = available_perks[:10]
                                
                                # Build embed
                                perk_list = ""
                                for i, perk in enumerate(selected_perks, 1):
                                    perk_list += f"{i}. **{perk['name']}** - {perk['effect']}\n"
                                
                                embed_recovery = discord.Embed(
                                    title="🎁 Recover Your Starting Perks",
                                    description=f"You have Upgrade Tier {upgrade_level} but no starting perks!\n\n"
                                                f"Select **2 perks** that will be permanently active:\n\n{perk_list}",
                                    color=discord.Color.gold()
                                )
                                
                                # Create proper Select with options
                                perk_options = [
                                    discord.SelectOption(
                                        label=perk['name'][:100],
                                        value=str(i),
                                        description=perk['effect'][:100]
                                    )
                                    for i, perk in enumerate(selected_perks)
                                ]
                                
                                select_menu = discord.ui.Select(
                                    placeholder="Select 2 perks...",
                                    min_values=2,
                                    max_values=2,
                                    options=perk_options
                                )
                                
                                selected_perk_list = []
                                
                                async def select_callback(select_interaction: discord.Interaction):
                                    nonlocal selected_perk_list
                                    selected_perk_list = [int(idx) for idx in select_interaction.data['values']]
                                    selected_names = ", ".join([selected_perks[idx]['name'] for idx in selected_perk_list])
                                    await select_interaction.response.send_message(f"✅ You selected: **{selected_names}**\n\nNow click **Confirm Selection** to activate your perks!", ephemeral=True)
                                
                                select_menu.callback = select_callback
                                
                                # Create view with select and confirm button
                                class RecoveryView(discord.ui.View):
                                    def __init__(self):
                                        super().__init__(timeout=300)
                                        self.add_item(select_menu)
                                        self.selected = selected_perk_list
                                    
                                    @discord.ui.button(label="Confirm Selection", style=discord.ButtonStyle.success, emoji="✅")
                                    async def confirm(self, confirm_interaction: discord.Interaction, button: discord.ui.Button):
                                        if confirm_interaction.user.id != btn_interaction.user.id:
                                            await confirm_interaction.response.send_message("This is not your selection!", ephemeral=True)
                                            return
                                        
                                        if len(selected_perk_list) != 2:
                                            await confirm_interaction.response.send_message("You must select exactly 2 perks!", ephemeral=True)
                                            return
                                        
                                        await confirm_interaction.response.defer()
                                        
                                        # Save selected perks
                                        conn_perk = sqlite3.connect('dragon_bot.db', timeout=120.0)
                                        c_perk = conn_perk.cursor()
                                        
                                        expires_at = int(datetime(2099, 12, 31).timestamp())
                                        
                                        for idx in selected_perk_list:
                                            perk = selected_perks[idx]
                                            c_perk.execute(
                                                '''INSERT OR REPLACE INTO active_perks 
                                                   (guild_id, user_id, perk_id, perk_name, perk_effect, perk_value, perk_type, expires_at) 
                                                   VALUES (?, ?, ?, ?, ?, ?, ?, ?)''',
                                                (btn_interaction.guild_id, btn_interaction.user.id, perk['id'], perk['name'], perk['effect'], perk.get('value', 0), perk.get('type', 'upgrade'), expires_at)
                                            )
                                        
                                        conn_perk.commit()
                                        conn_perk.close()
                                        
                                        selected_names = ", ".join([selected_perks[idx]['name'] for idx in selected_perk_list])
                                        success_embed = discord.Embed(
                                            title="🎉 Perks Recovered!",
                                            description=f"Your starting perks are now permanently active:\n\n**{selected_names}**",
                                            color=discord.Color.green()
                                        )
                                        
                                        await confirm_interaction.followup.send(embed=success_embed, ephemeral=False)
                                        self.stop()
                                
                                recovery_view = RecoveryView()
                                await btn_interaction.followup.send(embed=embed_recovery, view=recovery_view, ephemeral=False)
                    
                    view = MaxLevelView()
                    await interaction.followup.send(embed=embed, view=view, ephemeral=False)
                else:
                    # No missing perks - just show message without button
                    await interaction.followup.send(embed=embed, ephemeral=False)
                return
            
            # Get the cost of the next upgrade
            next_upgrade_level = current_upgrade_level + 1
            upgrade_cost = DRAGONNEST_UPGRADES.get(next_upgrade_level, {}).get('cost', 0)
            next_upgrade_name = DRAGONNEST_UPGRADES.get(next_upgrade_level, {}).get('name', 'Unknown')
            
            # Check if user has enough coins
            if balance < upgrade_cost:
                coins_needed = upgrade_cost - balance
                embed = discord.Embed(
                    title="❌ Not Enough Coins",
                    description=f"You need **{upgrade_cost:,}** coins to upgrade your Dragon Nest.\n\n"
                                f"💰 You have: **{int(balance):,}** coins\n"
                                f"💸 You need: **{int(coins_needed):,}** more coins",
                    color=discord.Color.red()
                )
                await interaction.followup.send(embed=embed, ephemeral=False)
                return
            
            # Show confirmation embed with a button
            current_rarities = DRAGONNEST_UPGRADES.get(current_upgrade_level, {}).get('allowed_rarities', [])
            next_rarities = DRAGONNEST_UPGRADES.get(next_upgrade_level, {}).get('allowed_rarities', [])
            
            rarity_emoji = {
                "common": "⚪",
                "uncommon": "🟢",
                "rare": "🔵",
                "epic": "🟣",
                "legendary": "🟡",
                "mythic": "🌟",
                "ultra": "✨"
            }
            
            current_perks = " ".join([rarity_emoji.get(r, r) + f" {r.capitalize()}" for r in current_rarities])
            next_perks = " ".join([rarity_emoji.get(r, r) + f" {r.capitalize()}" for r in next_rarities])
            
            embed = discord.Embed(
                title=f"⬆️ Upgrade to {next_upgrade_name}",
                description=f"Ready to upgrade your Dragon Nest?\n\n"
                            f"**Current Level:** Level {current_upgrade_level} ({DRAGONNEST_UPGRADES.get(current_upgrade_level, {}).get('name', 'Unknown')})\n"
                            f"**Current Perks:** {current_perks}\n\n"
                            f"**Next Level:** Level {next_upgrade_level} ({next_upgrade_name})\n"
                            f"**New Perks:** {next_perks}\n\n"
                            f"💰 **Cost:** {upgrade_cost:,} coins\n"
                            f"✅ **You have:** {int(balance):,} coins\n\n"
                            f"⚠️ **WARNING - COMPLETE HARD RESET ON UPGRADE:**\n"
                            f"When you upgrade, ALL of the following will be PERMANENTLY DELETED:\n"
                            f"🐉 All dragons\n"
                            f"� All items & lales\n"
                            f"📊 All market listings\n"
                            f"✨ All lucky charms\n"
                            f"📚 All skills (reset to Level 0)\n"
                            f"🏰 Dragon Nest level (reset to 0)\n"
                            f"📖 All collected perks\n"
                            f"💰 ALL COINS (balance will be 0)\n"
                            f"⏰ All dragonscales\n\n"
                            f"🔷 **Alpha Dragons WILL BE KEPT!**\n"
                            f"Please make sure this is intentional! This is a hard reset to start fresh with better perks.",
                color=discord.Color.red()
            )
            embed.set_footer(text="⚠️ This action CANNOT be undone! Click 'Confirm Upgrade' to proceed.")
            
            # Create confirmation view
            class UpgradeConfirmView(discord.ui.View):
                def __init__(self, guild_id, user_id, next_level, cost):
                    super().__init__(timeout=180)
                    self.guild_id = guild_id
                    self.user_id = user_id
                    self.next_level = next_level
                    self.cost = cost
                
                @discord.ui.button(label="Confirm Upgrade", style=discord.ButtonStyle.success, emoji="✅")
                async def confirm_upgrade(self, btn_interaction: discord.Interaction, button: discord.ui.Button):
                    if btn_interaction.user.id != self.user_id:
                        await btn_interaction.response.send_message("This is not your upgrade!", ephemeral=True)
                        return
                    
                    await btn_interaction.response.defer()
                    
                    conn_upgrade = sqlite3.connect('dragon_bot.db', timeout=120.0)
                    c_upgrade = conn_upgrade.cursor()
                    
                    # Verify balance again (prevent race conditions)
                    c_upgrade.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    balance_check = c_upgrade.fetchone()
                    current_balance = balance_check[0] if balance_check else 0
                    
                    if current_balance < self.cost:
                        await btn_interaction.followup.send(
                            "❌ Your balance has changed! You no longer have enough coins.",
                            ephemeral=False
                        )
                        conn_upgrade.close()
                        return
                    
                    # Deduct coins and upgrade
                    c_upgrade.execute('UPDATE users SET balance = 0 WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    c_upgrade.execute('UPDATE dragon_nest SET upgrade_level = ? WHERE guild_id = ? AND user_id = ?',
                                      (self.next_level, self.guild_id, self.user_id))
                    
                    # Hard reset: Delete all dragons, items, lucky charms, packs, and dragonscales (keep alphas)
                    c_upgrade.execute('DELETE FROM user_dragons WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    c_upgrade.execute('DELETE FROM user_items WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    c_upgrade.execute('DELETE FROM active_items WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    c_upgrade.execute('DELETE FROM user_luckycharms WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    c_upgrade.execute('DELETE FROM user_packs WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    c_upgrade.execute('DELETE FROM dragonscales WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    c_upgrade.execute('DELETE FROM dragonscale_event_log WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    # Delete market listings
                    c_upgrade.execute('DELETE FROM market_listings WHERE guild_id = ? AND seller_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    # Reset Dragon Nest level to 0
                    c_upgrade.execute('UPDATE dragon_nest SET level = 0, xp = 0 WHERE guild_id = ? AND user_id = ?',
                                      (self.guild_id, self.user_id))
                    
                    # Keep all perks (both level-perks and permanent perks) - they should NOT be deleted!
                    # User can use /dragonnest -> Claim Missing Perks to reclaim if needed
                    # Level-perks will be regenerated based on Dragon Nest level
                    # Permanent perks are kept for stacking
                    
                    # Reset skills to level 0 by removing skill items
                    c_upgrade.execute('DELETE FROM user_items WHERE guild_id = ? AND user_id = ? AND item_type IN (?, ?)',
                                      (self.guild_id, self.user_id, 'knowledge_book', 'precision_stone'))
                    
                    conn_upgrade.commit()
                    conn_upgrade.close()
                    
                    # Show success message
                    upgrade_name = DRAGONNEST_UPGRADES.get(self.next_level, {}).get('name', 'Unknown')
                    new_rarities = DRAGONNEST_UPGRADES.get(self.next_level, {}).get('allowed_rarities', [])
                    new_perks_str = " ".join([rarity_emoji.get(r, r) + f" {r.capitalize()}" for r in new_rarities])
                    
                    success_embed = discord.Embed(
                        title="✨ Dragon Nest Upgraded!",
                        description=f"Your Dragon Nest has been upgraded to **{upgrade_name} (Level {self.next_level})**!\n\n"
                                    f"🎁 **New Available Perks:**\n{new_perks_str}\n\n"
                                    f"💰 Upgrade Cost: **{self.cost:,}** coins\n\n"
                                    f"⚠️ **COMPLETE HARD RESET APPLIED:**\n"
                                    f"🐉 All dragons deleted\n"
                                    f"� All items & lales deleted\n"
                                    f"📊 All market listings deleted\n"
                                    f"✨ All lucky charms deleted\n"
                                    f"📚 All skills reset to Level 0\n"
                                    f"🔷 **Alpha dragons KEPT!**\n"
                                    f"🏰 Dragon Nest level reset to 0\n"
                                    f"📖 **All collected level-perks deleted (can be reclaimed)**\n"
                                    f"✨ **Permanent upgrade-perks KEPT & STACKED!**\n"
                                    f"💰 Balance reset to 0 coins\n"
                                    f"⏰ All dragonscales deleted\n"
                                    f"🎉 Lower rarity perks will no longer appear in new selections!\n\n"
                                    f"You're starting fresh with better perks! 🚀",
                        color=discord.Color.green()
                    )
                    
                    await btn_interaction.followup.send(embed=success_embed, ephemeral=False)
                    
                    # Store the 10 upgrade perks in pending_perks for later claiming
                    # We store ALL upgrade tiers in one JSON with level=0 as the special marker
                    allowed_rarities = DRAGONNEST_UPGRADES.get(self.next_level, {}).get('allowed_rarities', [])
                    available_perks = []
                    for rarity in allowed_rarities:
                        available_perks.extend(PERKS_POOL.get(rarity, []))
                    
                    # Shuffle and pick 10 random perks
                    random.shuffle(available_perks)
                    selected_perks = available_perks[:10]
                    
                    # Store these perks in pending_perks
                    conn_store = sqlite3.connect('dragon_bot.db', timeout=120.0)
                    c_store = conn_store.cursor()
                    import json
                    
                    # Get existing upgrade perks (if any) to add to them
                    c_store.execute('SELECT perks_json FROM pending_perks WHERE guild_id = ? AND user_id = ? AND level = 0',
                                    (self.guild_id, self.user_id))
                    existing_result = c_store.fetchone()
                    
                    existing_upgrades = {}
                    if existing_result:
                        try:
                            existing_data = json.loads(existing_result[0])
                            existing_upgrades = existing_data.get('upgrade_tiers', {})
                        except:
                            existing_upgrades = {}
                    
                    # Store perks as tuples of (rarity, perk_dict)
                    perks_to_store = [(rarity, perk) for rarity in allowed_rarities for perk in PERKS_POOL.get(rarity, []) if perk in selected_perks]
                    
                    # Add this tier's perks to the upgrade tiers dict
                    existing_upgrades[str(self.next_level)] = {
                        'perks': perks_to_store,
                        'rarity': allowed_rarities
                    }
                    
                    # Store all upgrade tiers together with level=0 as marker
                    c_store.execute('''INSERT OR REPLACE INTO pending_perks (guild_id, user_id, level, perks_json)
                                       VALUES (?, ?, ?, ?)''',
                                    (self.guild_id, self.user_id, 0, json.dumps({'upgrade_tiers': existing_upgrades})))
                    conn_store.commit()
                    conn_store.close()
                    
                    # Create perk selection embed
                    perk_list = ""
                    for i, perk in enumerate(selected_perks, 1):
                        perk_list += f"{i}. **{perk['name']}** - {perk['effect']}\n"
                    
                    perk_embed = discord.Embed(
                        title="🎁 Choose Your Starting Perks",
                        description=f"Select **2 perks** that will be permanently active!\n\n{perk_list}",
                        color=discord.Color.gold()
                    )
                    perk_embed.set_footer(text="You can choose 2 perks that will stay with you forever.")
                    
                    # Create dropdown view for perk selection
                    class PerkSelectionView(discord.ui.View):
                        def __init__(self, guild_id, user_id, perks):
                            super().__init__(timeout=300)
                            self.guild_id = guild_id
                            self.user_id = user_id
                            self.perks = perks
                            self.selected_perks = []
                            
                            # Create dropdown with perks
                            perk_options = [
                                discord.SelectOption(
                                    label=perk['name'][:100],
                                    value=str(i),
                                    description=perk['effect'][:100]
                                )
                                for i, perk in enumerate(perks)
                            ]
                            
                            self.perk_select.options = perk_options
                        
                        @discord.ui.select(placeholder="Select 2 perks...", min_values=2, max_values=2)
                        async def perk_select(self, interaction: discord.Interaction, select: discord.ui.Select):
                            self.selected_perks = [int(idx) for idx in select.values]
                            selected_names = ", ".join([self.perks[idx]['name'] for idx in self.selected_perks])
                            await interaction.response.send_message(f"✅ You selected: **{selected_names}**\n\nNow click **Confirm Selection** to activate your perks!", ephemeral=True)
                        
                        @discord.ui.button(label="Confirm Selection", style=discord.ButtonStyle.success, emoji="✅")
                        async def confirm_perks(self, btn_interaction: discord.Interaction, button: discord.ui.Button):
                            try:
                                if btn_interaction.user.id != self.user_id:
                                    await btn_interaction.response.send_message("This is not your selection!", ephemeral=True)
                                    return
                                
                                if len(self.selected_perks) != 2:
                                    await btn_interaction.response.send_message("You must select exactly 2 perks!", ephemeral=True)
                                    return
                                
                                await btn_interaction.response.defer()
                                
                                # Save selected perks as permanent active perks
                                conn_perk = sqlite3.connect('dragon_bot.db', timeout=120.0)
                                c_perk = conn_perk.cursor()
                                
                                current_time = int(time.time())
                                
                                for perk_idx in self.selected_perks:
                                    perk = self.perks[perk_idx]
                                    # Add to active_perks (permanent - set expires_at to year 2099)
                                    # IMPORTANT: Use INSERT OR IGNORE to add new perks WITHOUT overwriting existing ones
                                    expires_at = int(datetime(2099, 12, 31).timestamp())
                                    c_perk.execute(
                                        '''INSERT OR IGNORE INTO active_perks 
                                           (guild_id, user_id, perk_id, perk_name, perk_effect, perk_value, perk_type, expires_at) 
                                           VALUES (?, ?, ?, ?, ?, ?, ?, ?)''',
                                        (self.guild_id, self.user_id, perk['id'], perk['name'], perk['effect'], perk['value'], perk['type'], expires_at)
                                    )
                                
                                conn_perk.commit()
                                conn_perk.close()
                                
                                # Show confirmation
                                selected_names = ", ".join([self.perks[idx]['name'] for idx in self.selected_perks])
                                confirm_embed = discord.Embed(
                                    title="🎉 Perks Activated!",
                                    description=f"Your starting perks are now permanently active:\n\n**{selected_names}**",
                                    color=discord.Color.green()
                                )
                                
                                await btn_interaction.followup.send(embed=confirm_embed, ephemeral=False)
                                self.stop()
                            except Exception as e:
                                import traceback
                                await btn_interaction.followup.send(f"❌ Error confirming perks: {str(e)}", ephemeral=True)
                                traceback.print_exc()
                    
                    perk_view = PerkSelectionView(btn_interaction.guild_id, btn_interaction.user.id, selected_perks)
                    await btn_interaction.followup.send(embed=perk_embed, view=perk_view, ephemeral=False)
                
                @discord.ui.button(label="Cancel", style=discord.ButtonStyle.danger, emoji="❌")
                async def cancel_upgrade(self, btn_interaction: discord.Interaction, button: discord.ui.Button):
                    if btn_interaction.user.id != self.user_id:
                        await btn_interaction.response.send_message("This is not your upgrade!", ephemeral=True)
                        return
                    
                    await btn_interaction.response.defer()
                    
                    cancel_embed = discord.Embed(
                        title="Upgrade Cancelled",
                        description="Your Dragon Nest upgrade has been cancelled.",
                        color=discord.Color.red()
                    )
                    
                    await btn_interaction.followup.send(embed=cancel_embed, ephemeral=False)
            
            view = UpgradeConfirmView(interaction.guild_id, interaction.user.id, next_upgrade_level, upgrade_cost)
            await interaction.followup.send(embed=embed, view=view, ephemeral=False)
        
        async def view_perks(self, interaction: discord.Interaction):
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            
            current_time = int(time.time())
            
            # Get active perks
            c.execute('''SELECT perk_name, perk_effect, expires_at FROM active_perks 
                         WHERE guild_id = ? AND user_id = ? AND expires_at > ?''',
                      (interaction.guild_id, interaction.user.id, current_time))
            active_perks = c.fetchall()
            
            # Get permanent collection with effects
            c.execute('''SELECT perk_name, perk_effect, rarity FROM user_perks 
                         WHERE guild_id = ? AND user_id = ?''',
                      (interaction.guild_id, interaction.user.id))
            collected_perks = c.fetchall()
            
            # Get current level and activation status
            c.execute('SELECT level, perks_activated_at_current_level FROM dragon_nest WHERE guild_id = ? AND user_id = ?',
                      (interaction.guild_id, interaction.user.id))
            result = c.fetchone()
            current_level = result[0] if result else 0
            last_activation_level = result[1] if result and result[1] else 0
            
            # Check if user has missing perks
            perks_count = len(collected_perks)
            expected_perks = current_level
            missing_perks = expected_perks - perks_count
            
            conn.close()
            
            perk_embed = discord.Embed(
                title="✨ Your Dragon Nest Perks",
                color=discord.Color.purple()
            )
            
            # Show active perks first
            if active_perks:
                active_text = ""
                for perk_name, perk_effect, expires_at in active_perks:
                    time_left = expires_at - current_time
                    # Check if permanent (expires in year 2099 or later - more than 70 years from now)
                    is_permanent = time_left > (70 * 365.25 * 24 * 3600)  # More than 70 years
                    if is_permanent:
                        duration_str = "✨ PERMANENT"
                    else:
                        duration_str = f"⏰ {format_time_remaining(time_left)} remaining"
                    active_text += f"🔥 **{perk_name}**\n   *{perk_effect}*\n   {duration_str}\n\n"
                perk_embed.add_field(name="🔥 Active Perks", value=active_text, inline=False)
            else:
                perk_embed.add_field(name="🔥 Active Perks", value="No active perks", inline=False)
            
            # Show collection with effects
            if collected_perks:
                collection_text = ""
                rarity_emoji = {"common": "⚪", "uncommon": "🟢", "rare": "🔵", "epic": "🟣", "legendary": "🟡"}
                for perk_name, perk_effect, rarity in collected_perks[:10]:  # Limit to 10
                    collection_text += f"{rarity_emoji.get(rarity, '⚪')} **{perk_name}**\n   *{perk_effect}*\n\n"
                if len(collected_perks) > 10:
                    collection_text += f"*...and {len(collected_perks) - 10} more*"
                perk_embed.add_field(name="📚 Collection", value=collection_text, inline=False)
            
            # Create view with Activate, Claim, and Back buttons
            class ViewPerksActionsView(discord.ui.View):
                def __init__(self, guild_id, user_id, current_level, last_activation_level, missing_perks, has_perks, original_view):
                    super().__init__(timeout=180)
                    self.guild_id = guild_id
                    self.user_id = user_id
                    self.current_level = current_level
                    self.last_activation_level = last_activation_level
                    self.missing_perks = missing_perks
                    self.has_perks = has_perks
                    self.original_view = original_view
                    
                    # Add activate button if user has perks (even if already activated this level)
                    if has_perks:
                        self._add_activate_button()
                    if missing_perks > 0:
                        self._add_claim_button()
                    
                    # Add back button
                    self._add_back_button()
                
                def _add_activate_button(self):
                    button = discord.ui.Button(
                        label="Activate Perks",
                        style=discord.ButtonStyle.green,
                        emoji="🔥"
                    )
                    button.callback = self.activate_perks_button
                    self.add_item(button)
                
                def _add_claim_button(self):
                    button = discord.ui.Button(
                        label="Claim Missing Perks",
                        style=discord.ButtonStyle.blurple,
                        emoji="🎁"
                    )
                    button.callback = self.claim_missing_button
                    self.add_item(button)
                
                def _add_back_button(self):
                    button = discord.ui.Button(
                        label="Back",
                        style=discord.ButtonStyle.gray,
                        emoji="◀️"
                    )
                    button.callback = self.back_button
                    self.add_item(button)
                
                async def activate_perks_button(self, btn_interaction: discord.Interaction):
                    if btn_interaction.user.id != self.user_id:
                        await btn_interaction.response.send_message("This is not your perk menu!", ephemeral=False)
                        return
                    
                    # Check if perks were already activated at this level
                    if self.current_level == self.last_activation_level and self.current_level > 0:
                        await btn_interaction.response.send_message(
                            f"❌ You've already activated your perks at this level!\n\nLevel up or down and reach another level to activate them again.",
                            ephemeral=False
                        )
                        return
                    
                    if not self.has_perks:
                        await btn_interaction.response.send_message(
                            "❌ You haven't collected any perks yet!\n\n"
                            "Complete Dragon Nest bounties to earn perks!",
                            ephemeral=False
                        )
                        return
                    
                    # Defer the interaction first
                    await btn_interaction.response.defer()
                    
                    # Get all collected perks
                    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                    c = conn.cursor()
                    
