@bot.tree.command(name="coinflip", description="Flip a coin for double or nothing! Challenge a player or the bot")
async def coinflip(interaction: discord.Interaction, amount: int, opponent: discord.User = None):
    """Coinflip betting game - player vs player or player vs bot"""
    # IMMEDIATELY defer to claim response slot before any async operations
    await interaction.response.defer(ephemeral=False)
    
    guild_id = interaction.guild_id
    user_id = interaction.user.id
    
    # Check softlock
    is_softlocked, _ = await asyncio.to_thread(is_player_softlocked, guild_id, user_id)
    if is_softlocked:
        embed = discord.Embed(
            title="🚫 Softlock Active",
            description="You must upgrade your Dragon Nest before you can use coinflip!",
            color=discord.Color.red()
        )
        embed.set_footer(text="This message will auto-delete in 5 seconds")
        msg = await interaction.followup.send(embed=embed)
        await asyncio.sleep(5)
        try:
            await msg.delete()
        except:
            pass
        return
    
    # Validate amount
    if amount < 100:
        await interaction.followup.send("❌ Minimum bet is **100 coins**!", ephemeral=False)
        return
    
    # Check user balance
    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
    c = conn.cursor()
    c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?', (guild_id, user_id))
    result = c.fetchone()
    
    if not result or result[0] < amount:
        conn.close()
        await interaction.followup.send(f"❌ You don't have enough coins! You need **{amount}** 🪙", ephemeral=False)
        return
    
    challenger_balance = result[0]
    
    # Player vs Bot
    if opponent is None or opponent.id == bot.user.id:
        # Deduct bet from challenger
        await asyncio.to_thread(update_balance, guild_id, user_id, -amount)
        
        # Flip coin
        result = random.choice(['heads', 'tails'])
        challenger_choice = random.choice(['heads', 'tails'])
        won = result == challenger_choice
        
        if won:
            # Win: get back bet + winnings
            await asyncio.to_thread(update_balance, guild_id, user_id, amount * 2)
            
            embed = discord.Embed(
                title="🪙 Coinflip vs Bot",
                description=f"**{interaction.user.mention}** flipped **{result}**!\n\n"
                            f"🎉 **YOU WIN!**\n"
                            f"💰 Won: **{amount}** coins\n"
                            f"💵 New balance: **{int(challenger_balance + amount)}** 🪙",
                color=discord.Color.green()
            )
        else:
            embed = discord.Embed(
                title="🪙 Coinflip vs Bot",
                description=f"**{interaction.user.mention}** flipped **{result}**!\n\n"
                            f"💔 **YOU LOSE!**\n"
                            f"💸 Lost: **{amount}** coins\n"
                            f"💵 New balance: **{int(challenger_balance - amount)}** 🪙",
                color=discord.Color.red()
            )
        
        # Track coinflip quest
        _qr = await asyncio.to_thread(check_dragonpass_quests, guild_id, user_id, 'use_coinflip', 1)
        if _qr and _qr[3]:
            await send_quest_notification(bot, guild_id, user_id, _qr[3])

        conn.close()
        await interaction.followup.send(embed=embed)
        return

    # Player vs Player
    if opponent.bot:
        conn.close()
        await interaction.followup.send("❌ You can't challenge a bot! Leave opponent empty to play against the bot.", ephemeral=False)
        return
    
    if opponent.id == user_id:
        conn.close()
        await interaction.followup.send("❌ You can't challenge yourself!", ephemeral=False)
        return
    
    # Check if there's already a pending bet between these users
    c.execute('''SELECT bet_id FROM coinflip_bets 
                 WHERE guild_id = ? AND ((challenger_id = ? AND opponent_id = ?) OR (challenger_id = ? AND opponent_id = ?))
                 AND status = 'pending' ''',
              (guild_id, user_id, opponent.id, opponent.id, user_id))
    
    if c.fetchone():
        conn.close()
        await interaction.followup.send("❌ There's already a pending coinflip bet between you two!", ephemeral=False)
        return
    
    # Check opponent balance
    c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?', (guild_id, opponent.id))
    opp_result = c.fetchone()
    
    if not opp_result or opp_result[0] < amount:
        conn.close()
        await interaction.followup.send(f"❌ {opponent.mention} doesn't have enough coins for this bet!", ephemeral=False)
        return
    
    # Create bet
    current_time = int(time.time())
    expires_at = current_time + 300  # 5 minutes to accept
    
    c.execute('''INSERT INTO coinflip_bets (guild_id, challenger_id, opponent_id, amount, created_at, expires_at)
                 VALUES (?, ?, ?, ?, ?, ?)''',
              (guild_id, user_id, opponent.id, amount, current_time, expires_at))
    bet_id = c.lastrowid
    conn.commit()
    conn.close()
    
    # Create accept/decline buttons
    class CoinflipView(discord.ui.View):
        def __init__(self, bet_id, challenger_id, opponent_id, amount):
            super().__init__(timeout=300)
            self.bet_id = bet_id
            self.challenger_id = challenger_id
            self.opponent_id = opponent_id
            self.amount = amount
        
        @discord.ui.button(label="Accept", style=discord.ButtonStyle.green, emoji="✅")
        async def accept_button(self, interaction: discord.Interaction, button: discord.ui.Button):
            if interaction.user.id != self.opponent_id:
                await interaction.response.send_message("❌ Only the challenged player can accept!", ephemeral=False)
                return
            
            try:
                await interaction.response.defer()
            except discord.errors.NotFound:
                return  # Interaction already responded
            
            # Check bet still exists
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            c.execute('SELECT status FROM coinflip_bets WHERE bet_id = ?', (self.bet_id,))
            bet = c.fetchone()
            
            if not bet or bet[0] != 'pending':
                conn.close()
                try:
                    await interaction.followup.send("❌ This bet is no longer available!", ephemeral=False)
                except:
                    pass
                return
            
            # Check both players still have enough coins
            c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?', (interaction.guild_id, self.challenger_id))
            challenger_bal = c.fetchone()
            c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?', (interaction.guild_id, self.opponent_id))
            opponent_bal = c.fetchone()
            
            if not challenger_bal or challenger_bal[0] < self.amount:
                c.execute('UPDATE coinflip_bets SET status = ? WHERE bet_id = ?', ('cancelled', self.bet_id))
                conn.commit()
                conn.close()
                try:
                    await interaction.followup.send("❌ Challenger no longer has enough coins!", ephemeral=False)
                except:
                    pass
                return
            
            if not opponent_bal or opponent_bal[0] < self.amount:
                conn.close()
                try:
                    await interaction.followup.send("❌ You don't have enough coins anymore!", ephemeral=False)
                except:
                    pass
                return
            
            # Close connection BEFORE calling async functions to prevent database locked errors
            conn.close()
            
            # Deduct from both players
            await asyncio.to_thread(update_balance, interaction.guild_id, self.challenger_id, -self.amount)
            await asyncio.to_thread(update_balance, interaction.guild_id, self.opponent_id, -self.amount)
            
            # Flip coin
            result = random.choice(['heads', 'tails'])
            winner_id = random.choice([self.challenger_id, self.opponent_id])
            loser_id = self.opponent_id if winner_id == self.challenger_id else self.challenger_id
            
            # Give bet back + winnings to winner (total 2x bet)
            await asyncio.to_thread(update_balance, interaction.guild_id, winner_id, self.amount * 2)
            
            # Update bet status in DB
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            c.execute('UPDATE coinflip_bets SET status = ? WHERE bet_id = ?', ('completed', self.bet_id))
            
            # Get updated balances
            c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?', (interaction.guild_id, winner_id))
            winner_balance = c.fetchone()[0]
            c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?', (interaction.guild_id, loser_id))
            loser_balance = c.fetchone()[0]
            conn.commit()
            conn.close()
            
            # Track coinflip quest for both players
            _qr_c = await asyncio.to_thread(check_dragonpass_quests, interaction.guild_id, self.challenger_id, 'use_coinflip', 1)
            if _qr_c and _qr_c[3]:
                await send_quest_notification(interaction.client, interaction.guild_id, self.challenger_id, _qr_c[3])
            _qr_o = await asyncio.to_thread(check_dragonpass_quests, interaction.guild_id, self.opponent_id, 'use_coinflip', 1)
            if _qr_o and _qr_o[3]:
                await send_quest_notification(interaction.client, interaction.guild_id, self.opponent_id, _qr_o[3])
            
            winner = interaction.guild.get_member(winner_id)
            loser = interaction.guild.get_member(loser_id)
            
            embed = discord.Embed(
                title="🪙 Coinflip Result",
                description=f"The coin landed on **{result}**!\n\n"
                            f"🎉 **Winner:** {winner.mention}\n"
                            f"💰 Won: **{self.amount}** coins\n"
                            f"💵 Balance: **{int(winner_balance)}** 🪙\n\n"
                            f"💔 **Loser:** {loser.mention}\n"
                            f"💸 Lost: **{self.amount}** coins\n"
                            f"💵 Balance: **{int(loser_balance)}** 🪙",
                color=discord.Color.gold()
            )
            
            # Disable buttons
            for item in self.children:
                item.disabled = True
            
            try:
                await interaction.followup.send(embed=embed)
            except discord.errors.NotFound:
                pass  # Interaction already deleted
        
        @discord.ui.button(label="Decline", style=discord.ButtonStyle.red, emoji="❌")
        async def decline_button(self, interaction: discord.Interaction, button: discord.ui.Button):
            if interaction.user.id != self.opponent_id:
                await interaction.response.send_message("❌ Only the challenged player can decline!", ephemeral=False)
                return
            
            try:
                await interaction.response.defer()
            except discord.errors.NotFound:
                return  # Interaction already responded
            
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            c.execute('UPDATE coinflip_bets SET status = ? WHERE bet_id = ?', ('declined', self.bet_id))
            conn.commit()
            conn.close()
            
            embed = discord.Embed(
                title="🪙 Coinflip Declined",
                description=f"{interaction.user.mention} declined the coinflip challenge!",
                color=discord.Color.red()
            )
            
            # Disable buttons
            for item in self.children:
                item.disabled = True
            
            try:
                await interaction.followup.send(embed=embed)
            except discord.errors.NotFound:
                pass  # Interaction already deleted
    
    embed = discord.Embed(
        title="🪙 Coinflip Challenge!",
        description=f"**{interaction.user.mention}** challenges **{opponent.mention}** to a coinflip!\n\n"
                    f"💰 Bet: **{amount}** coins\n"
                    f"🎲 Winner takes all!\n\n"
                    f"⏰ Expires in 5 minutes",
        color=discord.Color.gold()
    )
    
    view = CoinflipView(bet_id, user_id, opponent.id, amount)
    await interaction.followup.send(embed=embed, view=view)

@bot.tree.command(name="bingo", description="Play dragon bingo! Catch dragons to mark your card")
async def bingo(interaction: discord.Interaction):
    """Dragon bingo card system - 5x5 grid of dragon types"""
    # IMMEDIATELY defer to claim response slot
    await interaction.response.defer(ephemeral=False)
    
    guild_id = interaction.guild_id
    user_id = interaction.user.id
    
    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
    c = conn.cursor()
    
    # Check if user has an active bingo card
    current_time = int(time.time())
    c.execute('''SELECT card_data, marked_positions, created_at, expires_at, completed 
                 FROM bingo_cards WHERE guild_id = ? AND user_id = ?''',
              (guild_id, user_id))
    existing_card = c.fetchone()
    
    if existing_card:
        card_data, marked_str, created_at, expires_at, completed = existing_card
        
        # Check if expired
        if current_time > expires_at:
            c.execute('DELETE FROM bingo_cards WHERE guild_id = ? AND user_id = ?', (guild_id, user_id))
            conn.commit()
            existing_card = None
        elif completed:
            conn.close()
            # Card is completed - calculate time until it expires
            time_remaining = expires_at - current_time
            
            time_str = format_time_remaining(time_remaining)
            await interaction.followup.send(f"✅ You already completed this bingo card! It will expire in **{time_str}** and you can start a new one.", ephemeral=False)
            return
    
    # Generate new card if needed
    if not existing_card:
        # Generate 5x5 grid (25 dragons, can have duplicates)
        all_dragons = list(DRAGON_TYPES.keys())
        
        # Weight towards common dragons for achievability
        weighted_dragons = []
        for dragon, data in DRAGON_TYPES.items():
            rarity = next((r for r, dragons in DRAGON_RARITY_TIERS.items() if dragon in dragons), 'common')
            weight = {'common': 40, 'uncommon': 25, 'rare': 15, 'epic': 10, 'legendary': 6, 'mythic': 3, 'ultra': 1}
            weighted_dragons.extend([dragon] * weight.get(rarity, 10))
        
        card = []
        for i in range(25):
            if i == 12:  # Center square is FREE
                card.append('FREE')
            else:
                card.append(random.choice(weighted_dragons))
        
        card_data = ','.join(card)
        marked_positions = '[]'
        created_at = current_time
        expires_at = current_time + (48 * 60 * 60)  # 48 hours
        
        c.execute('''INSERT OR REPLACE INTO bingo_cards 
                     (guild_id, user_id, card_data, marked_positions, created_at, expires_at)
                     VALUES (?, ?, ?, ?, ?, ?)''',
                  (guild_id, user_id, card_data, marked_positions, created_at, expires_at))
        conn.commit()
        marked_str = marked_positions  # Initialize marked_str for new card
    else:
        card_data, marked_str, created_at, expires_at, completed = existing_card
    
    # Parse card data
    card = card_data.split(',')
    marked = safe_json_loads(marked_str, [])
    
    # Mark center as free (if not already marked)
    if 12 not in marked:
        marked.append(12)
        # Update database with FREE square marked
        c.execute('UPDATE bingo_cards SET marked_positions = ? WHERE guild_id = ? AND user_id = ?',
                  (str(marked), guild_id, user_id))
        conn.commit()
    
    # Check for bingo (5 in a row/column/diagonal)
    def check_bingo(marked_positions, card_size=5):
        lines = []
        
        # Rows
        for row in range(card_size):
            lines.append([row * card_size + col for col in range(card_size)])
        
        # Columns
        for col in range(card_size):
            lines.append([row * card_size + col for row in range(card_size)])
        
        # Diagonals
        lines.append([i * card_size + i for i in range(card_size)])
        lines.append([i * card_size + (card_size - 1 - i) for i in range(card_size)])
        
        for line in lines:
            if all(pos in marked_positions for pos in line):
                return True, line
        
        return False, []
    
    has_bingo, bingo_line = check_bingo(marked)
    
    # CLOSE CONNECTION BEFORE calling check_dragonpass_quests to avoid database locks!
    conn.close()
    
    # Track bingo check quest (run in executor to avoid blocking event loop)
    _qr = await asyncio.to_thread(check_dragonpass_quests, guild_id, user_id, 'check_bingo', 1)
    if _qr and _qr[3]:
        await send_quest_notification(bot, guild_id, user_id, _qr[3])
    
    # Build card display (ALWAYS show the card)
    card_display = ""
    for row in range(5):
        row_text = ""
        for col in range(5):
            pos = row * 5 + col
            dragon_type = card[pos]
            
            if dragon_type == 'FREE':
                row_text += "⭐ "
            elif pos in marked:
                row_text += "✅ "
            else:
                row_text += "❌ "
            
            if dragon_type != 'FREE':
                dragon_data = DRAGON_TYPES.get(dragon_type, {})
                row_text += f"{dragon_data.get('name', dragon_type)[:5]:<5} "
            else:
                row_text += "FREE  "
        
        card_display += row_text + "\n"
    
    marked_count = len(marked)
    expires_in = expires_at - current_time
    
    embed = discord.Embed(
        title="🎯 Dragon Bingo Card",
        description=f"**Catch dragons to mark your card!**\n\n"
                    f"```\n{card_display}```\n"
                    f"**Progress:** {marked_count}/25 marked\n"
                    f"⏰ Expires in: **{format_time_remaining(expires_in)}**\n\n"
                    f"💡 Get 5 in a row (horizontal, vertical, or diagonal) to win **500** 🪙!",
        color=discord.Color.blue()
    )
    
    # Send card first
    await interaction.followup.send(embed=embed, ephemeral=False)
    
    # Then check if BINGO and send congratulations
    if has_bingo and not completed:
        # Award prize
        reward = 500
        try:
            await asyncio.to_thread(update_balance, guild_id, user_id, reward)
        except Exception as e:
            logger.error(f"Error updating balance for bingo: {e}")
        
        # Mark as completed - use NEW connection since we closed the previous one
        try:
            conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
            c = conn.cursor()
            c.execute('UPDATE bingo_cards SET completed = 1 WHERE guild_id = ? AND user_id = ?',
                      (guild_id, user_id))
            conn.commit()
            conn.close()
        except Exception as e:
            logger.error(f"Error marking bingo as completed: {e}")
        
        # Track bingo completion quest (run in executor to avoid blocking event loop)
        try:
            _qr = await asyncio.to_thread(check_dragonpass_quests, guild_id, user_id, 'complete_bingo', 1)
            if _qr and _qr[3]:
                await send_quest_notification(bot, guild_id, user_id, _qr[3])
        except Exception as e:
            logger.error(f"Error tracking bingo completion quest: {e}")
        
        bingo_embed = discord.Embed(
            title="🎉 BINGO! 🎉",
            description=f"**Congratulations {interaction.user.mention}!**\n\n"
                        f"You completed a line!\n"
                        f"🏆 Reward: **{reward}** 🪙",
            color=discord.Color.gold()
        )
        await interaction.followup.send(embed=bingo_embed)

@bot.tree.command(name="achievements", description="View your achievements and track your progress")
async def achievements(interaction: discord.Interaction, user: discord.User = None):
    """Display achievements for a user"""
    await interaction.response.defer(ephemeral=False)
    target_user = user or interaction.user
    guild_id = interaction.guild_id
    user_id = target_user.id
    
    # Check achievements first (which also updates the database)
    if interaction.user.id == user_id:
        await check_and_award_achievements(guild_id, user_id, bot=bot, interaction=interaction)
    
    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
    c = conn.cursor()
    
    # Get user stats for achievement checking
    c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?', (guild_id, user_id))
    balance_result = c.fetchone()
    balance = balance_result[0] if balance_result else 0
    
    # Total dragons caught
    c.execute('SELECT SUM(count) FROM user_dragons WHERE guild_id = ? AND user_id = ?', (guild_id, user_id))
    total_caught_result = c.fetchone()
    total_caught = total_caught_result[0] if total_caught_result and total_caught_result[0] else 0
    
    # Unique types collected
    c.execute('SELECT COUNT(*) FROM user_dragons WHERE guild_id = ? AND user_id = ? AND count > 0', (guild_id, user_id))
    unique_types = c.fetchone()[0]
    
    # Check legendary, mythic, ultra catches
    legendary_caught = 0
    mythic_caught = 0
    ultra_caught = 0
    
    for dragon_type in DRAGON_RARITY_TIERS['legendary']:
        c.execute('SELECT count FROM user_dragons WHERE guild_id = ? AND user_id = ? AND dragon_type = ?',
                  (guild_id, user_id, dragon_type))
        result = c.fetchone()
        if result and result[0] > 0:
            legendary_caught += 1
            break
    
    for dragon_type in DRAGON_RARITY_TIERS['mythic']:
        c.execute('SELECT count FROM user_dragons WHERE guild_id = ? AND user_id = ? AND dragon_type = ?',
                  (guild_id, user_id, dragon_type))
        result = c.fetchone()
        if result and result[0] > 0:
            mythic_caught += 1
            break
    
    for dragon_type in DRAGON_RARITY_TIERS['ultra']:
        c.execute('SELECT count FROM user_dragons WHERE guild_id = ? AND user_id = ? AND dragon_type = ?',
                  (guild_id, user_id, dragon_type))
        result = c.fetchone()
        if result and result[0] > 0:
            ultra_caught += 1
            break
    
    # Trades completed (count from trade_offers with status = completed)
    c.execute('''SELECT COUNT(*) FROM trade_offers 
                 WHERE guild_id = ? AND (sender_id = ? OR receiver_id = ?) AND status = 'completed' ''',
              (guild_id, user_id, user_id))
    trades_completed = c.fetchone()[0]
    
    # Breeds completed
    c.execute('SELECT COUNT(*) FROM bred_dragons WHERE guild_id = ? AND user_id = ?', (guild_id, user_id))
    breeds_completed = c.fetchone()[0]
    
    # Alpha dragons crafted
    c.execute('SELECT COUNT(*) FROM user_alphas WHERE guild_id = ? AND user_id = ?', (guild_id, user_id))
    alphas_crafted = c.fetchone()[0]
    
    # Check each achievement
    unlocked_achievements = []
    locked_achievements = []
    
    achievement_progress = {
        'first_catch': total_caught,
        'catch_10': total_caught,
        'catch_50': total_caught,
        'catch_100': total_caught,
        'catch_500': total_caught,
        'first_legendary': legendary_caught,
        'first_mythic': mythic_caught,
        'first_ultra': ultra_caught,
        'collector_10': unique_types,
        'collector_all': unique_types,
        'rich_1000': balance,
        'rich_10000': balance,
        'trader': trades_completed,
        'breeder': breeds_completed,
        'alpha_crafter': alphas_crafted,
    }
    
    for ach_id, ach_data in ACHIEVEMENTS.items():
        progress = achievement_progress.get(ach_id, 0)
        requirement = ach_data['requirement']
        
        # Check if unlocked
        c.execute('SELECT unlocked FROM user_achievements WHERE guild_id = ? AND user_id = ? AND achievement_id = ?',
                  (guild_id, user_id, ach_id))
        unlocked_result = c.fetchone()
        is_unlocked = unlocked_result[0] if unlocked_result else False
        
        ach_display = {
            'id': ach_id,
            'name': ach_data['name'],
            'description': ach_data['description'],
            'icon': ach_data['icon'],
            'reward': ach_data['reward_coins'],
            'progress': progress,
            'requirement': requirement
        }
        
        if is_unlocked:
            unlocked_achievements.append(ach_display)
        else:
            locked_achievements.append(ach_display)
    
    conn.close()
    
    # Organize achievements by category
    achievements_by_category = {}
    for ach_id, ach_data in ACHIEVEMENTS.items():
        category = ach_data.get('category', 'Other')
        if category not in achievements_by_category:
            achievements_by_category[category] = {'unlocked': [], 'locked': []}
    
    # Populate categories
    for ach in unlocked_achievements:
        ach_data = ACHIEVEMENTS.get(ach['id'], {})
        category = ach_data.get('category', 'Other')
        achievements_by_category[category]['unlocked'].append(ach)
    
    for ach in locked_achievements:
        ach_data = ACHIEVEMENTS.get(ach['id'], {})
        category = ach_data.get('category', 'Other')
        achievements_by_category[category]['locked'].append(ach)
    
    # Create category list
    categories = sorted(achievements_by_category.keys())
    
    # Create navigation view
    class AchievementsNavigationView(discord.ui.View):
        def __init__(self, categories_list, achievements_dict, target, guild, user):
            super().__init__(timeout=300)
            self.categories_list = categories_list
            self.achievements_dict = achievements_dict
            self.target_user = target
            self.guild_id = guild
            self.user_id = user
            self.current_category_index = 0
        
        def get_category_embed(self):
            """Generate embed for current category"""
            category = self.categories_list[self.current_category_index]
            cat_data = self.achievements_dict[category]
            unlocked_in_cat = len(cat_data['unlocked'])
            total_in_cat = len(cat_data['unlocked']) + len(cat_data['locked'])
            
            embed = discord.Embed(
                title=f"🏆 {self.target_user.display_name}'s Achievements",
                description=f"{category}\n**{unlocked_in_cat}/{total_in_cat} unlocked**",
                color=discord.Color.gold()
            )
            
            # Show all achievements in this category
            if cat_data['unlocked']:
                unlocked_text = ""
                for ach in cat_data['unlocked']:
                    unlocked_text += f"✅ {ach['icon']} **{ach['name']}**\n   _{ach['description']}_\n    💰 +{ach['reward']} coins\n\n"
                embed.add_field(name="✅ Unlocked", value=unlocked_text, inline=False)
            
            if cat_data['locked']:
                locked_text = ""
                for ach in cat_data['locked']:
                    progress_pct = int((ach['progress'] / ach['requirement']) * 100) if ach['requirement'] > 0 else 0
                    progress_bar = "▓" * int(progress_pct / 5) + "░" * (20 - int(progress_pct / 5))
                    locked_text += f"🔒 {ach['icon']} **{ach['name']}**\n   _{ach['description']}_\n   {progress_bar} {ach['progress']}/{ach['requirement']} ({progress_pct}%)\n   💰 +{ach['reward']} coins\n\n"
                embed.add_field(name="🔒 Locked", value=locked_text, inline=False)
            
            # Footer with pagination
            embed.set_footer(text=f"Category {self.current_category_index + 1}/{len(self.categories_list)}")
            return embed
        
        @discord.ui.button(label="◀", style=discord.ButtonStyle.blurple, emoji="⬅️")
        async def previous_category(self, interaction: discord.Interaction, button: discord.ui.Button):
            if interaction.user.id != self.user_id:
                await interaction.response.send_message("This is not your achievements!", ephemeral=True)
                return
            
            self.current_category_index = (self.current_category_index - 1) % len(self.categories_list)
            await interaction.response.edit_message(embed=self.get_category_embed())
        
        @discord.ui.button(label="▶", style=discord.ButtonStyle.blurple, emoji="➡️")
        async def next_category(self, interaction: discord.Interaction, button: discord.ui.Button):
            if interaction.user.id != self.user_id:
                await interaction.response.send_message("This is not your achievements!", ephemeral=True)
                return
            
            self.current_category_index = (self.current_category_index + 1) % len(self.categories_list)
            await interaction.response.edit_message(embed=self.get_category_embed())
    
    view = AchievementsNavigationView(categories, achievements_by_category, target_user, guild_id, interaction.user.id)
    embed = view.get_category_embed()
    await interaction.followup.send(embed=embed, view=view)

@tasks.loop(minutes=30)
async def spawn_black_market():
    """Automatically spawn Black Market with fixed selection: 2 packs, 1 epic+ dragon, 1 random item"""
    current_time = int(time.time())
    
    for guild_id, channel_id in spawn_channels.items():
        # Check if black market is already active
        if guild_id in black_market_active:
            if black_market_active[guild_id]['end_time'] > current_time:
                continue
            # Check if enough time has passed
            time_since_closed = current_time - black_market_active[guild_id]['end_time']
            if time_since_closed < BLACK_MARKET_SPAWN_INTERVAL:
                continue
        
        # 20% chance to spawn
        if random.random() > 0.2:
            continue
        
        # Select 2 random packs
        pack_items = ['pack_wooden', 'pack_stone', 'pack_bronze']
        selected_packs = random.sample(pack_items, 2)
        
        # Select 1 epic or higher rarity dragon
        epic_dragons = []
        for rarity in ['epic', 'legendary', 'mythic', 'ultra']:
            epic_dragons.extend(DRAGON_RARITY_TIERS[rarity])
        
        selected_dragon = random.choice(epic_dragons)
        dragon_data = DRAGON_TYPES[selected_dragon]
        
        # Select 1 random special item
        special_items = ['dna_sample', 'lucky_charm', 'lucky_dice', 'night_vision']
        selected_item = random.choice(special_items)
        
        # Calculate dragon price: 25% discount on normal value
        base_dragon_price = int(dragon_data['value'] * 20)
        black_market_dragon_price = int(base_dragon_price * 0.75)
        
        # Create items list with stock
        items_list = []
        for pack_key in selected_packs:
            items_list.append({
                'key': pack_key,
                'stock': random.randint(3, 8),
                'is_dragon': False
            })
        
        # Add dragon
        items_list.append({
            'key': selected_dragon,
            'stock': random.randint(1, 3),
            'price': black_market_dragon_price,
            'is_dragon': True,
            'dragon_data': dragon_data
        })
        
        # Add special item
        items_list.append({
            'key': selected_item,
            'stock': random.randint(2, 5),
            'is_dragon': False
        })
        
        end_time = current_time + BLACK_MARKET_DURATION
        black_market_active[guild_id] = {
            'end_time': end_time,
            'items': items_list,
            'message_id': None
        }
        
        guild = bot.get_guild(guild_id)
        if guild:
            channel = guild.get_channel(channel_id)
            if channel:
                # Build items display (no prices, no discounts)
                items_text = ""
                for item in items_list:
                    if item['is_dragon']:
                        # Get rarity
                        rarity = 'common'
                        for r, dragons in DRAGON_RARITY_TIERS.items():
                            if selected_dragon in dragons:
                                rarity = r
                                break
                        items_text += f"{item['dragon_data']['emoji']} **{item['dragon_data']['name']} Dragon** ({rarity.title()}) | Stock: {item['stock']}\n"
                    else:
                        item_info = BLACK_MARKET_ITEMS[item['key']]
                        items_text += f"{item_info['emoji']} **{item_info['name']}** | Stock: {item['stock']}\n"
                
                embed = discord.Embed(
                    title="🎩 BLACK MARKET OPENED!",
                    description=f"**A mysterious merchant has appeared with rare deals...**\n\n"
                                f"{items_text}\n"
                                f"⏰ Available for **30 minutes**!\n\n"
                                f"Click the button below to shop!",
                    color=0xFEE75C
                )
                embed.set_footer(text="💎 Limited quantities - first come, first served!")
                
                class BlackMarketAnnounceView(discord.ui.View):
                    def __init__(self):
                        super().__init__(timeout=None)
                    
                    @discord.ui.button(label="Shop Black Market", style=discord.ButtonStyle.success, emoji="🎩")
                    async def shop_market_button(self, interaction: discord.Interaction, button: discord.ui.Button):
                        """Show Black Market shop"""
                        current_time = int(time.time())
                        gid = interaction.guild_id
                        
                        # Check if black market is still active
                        if gid not in black_market_active or black_market_active[gid]['end_time'] < current_time:
                            await interaction.response.send_message("❌ The Black Market has closed!", ephemeral=False)
                            return
                        
                        # Get user balance (use async to prevent event loop blocking)
                        user_data = await get_user_async(gid, interaction.user.id)
                        balance = user_data[2]
                        
                        # Create shop selection
                        class BlackMarketSelect(discord.ui.Select):
                            def __init__(self):
                                options = []
                                for item in black_market_active[gid]['items']:
                                    if item['is_dragon']:
                                        rarity = 'common'
                                        for r, dragons in DRAGON_RARITY_TIERS.items():
                                            if item['key'] in dragons:
                                                rarity = r
                                                break
                                        options.append(
                                            discord.SelectOption(
                                                label=f"{item['dragon_data']['name']} Dragon ({rarity.title()}) - {item['price']:,}🪙",
                                                description=f"Stock: {item['stock']} | Rarity: {rarity.title()}",
                                                value=item['key'],
                                                emoji=item['dragon_data']['emoji']
                                            )
                                        )
                                    else:
                                        item_info = BLACK_MARKET_ITEMS[item['key']]
                                        options.append(
                                            discord.SelectOption(
                                                label=f"{item_info['name']} - {item_info['black_price']:,}🪙",
                                                description=f"Stock: {item['stock']}",
                                                value=item['key'],
                                                emoji=item_info['emoji']
                                            )
                                        )
                                super().__init__(placeholder="Select item to purchase...", options=options, min_values=1, max_values=1)
                            
                            async def callback(self, select_interaction: discord.Interaction):
                                # Check softlock status
                                is_softlocked, upgrade_level = is_player_softlocked(gid, select_interaction.user.id)
                                if is_softlocked:
                                    upgrade_cost = DRAGONNEST_UPGRADES[upgrade_level + 1]['cost']
                                    softlock_embed = discord.Embed(
                                        title="🔒 Dragon Nest Upgrade Required!",
                                        description=f"You have enough coins to upgrade your Dragon Nest!\n\n"
                                                    f"**Current Level:** {upgrade_level}\n"
                                                    f"**Upgrade Cost:** {upgrade_cost:,} 🪙\n\n"
                                                    f"You're **softlocked** from shopping until you upgrade.\n"
                                                    f"Use `/dragonnest` to upgrade!",
                                        color=discord.Color.red()
                                    )
                                    await select_interaction.response.send_message(embed=softlock_embed, ephemeral=False, delete_after=5)
                                    return
                                
                                item_key = self.values[0]
                                
                                # Find item in market
                                market_item = None
                                for item in black_market_active[gid]['items']:
                                    if item['key'] == item_key:
                                        market_item = item
                                        break
                                
                                if not market_item:
                                    await select_interaction.response.send_message("❌ Item not found!", ephemeral=False)
                                    return
                                
                                if market_item['stock'] <= 0:
                                    await select_interaction.response.send_message("❌ Out of stock!", ephemeral=False)
                                    return
                                
                                if market_item['is_dragon']:
                                    price = market_item['price']
                                    item_info = market_item['dragon_data']
                                else:
                                    item_info = BLACK_MARKET_ITEMS[item_key]
                                    price = item_info['black_price']
                                
                                user_data = get_user(gid, select_interaction.user.id)
                                balance = user_data[2]
                                
                                if balance < price:
                                    await select_interaction.response.send_message(
                                        f"❌ You need **{price:,}** 🪙 but only have **{int(balance):,}** 🪙!",
                                        ephemeral=False
                                    )
                                    return
                                
                                # Process purchase
                                conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
                                c = conn.cursor()
                                
                                # Deduct balance
                                c.execute('UPDATE users SET balance = balance - ? WHERE guild_id = ? AND user_id = ?',
                                          (price, gid, select_interaction.user.id))
                                
                                if market_item['is_dragon']:
                                    # Add dragon
                                    await add_dragons(gid, select_interaction.user.id, item_key, 1)
                                    item_name = f"{item_info['emoji']} {item_info['name']} Dragon"
                                else:
                                    # Add item based on type
                                    if item_key.startswith('pack_'):
                                        pack_type = item_key.split('_')[1]
                                        c.execute('''INSERT INTO user_packs (guild_id, user_id, pack_type, count) 
                                                     VALUES (?, ?, ?, 1) 
                                                     ON CONFLICT(guild_id, user_id, pack_type) 
                                                     DO UPDATE SET count = count + 1''',
                                                  (gid, select_interaction.user.id, pack_type))
                                    else:
                                        # Special items: dna_sample, lucky_charm, lucky_dice, night_vision
                                        item_type_map = {
                                            'dna_sample': 'dna',
                                            'lucky_charm': None,
                                            'lucky_dice': 'lucky_dice',
                                            'night_vision': 'night_vision'
                                        }
                                        
                                        if item_key == 'lucky_charm':
                                            c.execute('''INSERT INTO user_luckycharms (guild_id, user_id, count) 
                                                         VALUES (?, ?, 1) 
                                                         ON CONFLICT(guild_id, user_id) 
                                                         DO UPDATE SET count = count + 1''',
                                                      (gid, select_interaction.user.id))
                                        elif item_type_map.get(item_key):
                                            item_type = item_type_map[item_key]
                                            c.execute('''INSERT INTO user_items (guild_id, user_id, item_type, count) 
                                                         VALUES (?, ?, ?, 1) 
                                                         ON CONFLICT(guild_id, user_id, item_type) 
                                                         DO UPDATE SET count = count + 1''',
                                                      (gid, select_interaction.user.id, item_type))
                                    
                                    item_name = f"{item_info['emoji']} {item_info['name']}"
                                
                                conn.commit()
                                conn.close()
                                
                                # Reduce stock
                                market_item['stock'] -= 1
                                
                                success_embed = discord.Embed(
                                    title="✅ Purchase Complete!",
                                    description=f"You've acquired **{item_name}** from the Black Market!\n\n"
                                                f"💰 Paid: **{price:,}** 🪙",
                                    color=discord.Color.green()
                                )
                                await select_interaction.response.send_message(embed=success_embed, ephemeral=False)
                                
                                # Update the main announcement embed with new stock
                                if black_market_active[gid]['message_id']:
                                    try:
                                        guild = bot.get_guild(gid)
                                        if guild:
                                            for channel in guild.text_channels:
                                                try:
                                                    msg = await channel.fetch_message(black_market_active[gid]['message_id'])
                                                    if msg:
                                                        # Rebuild items display with updated stock
                                                        items_text = ""
                                                        for item in black_market_active[gid]['items']:
                                                            if item['is_dragon']:
                                                                rarity = 'common'
                                                                for r, dragons in DRAGON_RARITY_TIERS.items():
                                                                    if item['key'] in dragons:
                                                                        rarity = r
                                                                        break
                                                                items_text += f"{item['dragon_data']['emoji']} **{item['dragon_data']['name']} Dragon** ({rarity.title()}) | Stock: {item['stock']}\n"
                                                            else:
                                                                item_info = BLACK_MARKET_ITEMS[item['key']]
                                                                items_text += f"{item_info['emoji']} **{item_info['name']}** | Stock: {item['stock']}\n"
                                                        
                                                        updated_embed = discord.Embed(
                                                            title="🎩 BLACK MARKET OPENED!",
                                                            description=f"**A mysterious merchant has appeared with rare deals...**\n\n"
                                                                        f"{items_text}\n"
                                                                        f"⏰ Available for **30 minutes**!\n\n"
                                                                        f"Click the button below to shop!",
                                                            color=0xFEE75C
                                                        )
                                                        updated_embed.set_footer(text="💎 Limited quantities - first come, first served!")
                                                        await msg.edit(embed=updated_embed)
                                                        break
                                                except:
                                                    pass
                                    except:
                                        pass
                        
                        class BlackMarketView(discord.ui.View):
                            def __init__(self):
                                super().__init__(timeout=300)
                                self.add_item(BlackMarketSelect())
                        
                        time_left = black_market_active[gid]['end_time'] - current_time
                        minutes_left = time_left // 60
                        
                        market_embed = discord.Embed(
                            title="🎩 Black Market - OPEN",
                            description=f"**Limited Time Offers!**\n\n",
                            color=0xFEE75C
                        )
                        
                        for item in black_market_active[gid]['items']:
                            if item['is_dragon']:
                                rarity = 'common'
                                for r, dragons in DRAGON_RARITY_TIERS.items():
                                    if item['key'] in dragons:
                                        rarity = r
                                        break
                                market_embed.description += f"{item['dragon_data']['emoji']} **{item['dragon_data']['name']} Dragon** ({rarity.title()})\n"
                                market_embed.description += f"   Stock: {item['stock']}\n\n"
                            else:
                                item_info = BLACK_MARKET_ITEMS[item['key']]
                                market_embed.description += f"{item_info['emoji']} **{item_info['name']}**\n"
                                market_embed.description += f"   Stock: {item['stock']}\n\n"
                        
                        market_embed.description += f"\n⏰ Market closes in **{minutes_left}** minutes!"
                        market_embed.set_footer(text="💎 Limited quantities - act fast!")
                        
                        await interaction.response.send_message(embed=market_embed, view=BlackMarketView(), ephemeral=False)
                
                try:
                    market_message = await channel.send(embed=embed, view=BlackMarketAnnounceView())
                    black_market_active[guild_id]['message_id'] = market_message.id
                except:
                    pass


# ==================== BREEDING QUEUE PROCESSOR ====================
@tasks.loop(minutes=1)
async def process_breeding_queue():
    """Process queued breedings every minute - starts when cooldown is ready"""
    current_time = int(time.time())
    
    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
    c = conn.cursor()
    
    # Get ALL pending breedings (not filtered by scheduled_for anymore)
    c.execute('''SELECT queue_id, guild_id, user_id, parent1_type, parent2_type 
                 FROM breeding_queue 
                 WHERE status = 'pending'
                 ORDER BY created_at ASC''')
    all_breedings = c.fetchall()
    
    for queue_id, guild_id, user_id, parent1, parent2 in all_breedings:
        try:
            # NORMALIZE dragon types from DB
            parent1 = normalize_dragon_type(parent1)
            parent2 = normalize_dragon_type(parent2)
            
            # Validate normalized dragons exist
            if parent1 not in DRAGON_TYPES or parent2 not in DRAGON_TYPES:
                # Invalid dragons - remove from queue
                c.execute('DELETE FROM breeding_queue WHERE queue_id = ?', (queue_id,))
                conn.commit()
                continue
            
            # Check if user is ready to breed (cooldown wise)
            c.execute('SELECT last_breed, last_breed_rarity FROM breeding_cooldowns WHERE guild_id = ? AND user_id = ?',
                     (guild_id, user_id))
            cooldown_result = c.fetchone()
            
            # If has cooldown, check if ready
            if cooldown_result:
                last_breed = cooldown_result[0]
                last_rarity = cooldown_result[1] if len(cooldown_result) > 1 else 'common'
                cooldown_duration = BREEDING_COOLDOWNS.get(last_rarity, BREEDING_COOLDOWNS['common'])
                
                if current_time - last_breed < cooldown_duration:
                    # Still in cooldown, skip this breeding
                    continue
            
            # Check if user has enough coins
            # Calculate the actual breeding cost first
            p1_rarity = get_dragon_rarity(parent1)
            p2_rarity = get_dragon_rarity(parent2)
            breeding_cost = get_breeding_cost(p1_rarity, p2_rarity)
            
            c.execute('SELECT balance FROM users WHERE guild_id = ? AND user_id = ?',
                     (guild_id, user_id))
            balance_result = c.fetchone()
            balance = balance_result[0] if balance_result else 0
            
            if balance < breeding_cost:
                # Not enough coins - remove from queue and notify user
                c.execute('DELETE FROM breeding_queue WHERE queue_id = ?', (queue_id,))
                conn.commit()
                
                # Get dragon info for DM
                p1_data = DRAGON_TYPES.get(parent1, {})
                p2_data = DRAGON_TYPES.get(parent2, {})
                
                # Send DM to user
                try:
                    guild = bot.get_guild(guild_id)
                    user = guild.get_member(user_id) if guild else None
                    
                    if user:
                        dm_embed = discord.Embed(
                            title="💔 Breeding Cancelled",
                            description=f"Your queued breeding was cancelled because you don't have enough coins!",
                            color=discord.Color.red()
                        )
                        dm_embed.add_field(
                            name="❌ Cancelled Breeding",
                            value=f"{p1_data.get('emoji', '🐉')} {p1_data.get('name', parent1)} + {p2_data.get('emoji', '🐉')} {p2_data.get('name', parent2)}",
                            inline=False
                        )
                        dm_embed.add_field(
                            name="💰 Cost",
                            value=f"Required: {breeding_cost:,}🪙\nYou have: {int(balance):,}🪙",
                            inline=False
                        )
                        dm_embed.set_footer(text=f"Server: {guild.name if guild else 'Unknown'}")
                        
                        # Add button to go to spawn channel if it exists
                        channel_id = get_spawn_channel(guild_id)
                        if channel_id:
                            class GoToChannelView(discord.ui.View):
                                def __init__(self):
                                    super().__init__(timeout=None)
                                    channel = guild.get_channel(channel_id)
                                    if channel:
                                        self.add_item(discord.ui.Button(
                                            label=f"Go to {guild.name}",
                                            url=f"https://discord.com/channels/{guild_id}/{channel_id}",
                                            emoji="📍"
                                        ))
                            await user.send(embed=dm_embed, view=GoToChannelView())
                        else:
                            await user.send(embed=dm_embed)
                except:
                    pass
                
                continue
            
            # Roll for offspring
            def get_rarity(dragon_type):
                for rarity, dragons in DRAGON_RARITY_TIERS.items():
                    if dragon_type in dragons:
                        return rarity
                return 'common'
            
            rarity1 = get_rarity(parent1)
            rarity2 = get_rarity(parent2)
            
            breeding_key = (rarity1, rarity2)
            if breeding_key not in BREEDING_CHANCES:
                breeding_key = (rarity2, rarity1)
            
            chances = BREEDING_CHANCES.get(breeding_key, {'common': 100})
            
            roll = random.randint(1, 100)
            cumulative = 0
            result_rarity = 'fail'
            
            for rarity, chance in chances.items():
                cumulative += chance
                if roll <= cumulative:
                    result_rarity = rarity
                    break
            
            # Set cooldown
            rarity_order = ['common', 'uncommon', 'rare', 'epic', 'legendary', 'mythic', 'ultra']
            rarity1_idx = rarity_order.index(rarity1)
            rarity2_idx = rarity_order.index(rarity2)
            higher_rarity = rarity1 if rarity1_idx >= rarity2_idx else rarity2
            
            c.execute('''INSERT INTO breeding_cooldowns (guild_id, user_id, last_breed, last_breed_rarity)
                         VALUES (?, ?, ?, ?)
                         ON CONFLICT(guild_id, user_id) 
                         DO UPDATE SET last_breed = ?, last_breed_rarity = ?''',
                      (guild_id, user_id, current_time, higher_rarity, current_time, higher_rarity))
            
            # Handle result
            if result_rarity == 'fail':
                # Deduct cost
                c.execute('UPDATE users SET balance = balance - ? WHERE guild_id = ? AND user_id = ?',
                         (breeding_cost, guild_id, user_id))
                
                # Consume one parent
                consumed = random.choice([parent1, parent2])
                c.execute('UPDATE user_dragons SET count = count - 1 WHERE guild_id = ? AND user_id = ? AND dragon_type = ?',
                         (guild_id, user_id, consumed))
                c.execute('UPDATE breeding_queue SET status = "completed_fail" WHERE queue_id = ?', (queue_id,))
                
                # Send notification to user and channel
                try:
                    user = await bot.fetch_user(user_id)
                    p1_data = DRAGON_TYPES[parent1]
                    p2_data = DRAGON_TYPES[parent2]
                    consumed_data = DRAGON_TYPES[consumed]
                    
                    embed = discord.Embed(
                        title="❌ Breeding Failed",
                        description=f"**Breeder:** {user.mention}",
                        color=discord.Color.red()
                    )
                    embed.add_field(
                        name="Parents",
                        value=f"{p1_data['emoji']} **{p1_data['name']}** + {p2_data['emoji']} **{p2_data['name']}**",
                        inline=False
                    )
                    embed.add_field(
                        name="Result",
                        value=f"No offspring produced\n\n{consumed_data['emoji']} **{consumed_data['name']}** was consumed",
                        inline=False
                    )
                    embed.add_field(name="ℹ️ Info", value=f"💰 Cost: {breeding_cost:,}🪙\n✅ Parents remain in inventory", inline=False)
                    
                    # Get guild name
                    guild = bot.get_guild(guild_id)
                    embed.set_footer(text=f"Better luck next time! | Server: {guild.name if guild else 'Unknown'}")
                    
                    # Add button to go to spawn channel if it exists
                    channel_id = get_spawn_channel(guild_id)
                    if channel_id:
                        class GoToChannelView(discord.ui.View):
                            def __init__(self):
                                super().__init__(timeout=None)
                                channel = guild.get_channel(channel_id)
                                if channel:
                                    self.add_item(discord.ui.Button(
                                        label=f"Go to {guild.name}",
                                        url=f"https://discord.com/channels/{guild_id}/{channel_id}",
                                        emoji="📍"
                                    ))
                        await user.send(embed=embed, view=GoToChannelView())
                    else:
                        await user.send(embed=embed)
                    
                    # Try to send to spawn channel
                    try:
                        c.execute('SELECT spawn_channel FROM guild_settings WHERE guild_id = ?', (guild_id,))
                        channel_result = c.fetchone()
                        if channel_result and channel_result[0]:
                            channel = bot.get_channel(channel_result[0])
                            if channel:
                                await channel.send(embed=embed)
                    except:
                        pass
                except:
                    pass
            else:
                # Deduct cost
                c.execute('UPDATE users SET balance = balance - ? WHERE guild_id = ? AND user_id = ?',
                         (breeding_cost, guild_id, user_id))
                
                # Create offspring
                possible_offspring = DRAGON_RARITY_TIERS[result_rarity]
                offspring = random.choice(possible_offspring)
                
                c.execute('''INSERT OR IGNORE INTO user_dragons (guild_id, user_id, dragon_type, count)
                            VALUES (?, ?, ?, 1)''',
                         (guild_id, user_id, offspring))
                c.execute('UPDATE user_dragons SET count = count + 1 WHERE guild_id = ? AND user_id = ? AND dragon_type = ?',
                         (guild_id, user_id, offspring))
                c.execute('UPDATE breeding_queue SET status = "completed_success" WHERE queue_id = ?', (queue_id,))

                await check_and_award_achievements(guild_id, user_id, bot=bot)

                # Send notification to user and channel
                try:
                    user = await bot.fetch_user(user_id)
                    p1_data = DRAGON_TYPES[parent1]
                    p2_data = DRAGON_TYPES[parent2]
                    offspring_data = DRAGON_TYPES[offspring]
                    
                    # Calculate offspring value (simple formula)
                    p1_value = DRAGON_TYPES[parent1].get('value', 100)
                    p2_value = DRAGON_TYPES[parent2].get('value', 100)
                    offspring_value = (p1_value + p2_value) / 2 * (1 + (rarity_order.index(result_rarity) * 0.15))
                    
                    # Store roll result for display
                    roll_result = roll
                    
                    embed = discord.Embed(
                        title="✨ Breeding Successful!",
                        description=f"**Breeder:** {user.mention}",
                        color=discord.Color.from_rgb(255, 215, 0)
                    )
                    embed.add_field(
                        name="Parents",
                        value=f"{p1_data['emoji']} **{p1_data['name']}** + {p2_data['emoji']} **{p2_data['name']}**",
                        inline=False
                    )
                    embed.add_field(
                        name="Offspring",
                        value=f"{offspring_data['emoji']} **{offspring_data['name']}**",
                        inline=True
                    )
                    embed.add_field(
                        name="Rarity",
                        value=f"**{result_rarity.upper()}**",
                        inline=True
                    )
                    embed.add_field(
                        name="Value",
                        value=f"**{offspring_value:.2f}🪙**",
                        inline=True
                    )
                    embed.add_field(
                        name="ℹ️ Info",
                        value=f"✅ Parents remain in inventory\n💰 Cost: {breeding_cost:,}🪙\n🎲 Rolled: {roll_result}/100",
                        inline=False
                    )
                    
                    # Cooldown info
                    cooldown_duration = BREEDING_COOLDOWNS.get(higher_rarity, BREEDING_COOLDOWNS['common'])
                    cooldown_hours = cooldown_duration // 3600
                    cooldown_mins = (cooldown_duration % 3600) // 60
                    embed.add_field(
                        name="⏰ Cooldown",
                        value=f"**{cooldown_hours}h {cooldown_mins}m** ({higher_rarity.capitalize()} tier)",
                        inline=False
                    )
                    
                    # Get guild name
                    guild = bot.get_guild(guild_id)
                    embed.set_footer(text=f"Congratulations on the new addition! | Server: {guild.name if guild else 'Unknown'}")
                    
                    # Add button to go to spawn channel if it exists
                    channel_id = get_spawn_channel(guild_id)
                    if channel_id:
                        class GoToChannelView(discord.ui.View):
                            def __init__(self):
                                super().__init__(timeout=None)
                                channel = guild.get_channel(channel_id)
                                if channel:
                                    self.add_item(discord.ui.Button(
                                        label=f"Go to {guild.name}",
                                        url=f"https://discord.com/channels/{guild_id}/{channel_id}",
                                        emoji="📍"
                                    ))
                        await user.send(embed=embed, view=GoToChannelView())
                    else:
                        await user.send(embed=embed)
                    
                    # Try to send to spawn channel
                    try:
                        c.execute('SELECT spawn_channel FROM guild_settings WHERE guild_id = ?', (guild_id,))
                        channel_result = c.fetchone()
                        if channel_result and channel_result[0]:
                            channel = bot.get_channel(channel_result[0])
                            if channel:
                                await channel.send(embed=embed)
                    except:
                        pass
                except:
                    pass
            
            conn.commit()
            
        except Exception as e:
            print(f"Breeding queue error: {e}")
            c.execute('UPDATE breeding_queue SET status = "error" WHERE queue_id = ?', (queue_id,))
            conn.commit()
    
    conn.close()

# ==================== ADVENTURE PROCESSOR ====================
@tasks.loop(minutes=1)
async def process_adventures():
    """Process completed adventures and reward players"""
    # Run database operations in thread pool to avoid blocking event loop
    dms_to_send = await asyncio.to_thread(process_adventures_sync)
    
    # Send DMs asynchronously after database operations complete
    for user_id, dm_data, guild_id in dms_to_send:
        try:
            user = await bot.fetch_user(user_id)
            if user:
                # Add button to go to spawn channel if it exists
                channel_id = get_spawn_channel(guild_id)
                if channel_id:
                    guild = bot.get_guild(guild_id)
                    class GoToChannelView(discord.ui.View):
                        def __init__(self):
                            super().__init__(timeout=None)
                            channel = guild.get_channel(channel_id) if guild else None
                            if channel:
                                self.add_item(discord.ui.Button(
                                    label=f"Go to {guild.name}",
                                    url=f"https://discord.com/channels/{guild_id}/{channel_id}",
                                    emoji="📍"
                                ))
                    await user.send(embed=dm_data, view=GoToChannelView())
                else:
                    await user.send(embed=dm_data)
        except Exception as e:
            # Silently fail if we can't send DM (user might have DMs disabled)
            pass

def process_adventures_sync():
    """Synchronous adventure processing - runs in thread pool"""
    current_time = int(time.time())
    dms_to_send = []  # Collect DMs to send after database operations
    
    conn = sqlite3.connect('dragon_bot.db', timeout=120.0)
    c = conn.cursor()
    
    # Get all completed adventures that haven't been claimed
    c.execute('''SELECT adventure_id, guild_id, user_id, dragons_sent, adventure_type, returns_at
                 FROM user_adventures 
                 WHERE status = 'active' AND returns_at <= ? AND claimed = 0''', (current_time,))
    completed = c.fetchall()
    
    for adventure_id, guild_id, user_id, dragons_json, adv_type, returns_at in completed:
        try:
            # Ensure IDs are integers and handle None values
            adventure_id = int(adventure_id) if adventure_id else 0
            guild_id = int(guild_id) if guild_id else 0
            user_id = int(user_id) if user_id else 0
            returns_at = int(returns_at) if returns_at else current_time
            
            adventure_config = ADVENTURE_TYPES.get(adv_type, {})
            coins_range = adventure_config.get('rewards', {}).get('coins', (100, 300))
            dragon_chance = adventure_config.get('rewards', {}).get('dragon_chance', 0.15)
            
            # Roll for overall success/failure
            success_rate = adventure_config.get('success_rate', 0.70)
            
            # Initialize reward variables
            coins_earned = 0
            rewards_dragons = []
            rewards_items = []
            
            if random.random() < success_rate:
                # Adventure succeeded! Roll for rewards
                coins_earned = random.randint(coins_range[0], coins_range[1])
                
                # Roll for dragon
                if random.random() < dragon_chance:
                    # Got a dragon! Rarity depends on adventure type
                    possible_rarities = list(DRAGON_RARITY_TIERS.keys())
                    
                    # Different rarity weights based on adventure difficulty
                    if adv_type == 'exploration':
                        # Mostly common/uncommon
                        weights = [60, 25, 10, 3, 1, 1, 0]
                    elif adv_type == 'treasure_hunt':
                        # More uncommon/rare
                        weights = [40, 35, 15, 7, 2, 1, 0]
                    elif adv_type == 'dragon_raid':
                        # Epic and legendary possible
                        weights = [25, 30, 25, 15, 4, 1, 0]
                    else:  # legendary_quest
                        # Best chance for high rarity
                        weights = [10, 20, 30, 25, 10, 4, 1]
                
                    reward_rarity = random.choices(possible_rarities, weights=weights)[0]
                    reward_dragon = random.choice(DRAGON_RARITY_TIERS[reward_rarity])
                    
                    # Ensure reward_dragon is a string, not a list
                    if isinstance(reward_dragon, list):
                        reward_dragon = reward_dragon[0] if reward_dragon else 'stone'
                    
                    rewards_dragons.append(reward_dragon)
                    
                    # Add dragon to user
                    c.execute('''INSERT OR IGNORE INTO user_dragons (guild_id, user_id, dragon_type, count)
                                VALUES (?, ?, ?, 1)''', (guild_id, user_id, reward_dragon))
                    c.execute('UPDATE user_dragons SET count = count + 1 WHERE guild_id = ? AND user_id = ? AND dragon_type = ?',
                             (guild_id, user_id, reward_dragon))
                
                # Roll for item (separate from dragon)
                item_chance = adventure_config.get('rewards', {}).get('item_chance', 0.10)
                if random.random() < item_chance:
                    # Got an item!
                    item_type = random.choice(list(ADVENTURE_ITEMS.keys()))
                    item_data = ADVENTURE_ITEMS[item_type]
                    rewards_items.append(item_type)
                    
                    # Add item to user inventory (goes to active_perks so they can activate it later)
                    if item_type == 'dragonscale':
                        # Calculate random duration for Dragonscale
                        item_duration_minutes = random.randint(item_data['min_duration'], item_data['max_duration'])
                        # Add to inventory (user_dragonscales table)
                        c.execute('''INSERT OR IGNORE INTO user_dragonscales (guild_id, user_id, minutes_available)
                                    VALUES (?, ?, ?)''', (guild_id, user_id, item_duration_minutes))
                        c.execute('UPDATE user_dragonscales SET minutes_available = minutes_available + ? WHERE guild_id = ? AND user_id = ?',
                                 (item_duration_minutes, guild_id, user_id))
                    
                    elif item_type == 'lucky_charm':
                        # Lucky Charms go to inventory (user_luckycharms table)
                        c.execute('''INSERT OR IGNORE INTO user_luckycharms (guild_id, user_id, count)
                                    VALUES (?, ?, 1)''', (guild_id, user_id))
                        c.execute('UPDATE user_luckycharms SET count = count + 1 WHERE guild_id = ? AND user_id = ?',
                                 (guild_id, user_id))
                
                # Success: Set cooldown equal to adventure duration
                cooldown_duration = adventure_config['duration']
                
                # Add coins on success
                c.execute('UPDATE users SET balance = balance + ? WHERE guild_id = ? AND user_id = ?',
                         (coins_earned, guild_id, user_id))
            else:
                # Adventure failed - no rewards
                coins_earned = 0
                rewards_dragons = []
                rewards_items = []
                
                # Failure: Set cooldown to 1.5x the adventure duration
                cooldown_duration = int(adventure_config['duration'] * 1.5)
            
            # Apply cooldown
            cooldown_until = int(time.time()) + cooldown_duration
            c.execute('''INSERT INTO adventure_cooldowns (guild_id, user_id, adventure_type, cooldown_until)
                        VALUES (?, ?, ?, ?)
                        ON CONFLICT(guild_id, user_id, adventure_type)
                        DO UPDATE SET cooldown_until = ?''',
                     (guild_id, user_id, adv_type, cooldown_until, cooldown_until))
            
            # Mark as completed and claimed
            c.execute('''UPDATE user_adventures 
                        SET status = 'completed', rewards_coins = ?, rewards_dragons = ?, claimed = 1
                        WHERE adventure_id = ?''',
                     (coins_earned, json.dumps(rewards_dragons), adventure_id))
            
            conn.commit()

            # Achievement check after adventure claim
            await check_and_award_achievements(guild_id, user_id, bot=bot)

            # Prepare DM data to send (will be sent async after database operations)
            # Since dragons are no longer sent, just show results
            dragons_sent_count = 0  # No dragons sent anymore
            
            # Build reward summary
            reward_lines = []
            if coins_earned > 0:
                reward_lines.append(f"💰 {coins_earned:,} coins")
            if rewards_dragons:
                reward_lines.append(f"🐉 {', '.join(rewards_dragons)}")
            if rewards_items:
                reward_lines.append(f"📦 {', '.join(rewards_items)}")
            
            if not reward_lines:
                reward_lines = ["❌ No rewards found"]
            
            rewards_text = "\n".join(reward_lines)
            
            # Get cooldown info
            c.execute('SELECT cooldown_until FROM adventure_cooldowns WHERE guild_id = ? AND user_id = ? AND adventure_type = ?',
                     (guild_id, user_id, adv_type))
            cooldown_row = c.fetchone()
            cooldown_until = int(cooldown_row[0]) if cooldown_row and cooldown_row[0] else 0
            time_until_next = max(0, cooldown_until - int(time.time()))
            cooldown_hours = time_until_next // 3600
            cooldown_mins = (time_until_next % 3600) // 60
            
            if cooldown_hours > 0:
                cooldown_str = f"{cooldown_hours}h {cooldown_mins}m"
            else:
                cooldown_str = f"{cooldown_mins}m"
            
            # Determine status
            if coins_earned > 0 or rewards_dragons or rewards_items:
                status_emoji = "✅"
                status_text = "Success!"
            else:
                status_emoji = "❌"
                status_text = "Failed!"
            
            # Get guild name for this adventure
            adventure_guild_id = c.execute('SELECT guild_id FROM user_adventures WHERE user_id = ? AND adventure_id = ?',
                                          (user_id, adventure_id)).fetchone()
            guild_name = "Unknown"
            if adventure_guild_id:
                guild = bot.get_guild(adventure_guild_id[0])
                guild_name = guild.name if guild else "Unknown"
            
            # Build embed
            embed = discord.Embed(
                title="🏆 Adventure Complete!",
                description=f"**Type:** {adv_type.replace('_', ' ').title()}\n"
                           f"**Result:** {status_emoji} {status_text}\n\n"
                           f"**Rewards:**\n{rewards_text}",
                color=discord.Color.gold() if coins_earned > 0 else discord.Color.red()
            )
            
            embed.add_field(
                name="⏰ Next Adventure Ready In",
                value=cooldown_str,
                inline=False
            )
            
            embed.set_footer(text=f"Server: {guild_name}")
            
            # Collect DM to send (will be sent async by process_adventures)
            dms_to_send.append((user_id, embed, guild_id))
            
        except Exception as e:
            logger.error(f"Adventure processing error for adventure_id {adventure_id}: {e}", exc_info=True)
            print(f"Adventure processing error: {e}")
    
    conn.close()
    return dms_to_send

# ==================== CLEANUP TASK ====================
@tasks.loop(minutes=5)  # Check every 5 minutes
async def cleanup_stuck_sessions():
    """Clean up stuck breeding sessions (timeout after 30 minutes)"""
    current_time = int(time.time())
    timeout_duration = 30 * 60  # 30 minutes
    
    # Find and remove old sessions
    expired_sessions = [
        key for key, timestamp in active_breeding_sessions.items()
        if current_time - timestamp > timeout_duration
    ]
    
    for session_key in expired_sessions:
        del active_breeding_sessions[session_key]
    
    if expired_sessions:
        print(f"Cleaned up {len(expired_sessions)} stuck breeding sessions")

# Run bot
bot.run(os.getenv('DISCORD_BOT_TOKEN'))
